const TOTAL_WORDS = TOTAL_WORDS_SPECIAL + LIB_WORDS.length + HS_WORDS.length + PRO_WORDS.length + GRAD_WORDS.length + BIZ_WORDS.length;
/* ───────── 영어 문법 (2022 개정 교육과정: 중학·고등·수능) ───────── */
const GRAMMAR = {"ms":[{"id":"ms-be-verb","title":"be동사 (am/are/is)","key":"주어가 누구냐에 따라 am, are, is가 정해져요.","hook":"나는 am, 너희들은 are, 한 명(걔)은 is! ‘나-아, 너-아, 걔-이’ 리듬으로 외워봐요.","summary":"be동사는 ‘~이다, ~에 있다’의 뜻으로 주어의 상태나 위치를 나타냅니다. 주어에 따라 am, are, is로 형태가 바뀝니다.","rules":["I 다음에는 am, You/We/They 다음에는 are, He/She/It 다음에는 is를 씁니다.","부정문은 be동사 뒤에 not을 붙입니다 (is not = isn’t, are not = aren’t).","의문문은 be동사를 주어 앞으로 보냅니다 (Are you ~? Is he ~?).","be동사 뒤에는 명사·형용사·장소 표현이 옵니다."],"examples":[{"en":"I am a student.","ko":"나는 학생이다."},{"en":"She is kind.","ko":"그녀는 친절하다."},{"en":"Are they at school?","ko":"그들은 학교에 있니?"}],"quiz":[{"q":"He ___ my best friend.","choices":["am","is","are"],"answer":1,"explain":"주어가 He이므로 is를 씁니다."},{"q":"올바른 부정문을 고르세요.","choices":["I am not tired.","I not am tired.","I no am tired."],"answer":0,"explain":"be동사 뒤에 not을 붙입니다."}]},{"id":"ms-general-verbs","title":"일반동사 (현재형)","key":"He, She, It이 주어면 동사 끝에 s를 붙여요.","hook":"3인칭 단수(걔 한 명) 뒤엔 동사가 s를 신어요. ‘걔는 s를 신는다’로 기억해요!","summary":"일반동사는 동작이나 상태를 나타내는 동사로 be동사를 제외한 동사입니다. 3인칭 단수 주어일 때 동사에 -s/-es를 붙입니다.","rules":["주어가 He/She/It(3인칭 단수)일 때 동사에 -s를 붙입니다 (plays, likes).","-o, -s, -x, -ch, -sh로 끝나면 -es를 붙입니다 (goes, watches).","자음 + y로 끝나면 y를 i로 고치고 -es (study → studies).","부정문·의문문은 do/does를 사용하며, 이때 동사는 원형을 씁니다.","have는 3인칭 단수에서 has로 바뀝니다."],"examples":[{"en":"I like apples.","ko":"나는 사과를 좋아한다."},{"en":"She watches TV every day.","ko":"그녀는 매일 TV를 본다."},{"en":"Do you play soccer?","ko":"너는 축구를 하니?"}],"quiz":[{"q":"She ___ to school by bus.","choices":["go","goes","going"],"answer":1,"explain":"3인칭 단수 주어이고 -o로 끝나므로 goes."},{"q":"올바른 의문문을 고르세요.","choices":["Does he like pizza?","Does he likes pizza?","Do he like pizza?"],"answer":0,"explain":"does 다음에는 동사원형을 씁니다."}]},{"id":"ms-past-tense","title":"과거시제 (동사의 과거형)","key":"끝난 일은 동사에 ed, 단 불규칙은 따로 외워요.","hook":"과거는 ‘이미 끝!’ 도장 찍듯 ed를 꾹. go-went처럼 말 안 듣는 애들만 따로 챙기면 돼요.","summary":"과거시제는 이미 끝난 과거의 일을 나타냅니다. 규칙동사는 -ed를 붙이고, 불규칙동사는 형태가 따로 변합니다.","rules":["규칙동사는 동사에 -ed를 붙입니다 (played, watched).","-e로 끝나면 -d만 붙이고, 자음 + y는 y를 i로 고쳐 -ed (study → studied).","불규칙동사는 형태가 바뀝니다 (go → went, eat → ate, have → had).","be동사 과거형은 was(단수), were(복수)입니다.","부정문·의문문은 did를 쓰고 동사는 원형으로 돌아갑니다."],"examples":[{"en":"I visited my grandmother yesterday.","ko":"나는 어제 할머니를 방문했다."},{"en":"He went to the park.","ko":"그는 공원에 갔다. (go의 과거형 went)"},{"en":"We were happy.","ko":"우리는 행복했다."}],"quiz":[{"q":"She ___ a letter last night.","choices":["write","wrote","writes"],"answer":1,"explain":"write의 불규칙 과거형은 wrote."},{"q":"I ___ not eat breakfast this morning.","choices":["do","did","was"],"answer":1,"explain":"일반동사 과거 부정은 did not."}]},{"id":"ms-future-tense","title":"미래시제 (will / be going to)","key":"앞으로 할 일은 will이나 be going to를 써요.","hook":"방금 정한 건 will, 미리 짜둔 계획은 be going to! ‘즉흥은 will, 계획은 going to’예요.","summary":"미래시제는 앞으로 일어날 일이나 계획을 나타냅니다. will 또는 be going to + 동사원형을 사용합니다.","rules":["will + 동사원형: 미래의 일, 즉흥적 결정, 의지를 나타냅니다.","be going to + 동사원형: 이미 정해진 계획이나 예정을 나타냅니다.","부정문은 will not(= won’t) 또는 be not going to를 씁니다.","의문문은 Will you ~? / Are you going to ~? 형태로 만듭니다."],"examples":[{"en":"I will call you tomorrow.","ko":"내가 내일 너에게 전화할게."},{"en":"We are going to watch a movie tonight.","ko":"우리는 오늘 밤 영화를 볼 예정이다."},{"en":"It will rain soon.","ko":"곧 비가 올 것이다."}],"quiz":[{"q":"I ___ help you with your homework.","choices":["will","am","do"],"answer":0,"explain":"미래의 의지를 나타내므로 will."},{"q":"She is going ___ buy a new phone.","choices":["to","for","at"],"answer":0,"explain":"be going to + 동사원형."}]},{"id":"ms-present-progressive","title":"현재진행형 (be + -ing)","key":"지금 하는 중이면 be동사 + 동사ing예요.","hook":"‘지금 이 순간!’ 카메라로 찰칵 찍는 느낌이 ing. am/are/is랑 짝꿍으로 꼭 같이 와요.","summary":"현재진행형은 지금 진행 중인 동작을 나타냅니다. be동사(am/are/is) + 동사의 -ing형으로 만듭니다.","rules":["형태는 am/are/is + 동사원형 + -ing입니다.","-e로 끝나면 e를 빼고 -ing (make → making).","단모음 + 단자음으로 끝나면 자음을 한 번 더 쓰고 -ing (run → running).","now, right now, at the moment 등과 자주 함께 쓰입니다."],"examples":[{"en":"I am studying English now.","ko":"나는 지금 영어를 공부하고 있다."},{"en":"They are playing soccer.","ko":"그들은 축구를 하고 있다."},{"en":"She is running to the bus stop.","ko":"그녀는 버스 정류장으로 달려가고 있다."}],"quiz":[{"q":"Look! The baby ___ sleeping.","choices":["is","are","am"],"answer":0,"explain":"주어 The baby는 3인칭 단수이므로 is."},{"q":"We are ___ lunch right now.","choices":["have","having","haves"],"answer":1,"explain":"have는 e를 빼고 having."}]},{"id":"ms-past-progressive","title":"과거진행형 (was/were + -ing)","key":"그때 하고 있던 일은 was/were + 동사ing예요.","hook":"현재진행의 be만 과거로 바꾸면 끝! ‘그 순간 찰칵’ 사진을 어제 찍었다고 생각해요.","summary":"과거진행형은 과거 특정 시점에 진행 중이던 동작을 나타냅니다. was/were + 동사의 -ing형으로 만듭니다.","rules":["형태는 was(단수)/were(복수) + 동사원형 + -ing입니다.","‘~하고 있었다, ~하는 중이었다’의 뜻입니다.","when, while 같은 접속사와 자주 함께 쓰입니다.","부정문은 was/were 뒤에 not을 붙입니다."],"examples":[{"en":"I was reading a book at 9 p.m.","ko":"나는 밤 9시에 책을 읽고 있었다."},{"en":"They were watching TV when I came home.","ko":"내가 집에 왔을 때 그들은 TV를 보고 있었다."},{"en":"She was not sleeping.","ko":"그녀는 자고 있지 않았다."}],"quiz":[{"q":"While he ___ cooking, the phone rang.","choices":["was","is","were"],"answer":0,"explain":"주어 he는 단수이므로 was + -ing."},{"q":"They ___ playing games at that time.","choices":["was","were","are"],"answer":1,"explain":"주어 they는 복수이므로 were."}]},{"id":"ms-present-perfect","title":"현재완료 (have/has + p.p.)","key":"과거가 지금까지 이어지면 have/has + p.p.예요.","hook":"과거랑 현재를 잇는 다리예요. yesterday 같은 ‘딱 그때’ 단어랑은 절대 안 어울려요!","summary":"현재완료는 과거의 일이 현재에 영향을 주거나 연결될 때 씁니다. have/has + 과거분사(p.p.)로 만듭니다.","rules":["형태는 have/has + 과거분사(p.p.)입니다.","주요 용법: 완료(just, already, yet), 경험(ever, never), 계속(for, since), 결과.","3인칭 단수 주어일 때는 has를 씁니다.","명백한 과거 시점 표현(yesterday, last year)과는 함께 쓰지 않습니다.","부정문은 have/has not, 의문문은 Have/Has + 주어 ~? 형태입니다."],"examples":[{"en":"I have finished my homework.","ko":"나는 숙제를 다 끝냈다. (완료)"},{"en":"She has lived here for ten years.","ko":"그녀는 여기서 10년 동안 살아왔다. (계속)"},{"en":"Have you ever been to Japan?","ko":"너는 일본에 가 본 적이 있니? (경험)"}],"quiz":[{"q":"He has ___ his lunch already.","choices":["eat","ate","eaten"],"answer":2,"explain":"have/has 뒤에는 과거분사 eaten."},{"q":"I ___ known him since 2020.","choices":["have","has","had"],"answer":0,"explain":"주어 I이므로 have + p.p., since와 함께 계속 용법."}]},{"id":"ms-modals","title":"조동사 (can/may/must/should/will)","key":"조동사 뒤에는 무조건 동사원형이 와요.","hook":"can, may, must, should는 동사한테 ‘원형으로 와!’ 명령해요. 뒤에 s나 ed 절대 금지예요.","summary":"조동사는 동사 앞에서 능력·허가·의무·추측 등의 의미를 더합니다. 조동사 뒤에는 항상 동사원형이 옵니다.","rules":["can: 능력(~할 수 있다), 허가(~해도 된다).","may: 허가(~해도 된다), 약한 추측(~일지도 모른다).","must: 강한 의무(~해야 한다), 강한 추측(~임에 틀림없다).","should: 충고·약한 의무(~하는 게 좋다).","조동사 뒤에는 반드시 동사원형을 쓰고, 부정은 조동사 + not."],"examples":[{"en":"She can speak three languages.","ko":"그녀는 3개 국어를 말할 수 있다."},{"en":"You should drink more water.","ko":"너는 물을 더 마시는 게 좋다."},{"en":"You must wear a helmet.","ko":"너는 헬멧을 써야 한다."}],"quiz":[{"q":"You must ___ your homework first.","choices":["do","to do","doing"],"answer":0,"explain":"조동사 뒤에는 동사원형."},{"q":"It’s cloudy. It ___ rain later.","choices":["may","must not","should"],"answer":0,"explain":"약한 추측은 may(~일지도 모른다)."}]},{"id":"ms-nouns-articles","title":"명사와 관사 (a/an/the)","key":"모음 소리 앞엔 an, 그 외 단수 앞엔 a예요.","hook":"a-e-i-o-u 소리로 시작하면 an! 발음으로 정해요. 물·돈처럼 못 세는 건 a/an 안 붙여요.","summary":"명사는 사람·사물·개념의 이름이며, 셀 수 있는 명사와 셀 수 없는 명사로 나뉩니다. 관사 a/an/the는 명사 앞에 붙습니다.","rules":["셀 수 있는 명사의 복수형은 보통 -s/-es를 붙입니다 (book → books).","a는 자음 소리, an은 모음 소리로 시작하는 단수 명사 앞에 씁니다.","the는 이미 언급했거나 특정한 대상을 가리킬 때 씁니다.","셀 수 없는 명사(water, milk, money)에는 a/an을 쓰지 않습니다.","불규칙 복수형도 있습니다 (man → men, child → children)."],"examples":[{"en":"I saw a dog. The dog was big.","ko":"나는 개 한 마리를 봤다. 그 개는 컸다."},{"en":"She ate an apple.","ko":"그녀는 사과 하나를 먹었다. (모음 소리 앞 an)"},{"en":"I need some water.","ko":"나는 물이 좀 필요하다. (셀 수 없는 명사)"}],"quiz":[{"q":"He is ___ honest boy.","choices":["a","an","the"],"answer":1,"explain":"honest는 h가 묵음이라 모음 소리로 시작하므로 an."},{"q":"I bought three ___ yesterday.","choices":["box","boxs","boxes"],"answer":2,"explain":"-x로 끝나는 명사의 복수형은 -es."}]},{"id":"ms-pronouns","title":"대명사 (인칭·지시·재귀·부정대명사)","key":"역할에 따라 I, me, my, mine으로 모양이 바뀌어요.","hook":"‘나’ 하나가 자리마다 옷을 갈아입어요. 주어는 I, 목적어는 me로 변신한다고 생각해요!","summary":"대명사는 명사를 대신하는 말입니다. 인칭·지시·재귀·부정대명사 등이 있으며 역할에 따라 형태가 바뀝니다.","rules":["인칭대명사: 주격(I, he), 목적격(me, him), 소유격(my, his), 소유대명사(mine, his).","지시대명사: this/these(가까운 것), that/those(먼 것).","재귀대명사: myself, yourself, himself 등 ‘~ 자신’을 나타냅니다.","부정대명사: some, any, one, something, everyone 등 막연한 대상을 가리킵니다.","some은 주로 긍정문, any는 부정문·의문문에 씁니다."],"examples":[{"en":"This is my book, and that is hers.","ko":"이것은 내 책이고, 저것은 그녀의 것이다."},{"en":"He hurt himself.","ko":"그는 (자기 자신을) 다쳤다. (재귀대명사)"},{"en":"Is there anything to eat?","ko":"먹을 것이 좀 있니? (의문문에서 anything)"}],"quiz":[{"q":"I made this cake ___.","choices":["myself","me","my"],"answer":0,"explain":"‘나 스스로’를 나타내는 재귀대명사 myself."},{"q":"Do you have ___ questions?","choices":["some","any","one"],"answer":1,"explain":"의문문에서는 보통 any를 씁니다."}]},{"id":"ms-adjectives-adverbs","title":"형용사와 부사","key":"명사 꾸미면 형용사, 동사 꾸미면 부사(보통 ly)예요.","hook":"형용사에 ly를 붙이면 부사로 변신! 단 good은 well로 바뀌는 말썽쟁이예요.","summary":"형용사는 명사를 꾸미고, 부사는 동사·형용사·다른 부사를 꾸밉니다. 많은 부사는 형용사에 -ly를 붙여 만듭니다.","rules":["형용사는 명사 앞에서 꾸미거나 be동사 뒤에서 보어로 쓰입니다.","부사는 주로 형용사 + -ly로 만듭니다 (slow → slowly).","자음 + y로 끝나는 형용사는 y를 i로 고쳐 -ly (happy → happily).","fast, hard, early처럼 형용사와 부사 형태가 같은 단어도 있습니다.","good의 부사형은 well(불규칙)입니다."],"examples":[{"en":"She is a careful driver.","ko":"그녀는 조심스러운 운전자다. (형용사)"},{"en":"She drives carefully.","ko":"그녀는 조심스럽게 운전한다. (부사)"},{"en":"He runs fast.","ko":"그는 빨리 달린다. (fast는 형용사·부사 동형)"}],"quiz":[{"q":"He sings very ___.","choices":["good","well","goodly"],"answer":1,"explain":"동사 sings를 꾸미는 부사가 필요하고, good의 부사형은 well."},{"q":"She is a ___ student.","choices":["quietly","quiet","quietness"],"answer":1,"explain":"명사 student를 꾸미는 형용사 quiet."}]},{"id":"ms-comparatives-superlatives","title":"비교급·최상급","key":"둘 비교는 er+than, 셋 이상 최고는 the+est예요.","hook":"짧은 단어는 er/est, 긴 단어는 more/most! ‘더’는 than이랑, ‘제일’은 the랑 손잡아요.","summary":"비교급은 두 대상을 비교할 때, 최상급은 셋 이상 중 가장 정도가 큰 것을 나타낼 때 씁니다.","rules":["짧은 형용사: 비교급 -er, 최상급 -est (tall → taller → tallest).","긴 형용사: more/most를 앞에 붙입니다 (more beautiful, most beautiful).","비교급 뒤에는 than(~보다), 최상급 앞에는 the를 씁니다.","불규칙: good/well → better → best, bad → worse → worst, many/much → more → most.","동등비교는 as + 형용사원급 + as (~만큼 …한)."],"examples":[{"en":"She is taller than her brother.","ko":"그녀는 남동생보다 키가 크다."},{"en":"This is the most interesting book.","ko":"이것은 가장 흥미로운 책이다."},{"en":"He runs as fast as me.","ko":"그는 나만큼 빨리 달린다."}],"quiz":[{"q":"Today is ___ than yesterday.","choices":["hot","hotter","hottest"],"answer":1,"explain":"than이 있으므로 비교급 hotter."},{"q":"This is the ___ movie I have ever seen.","choices":["good","better","best"],"answer":2,"explain":"good의 최상급은 best."}]},{"id":"ms-five-sentence-patterns","title":"문장의 5형식","key":"동사가 어떤 식구를 데려오느냐로 1~5형식이 갈려요.","hook":"동사가 대장! 혼자면 1형식, 보어 데려오면 2형식, 목적어면 3형식. 동사 따라 식구 수가 달라져요.","summary":"영어 문장은 동사의 성질에 따라 다섯 가지 기본 구조로 나뉩니다. 각 형식은 필요한 문장 성분이 다릅니다.","rules":["1형식: 주어 + 동사 (S + V).","2형식: 주어 + 동사 + 보어 (S + V + C), be동사·become·look 등.","3형식: 주어 + 동사 + 목적어 (S + V + O).","4형식: 주어 + 동사 + 간접목적어 + 직접목적어 (S + V + IO + DO).","5형식: 주어 + 동사 + 목적어 + 목적격보어 (S + V + O + OC)."],"examples":[{"en":"Birds fly.","ko":"새들이 난다. (1형식)"},{"en":"She gave me a present.","ko":"그녀는 나에게 선물을 주었다. (4형식)"},{"en":"We call him Tom.","ko":"우리는 그를 Tom이라고 부른다. (5형식)"}],"quiz":[{"q":"‘He looks happy.’의 형식은?","choices":["1형식","2형식","3형식"],"answer":1,"explain":"looks 뒤의 happy는 주어를 설명하는 보어이므로 2형식."},{"q":"‘She made me a cake.’의 형식은?","choices":["3형식","4형식","5형식"],"answer":1,"explain":"me(간접목적어) + a cake(직접목적어)이므로 4형식."}]},{"id":"ms-to-infinitive","title":"to부정사 (명사적·형용사적·부사적 용법)","key":"to + 동사원형은 명사·형용사·부사로 다 변신해요.","hook":"to부정사는 만능 변신 로봇! ‘~하는 것, ~할, ~하기 위해’ 세 가지 옷을 갈아입어요.","summary":"to부정사는 to + 동사원형 형태로 명사·형용사·부사처럼 쓰입니다. 문장에서 여러 역할을 할 수 있습니다.","rules":["형태는 to + 동사원형입니다.","명사적 용법: 주어·목적어·보어 역할 (~하는 것). I want to sleep.","형용사적 용법: 앞의 명사를 꾸밈 (~할). something to eat.","부사적 용법: 목적(~하기 위해), 감정의 원인, 결과 등을 나타냄.","want, hope, decide, plan 등은 뒤에 to부정사를 목적어로 취합니다."],"examples":[{"en":"I want to be a teacher.","ko":"나는 선생님이 되고 싶다. (명사적 용법)"},{"en":"I have a lot of work to do.","ko":"나는 할 일이 많다. (형용사적 용법)"},{"en":"She went to the store to buy milk.","ko":"그녀는 우유를 사기 위해 가게에 갔다. (부사적 용법, 목적)"}],"quiz":[{"q":"I hope ___ you again.","choices":["see","to see","seeing"],"answer":1,"explain":"hope는 to부정사를 목적어로 취합니다."},{"q":"He has many friends to ___ with.","choices":["play","plays","played"],"answer":0,"explain":"to + 동사원형이므로 play."}]},{"id":"ms-gerund","title":"동명사 (동사 + -ing)","key":"동사ing가 명사처럼 ‘~하기’로 쓰이면 동명사예요.","hook":"enjoy, finish는 동명사를 좋아해요. 전치사 뒤엔 무조건 ing! ‘전치사 다음 ing’로 외워요.","summary":"동명사는 동사에 -ing를 붙여 명사처럼 쓰는 말로 ‘~하는 것, ~하기’의 뜻입니다. 주어·목적어·보어 역할을 합니다.","rules":["형태는 동사원형 + -ing이며 명사 역할을 합니다.","enjoy, finish, mind, keep, avoid 등은 뒤에 동명사를 목적어로 취합니다.","전치사 뒤에는 동사를 동명사 형태로 씁니다 (be good at swimming).","주어로 쓰일 때는 단수 취급합니다.","want, hope, decide는 동명사가 아닌 to부정사를 취하니 주의."],"examples":[{"en":"I enjoy reading books.","ko":"나는 책 읽는 것을 즐긴다."},{"en":"Swimming is good for your health.","ko":"수영은 건강에 좋다. (주어)"},{"en":"She is interested in learning Korean.","ko":"그녀는 한국어 배우는 것에 관심이 있다. (전치사 뒤)"}],"quiz":[{"q":"Would you mind ___ the window?","choices":["open","to open","opening"],"answer":2,"explain":"mind는 동명사를 목적어로 취합니다."},{"q":"He is good at ___ the piano.","choices":["play","playing","to play"],"answer":1,"explain":"전치사 at 뒤에는 동명사."}]},{"id":"ms-participles","title":"분사 (현재분사·과거분사)","key":"ing는 능동(~하는), p.p.는 수동(~된) 형용사예요.","hook":"신나게 하는 영화는 exciting, 그걸 본 내가 excited! ‘일으키면 ing, 느끼면 ed’예요.","summary":"분사는 동사가 형용사처럼 쓰이는 형태입니다. 현재분사(-ing)는 능동·진행, 과거분사(p.p.)는 수동·완료의 의미를 가집니다.","rules":["현재분사: 동사 + -ing, ‘~하는, ~하고 있는’ (능동·진행).","과거분사: 규칙은 -ed, 불규칙은 따로 (broken, written), ‘~된, ~당한’ (수동·완료).","분사는 명사를 앞이나 뒤에서 꾸밉니다.","감정 동사: -ing는 ‘~한 감정을 일으키는’, -ed는 ‘~한 감정을 느끼는’ (exciting vs excited)."],"examples":[{"en":"Look at the sleeping baby.","ko":"자고 있는 아기를 봐. (현재분사)"},{"en":"I found a broken window.","ko":"나는 깨진 창문을 발견했다. (과거분사)"},{"en":"The movie was exciting, so I was excited.","ko":"그 영화는 흥미진진해서 나는 흥분했다."}],"quiz":[{"q":"The ___ news made everyone happy.","choices":["surprising","surprised","surprise"],"answer":0,"explain":"소식이 감정을 일으키므로 현재분사 surprising."},{"q":"She bought a car made ___ Korea.","choices":["in","on","at"],"answer":0,"explain":"made in + 장소, made는 과거분사로 car를 수식."}]},{"id":"ms-passive-voice","title":"수동태 (be + p.p.)","key":"동작을 ‘당하는’ 쪽이 주어면 be + p.p.예요.","hook":"‘내가 한다’가 아니라 ‘나에게 당한다’ 느낌! 누가 했는지는 by로 살짝 붙여줘요.","summary":"수동태는 동작을 ‘당하는’ 대상을 주어로 삼는 표현입니다. be동사 + 과거분사(p.p.)로 만들며 행위자는 by로 나타냅니다.","rules":["형태는 주어 + be동사 + 과거분사(p.p.) (+ by 행위자)입니다.","능동태의 목적어가 수동태의 주어가 됩니다.","시제는 be동사로 표현합니다 (is made, was made, will be made).","행위자가 분명하지 않거나 중요하지 않으면 by ~를 생략합니다.","부정문은 be동사 뒤에 not을 붙입니다."],"examples":[{"en":"The window was broken by Tom.","ko":"그 창문은 Tom에 의해 깨졌다."},{"en":"English is spoken in many countries.","ko":"영어는 많은 나라에서 사용된다."},{"en":"The cake was made by my mother.","ko":"그 케이크는 우리 엄마가 만들었다."}],"quiz":[{"q":"This book ___ by a famous writer.","choices":["wrote","was written","writes"],"answer":1,"explain":"수동태는 be동사 + 과거분사, write의 p.p.는 written."},{"q":"The room ___ cleaned every day.","choices":["is","does","has"],"answer":0,"explain":"수동태 현재형은 be동사 is + p.p."}]},{"id":"ms-prepositions","title":"전치사 (시간·장소·방향)","key":"시간·장소는 좁으면 at, 넓으면 in으로 가요.","hook":"점은 at, 면은 on, 공간은 in! ‘콕→at, 위→on, 안→in’ 점점 커지는 순서로 외워요.","summary":"전치사는 명사 앞에 놓여 시간·장소·방향 등의 관계를 나타냅니다. 뒤에는 명사나 동명사가 옵니다.","rules":["시간: at(시각), on(요일·날짜), in(월·연도·계절).","장소: at(좁은 지점), on(접촉면 위), in(넓은 공간·내부).","방향: to(~로), from(~에서), into(~안으로), out of(~밖으로).","전치사 뒤의 동사는 동명사(-ing) 형태로 씁니다.","기타: with(~와 함께), for(~을 위해), about(~에 관하여)."],"examples":[{"en":"I get up at 7 o’clock.","ko":"나는 7시에 일어난다. (시각 at)"},{"en":"We meet on Monday.","ko":"우리는 월요일에 만난다. (요일 on)"},{"en":"The book is in my bag.","ko":"그 책은 내 가방 안에 있다. (내부 in)"}],"quiz":[{"q":"My birthday is ___ May.","choices":["at","on","in"],"answer":2,"explain":"월 앞에는 in을 씁니다."},{"q":"She is good ___ singing.","choices":["at","in","on"],"answer":0,"explain":"be good at + 동명사."}]},{"id":"ms-conjunctions","title":"접속사 (등위·종속)","key":"and, but은 대등하게, because는 이유로 이어줘요.","hook":"접속사는 문장 다리예요. and(그리고), but(그러나), because(왜냐면)만 알아도 절반은 통해요!","summary":"접속사는 단어·구·문장을 연결합니다. 대등하게 잇는 등위접속사와 주절에 종속절을 잇는 종속접속사가 있습니다.","rules":["등위접속사: and(그리고), but(그러나), or(또는), so(그래서).","종속접속사(시간): when(~할 때), while(~하는 동안), before/after.","종속접속사(이유·조건): because(~때문에), if(만약 ~라면).","종속접속사(양보): although/though(비록 ~일지라도).","that은 ‘~라는 것’으로 명사절을 이끕니다 (I think that ~)."],"examples":[{"en":"I was tired, so I went to bed early.","ko":"나는 피곤해서 일찍 잤다. (so)"},{"en":"She smiled when she saw me.","ko":"그녀는 나를 봤을 때 미소 지었다. (when)"},{"en":"I stayed home because it rained.","ko":"비가 와서 나는 집에 있었다. (because)"}],"quiz":[{"q":"He is rich, ___ he is not happy.","choices":["and","but","so"],"answer":1,"explain":"앞뒤가 대조되므로 but."},{"q":"___ you study hard, you will pass.","choices":["If","But","Or"],"answer":0,"explain":"조건을 나타내는 종속접속사 If."}]},{"id":"ms-relative-pronouns","title":"관계대명사 (who/which/that)","key":"사람은 who, 사물은 which, 둘 다는 that이에요.","hook":"앞 명사를 설명하려고 끌고 오는 꼬리표예요. 헷갈리면 that 하나로 거의 다 돼요!","summary":"관계대명사는 두 문장을 연결하면서 앞의 명사(선행사)를 꾸미는 절을 이끕니다. who, which, that 등이 있습니다.","rules":["who: 선행사가 사람일 때 사용 (주격).","which: 선행사가 사물·동물일 때 사용.","that: 사람·사물 모두에 사용 가능.","관계대명사는 접속사와 대명사 역할을 동시에 합니다.","관계사절은 선행사 바로 뒤에 옵니다."],"examples":[{"en":"I know a boy who can play the violin.","ko":"나는 바이올린을 켤 수 있는 소년을 안다. (사람 who)"},{"en":"This is the book which I bought.","ko":"이것은 내가 산 책이다. (사물 which)"},{"en":"The dog that is barking is mine.","ko":"짖고 있는 그 개는 내 것이다. (that)"}],"quiz":[{"q":"I have a friend ___ lives in Busan.","choices":["who","which","where"],"answer":0,"explain":"선행사가 사람(friend)이므로 who."},{"q":"This is the watch ___ my dad gave me.","choices":["who","which","what"],"answer":1,"explain":"선행사가 사물(watch)이므로 which."}]},{"id":"ms-questions","title":"의문사·의문문","key":"묻고 싶은 게 있으면 의문사를 맨 앞에 둬요.","hook":"누가·뭘·언제·어디·왜·어떻게! who, what, when, where, why, how 육형제를 앞세워요.","summary":"의문문은 무언가를 묻는 문장입니다. 의문사가 없는 의문문은 동사를 앞으로 보내고, 의문사 의문문은 의문사로 시작합니다.","rules":["의문사: who(누가), what(무엇), when(언제), where(어디), why(왜), how(어떻게).","be동사 의문문: be동사 + 주어 ~? (Are you ~?).","일반동사 의문문: Do/Does/Did + 주어 + 동사원형 ~?","의문사 의문문: 의문사 + (do/does/be) + 주어 + 동사 ~?","how many(수), how much(양·가격), how long(기간) 등 how + 형용사/부사."],"examples":[{"en":"Where do you live?","ko":"너는 어디에 사니?"},{"en":"What time is it now?","ko":"지금 몇 시니?"},{"en":"How many books do you have?","ko":"너는 책을 몇 권 가지고 있니?"}],"quiz":[{"q":"___ is your favorite color?","choices":["What","Where","When"],"answer":0,"explain":"‘무엇’을 묻고 있으므로 What."},{"q":"___ does the movie start?","choices":["Who","When","How many"],"answer":1,"explain":"시작 시점을 묻고 있으므로 When."}]},{"id":"ms-imperative-exclamatory","title":"명령문·감탄문","key":"명령문은 동사원형으로, 감탄문은 What/How로 시작해요.","hook":"시킬 땐 다짜고짜 동사부터! 감탄할 땐 ‘What a~!’ ‘How~!’로 마음껏 호들갑 떨어요.","summary":"명령문은 명령·요청·지시를 나타내고 동사원형으로 시작합니다. 감탄문은 강한 감정을 나타내며 What이나 How로 시작합니다.","rules":["명령문은 주어 You를 생략하고 동사원형으로 시작합니다 (Open the door.).","부정 명령문은 Don’t + 동사원형 (Don’t run.).","Please를 붙이면 정중한 요청이 됩니다.","What 감탄문: What + (a/an) + 형용사 + 명사 (+ 주어 + 동사)!","How 감탄문: How + 형용사/부사 (+ 주어 + 동사)!"],"examples":[{"en":"Close the window, please.","ko":"창문 좀 닫아 주세요. (명령문)"},{"en":"What a beautiful flower it is!","ko":"정말 아름다운 꽃이구나! (What 감탄문)"},{"en":"How fast he runs!","ko":"그는 정말 빨리 달리는구나! (How 감탄문)"}],"quiz":[{"q":"___ late for school!","choices":["Not be","Don’t be","No be"],"answer":1,"explain":"부정 명령문은 Don’t + 동사원형."},{"q":"___ a smart student she is!","choices":["What","How","Very"],"answer":0,"explain":"명사(student)가 있으므로 What 감탄문."}]}],"hs":[{"id":"hs-sentence-structure","title":"문장 성분과 5형식 문장 구조 (S+V / S+V+O / S+V+O+O / S+V+O+C)","key":"문장 모양은 동사가 정한다, 동사부터 봐!","hook":"동사는 식당 사장님이에요. 사장님 성격(동사)에 따라 손님(목적어·보어) 자리가 정해져요. look·sound 뒤엔 형용사 한 접시!","summary":"영어 문장은 주어·동사를 중심으로 목적어·보어 등의 성분이 결합해 1~5형식으로 나뉘며, 동사의 성격이 문장 구조를 결정한다.","rules":["1형식(S+V), 2형식(S+V+SC), 3형식(S+V+O), 4형식(S+V+IO+DO), 5형식(S+V+O+OC)으로 구분한다.","2형식 보어는 주어를 설명하고(주격보어), 5형식 보어는 목적어를 설명한다(목적격보어).","감각동사(look, sound, feel, taste, smell)는 2형식에서 형용사 보어를 취한다: It looks great.","사역동사(make, have, let)와 지각동사(see, hear)는 5형식에서 원형부정사를 목적격보어로 쓴다.","구(phrase)와 절(clause)도 명사·형용사·부사 역할로 문장 성분이 될 수 있다."],"examples":[{"en":"The committee made him the new chairman.","ko":"위원회는 그를 새 의장으로 만들었다. (5형식, him=O, chairman=OC)"},{"en":"Her explanation sounded reasonable to everyone.","ko":"그녀의 설명은 모두에게 합리적으로 들렸다. (2형식, 감각동사+형용사)"},{"en":"They sent the refugees food and clothing.","ko":"그들은 난민들에게 음식과 옷을 보냈다. (4형식)"}],"quiz":[{"q":"The news made everyone ___.","choices":["happily","happy","happiness"],"answer":1,"explain":"5형식 목적격보어 자리에는 형용사 happy가 와야 한다."},{"q":"다음 중 2형식(S+V+SC) 문장은?","choices":["She gave me a book.","The soup tastes salty.","He opened the door."],"answer":1,"explain":"감각동사 taste는 형용사 보어를 취하는 2형식이다."}]},{"id":"hs-tense-overview","title":"시제 전반과 완료시제 (현재완료·과거완료·미래완료)","key":"완료시제는 ‘두 시점을 잇는 다리’다.","hook":"have p.p.는 과거에서 현재로 놓은 다리, had p.p.는 과거보다 더 옛날로 놓은 다리예요. yesterday랑은 절대 같이 안 가요!","summary":"완료시제는 두 시점 사이의 관계를 나타내며, 과거완료는 과거의 한 시점보다 더 이전을, 미래완료는 미래의 한 시점까지의 완료를 표현한다.","rules":["현재완료(have/has p.p.): 과거에서 현재까지의 완료·경험·계속·결과를 나타낸다.","과거완료(had p.p.): 과거의 기준 시점보다 더 앞선 사건(대과거)을 나타낸다.","미래완료(will have p.p.): 미래의 특정 시점까지 완료될 동작을 나타낸다.","완료시제는 명백한 과거 시점 부사(yesterday, ago, last~)와 함께 쓰지 않는다.","for(기간)와 since(기점)는 완료시제의 계속 용법과 자주 함께 쓰인다."],"examples":[{"en":"When I arrived, the train had already left.","ko":"내가 도착했을 때 기차는 이미 떠나 있었다. (과거완료=대과거)"},{"en":"By next year, she will have worked here for a decade.","ko":"내년이면 그녀는 여기서 10년째 일한 것이 된다. (미래완료)"},{"en":"He has lived in Seoul since 2010.","ko":"그는 2010년 이래로 서울에 살고 있다. (현재완료 계속)"}],"quiz":[{"q":"By the time help came, the man ___ for an hour.","choices":["has waited","had waited","waits"],"answer":1,"explain":"과거 시점(came)보다 더 이전부터의 일이므로 과거완료 had waited."},{"q":"I ___ this book last week.","choices":["have finished","had finished","finished"],"answer":2,"explain":"명백한 과거 부사 last week와는 단순과거 finished를 쓴다."}]},{"id":"hs-perfect-progressive","title":"완료진행 시제 (have been -ing / had been -ing / will have been -ing)","key":"have been -ing는 ‘쭉 해오는 중’을 강조한다.","hook":"끝났냐가 아니라 ‘계속 굴러가는 중’이 포인트! 굴러가는 바퀴 떠올려요. know·like 같은 상태동사는 진행형 안 써요.","summary":"완료진행형은 어떤 시점까지 동작이 계속 진행되어 왔음을 강조하는 시제이다.","rules":["현재완료진행(have/has been -ing): 과거에 시작해 현재까지 계속 진행 중인 동작을 강조한다.","과거완료진행(had been -ing): 과거 기준 시점까지 계속 진행되어 온 동작을 나타낸다.","미래완료진행(will have been -ing): 미래 시점까지 계속 진행될 동작을 나타낸다.","동작의 ‘지속·진행’을 강조하며 결과보다 과정에 초점을 둔다.","상태동사(know, like, own 등)는 보통 진행형으로 쓰지 않는다."],"examples":[{"en":"She has been studying English for three hours.","ko":"그녀는 세 시간째 영어를 공부하고 있다. (현재완료진행, 지속 강조)"},{"en":"They had been arguing before the teacher came in.","ko":"선생님이 들어오기 전 그들은 계속 말다툼하고 있었다. (과거완료진행)"},{"en":"By June, I will have been teaching for ten years.","ko":"6월이면 나는 10년째 가르쳐 오고 있는 셈이 된다. (미래완료진행)"}],"quiz":[{"q":"My eyes are tired because I ___ at the screen all day.","choices":["have been staring","stare","had stared"],"answer":0,"explain":"지금까지 계속 진행되어 온 동작이므로 현재완료진행."}]},{"id":"hs-passive-advanced","title":"수동태 심화 (4·5형식 수동태, by 이외의 전치사)","key":"by 말고 따라붙는 전치사를 통째로 외워라.","hook":"interested in, satisfied with, known to처럼 짝꿍 전치사를 세트로 외워요. laughed at은 at까지 딱 붙어 한 덩어리예요!","summary":"4형식·5형식 문장의 수동태와, by 대신 다른 전치사를 쓰는 관용적 수동 표현을 다룬다.","rules":["4형식 수동태는 간접목적어·직접목적어 각각을 주어로 만들 수 있다: He was given a prize. / A prize was given to him.","5형식 수동태에서 목적격보어는 그대로 남는다: He was elected chairman.","지각·사역동사의 원형부정사 보어는 수동태에서 to부정사로 바뀐다: He was made to wait.","by 이외 전치사: be interested in, be satisfied with, be known to/for/as, be covered with, be surprised at, be filled with.","동사구의 수동태는 전치사·부사까지 한 덩어리로 유지한다: He was laughed at."],"examples":[{"en":"The boy was seen to enter the building.","ko":"그 소년이 건물에 들어가는 것이 목격되었다. (지각동사 수동태, to부정사)"},{"en":"The mountain was covered with snow.","ko":"그 산은 눈으로 덮여 있었다. (by 이외 전치사 with)"},{"en":"She was satisfied with the results.","ko":"그녀는 결과에 만족했다. (be satisfied with)"}],"quiz":[{"q":"The room was filled ___ smoke.","choices":["by","with","of"],"answer":1,"explain":"be filled with: ~으로 가득 차다."},{"q":"He was made ___ the truth.","choices":["tell","to tell","telling"],"answer":1,"explain":"사역동사 수동태에서 원형부정사는 to부정사로 바뀐다."}]},{"id":"hs-modal-have-pp","title":"조동사 심화 (조동사 + have p.p.)","key":"조동사+have p.p.는 ‘과거에 대한 내 마음’이다.","hook":"should have p.p.는 ‘아 그거 했어야 했는데…’ 후회 한숨이에요. must have는 ‘분명 그랬을 거야’ 확신이고요.","summary":"조동사 + have p.p.는 과거 사실에 대한 추측·후회·확신 등을 나타내는 고등 핵심 표현이다.","rules":["must have p.p.: ~했음에 틀림없다 (과거에 대한 강한 확신).","cannot have p.p.: ~했을 리가 없다 (과거에 대한 강한 부정 추측).","may/might have p.p.: ~했을지도 모른다 (약한 추측).","should have p.p.: ~했어야 했는데 (안 한 것에 대한 후회·유감).","need not have p.p.: ~할 필요가 없었는데 (했지만 불필요했음)."],"examples":[{"en":"You should have studied harder for the exam.","ko":"너는 시험공부를 더 열심히 했어야 했다. (후회)"},{"en":"She cannot have said such a thing.","ko":"그녀가 그런 말을 했을 리가 없다. (강한 부정 추측)"},{"en":"He must have missed the bus.","ko":"그는 버스를 놓쳤음에 틀림없다. (강한 확신)"}],"quiz":[{"q":"The ground is wet. It ___ last night.","choices":["must rain","must have rained","should rain"],"answer":1,"explain":"과거 사실에 대한 강한 추측은 must have p.p."},{"q":"I ___ bought so much food; we wasted half of it.","choices":["should not have","must have","cannot have"],"answer":0,"explain":"하지 말았어야 했다는 후회는 should not have p.p."}]},{"id":"hs-to-infinitive-advanced","title":"to부정사 심화 (의미상 주어·완료부정사·too~to·enough to)","key":"too~to는 ‘너무 ~해서 못 한다’ 한 세트다.","hook":"too tired to walk = 너무 피곤해서 못 걸어요. ‘too(너무)’ 나오면 끝은 항상 ‘못 한다’로 떨어진다 기억해요!","summary":"to부정사의 의미상 주어, 본동사보다 앞선 시제를 나타내는 완료부정사, too~to / enough to 구문을 학습한다.","rules":["의미상 주어는 보통 for+목적격, 사람의 성질을 나타내는 형용사 뒤에서는 of+목적격을 쓴다.","완료부정사(to have p.p.)는 본동사보다 더 이전의 시제를 나타낸다.","too+형용사/부사+to부정사: 너무 ~해서 …할 수 없다 (= so~that…can’t).","형용사/부사+enough+to부정사: …할 만큼 충분히 ~하다.","It is + 형용사 + for[of] + 목적격 + to부정사 형태의 가주어 구문에 주의한다."],"examples":[{"en":"It was kind of you to help the old man.","ko":"노인을 도와주다니 당신은 친절하군요. (성질 형용사 → of you)"},{"en":"He seems to have been rich in his youth.","ko":"그는 젊은 시절 부자였던 것 같다. (완료부정사=본동사보다 앞선 시제)"},{"en":"The water was too hot to drink.","ko":"그 물은 너무 뜨거워서 마실 수 없었다. (too~to)"}],"quiz":[{"q":"She is old enough ___ on her own.","choices":["to travel","traveling","travel"],"answer":0,"explain":"enough 뒤에는 to부정사가 온다."},{"q":"It was careless ___ him to lose the keys.","choices":["for","of","to"],"answer":1,"explain":"사람의 성질을 나타내는 형용사(careless) 뒤에는 of+목적격."}]},{"id":"hs-gerund-advanced","title":"동명사 심화 (관용표현·동명사 vs to부정사)","key":"동사마다 -ing파/to파가 정해져 있다.","hook":"enjoy·finish는 -ing 좋아하는 ‘과거파’, want·hope는 to 좋아하는 ‘미래파’예요. remember는 둘 다 되는데 뜻이 확 달라져요!","summary":"동명사 관용표현과, 동사에 따라 목적어로 동명사·부정사를 선택하는 차이를 다룬다.","rules":["동명사 관용표현: be busy -ing, cannot help -ing(~하지 않을 수 없다), feel like -ing, look forward to -ing, be used to -ing.","동명사만 목적어로 취하는 동사: enjoy, finish, mind, avoid, give up, suggest, consider.","to부정사만 목적어로 취하는 동사: want, hope, decide, expect, promise, refuse.","remember/forget/stop/try는 동명사(과거·이미 한 일)와 부정사(미래·앞으로 할 일)의 의미가 다르다.","전치사 to 뒤에는 동명사가 온다: look forward to -ing, be devoted to -ing."],"examples":[{"en":"I am looking forward to meeting you.","ko":"당신을 만나기를 고대합니다. (to+동명사)"},{"en":"Remember to lock the door before you leave.","ko":"나가기 전에 문 잠그는 것을 기억해라. (앞으로 할 일 → to부정사)"},{"en":"He stopped smoking last year.","ko":"그는 작년에 담배 피우는 것을 그만두었다. (하던 일을 멈춤 → 동명사)"}],"quiz":[{"q":"I couldn’t help ___ when I heard the joke.","choices":["to laugh","laughing","laugh"],"answer":1,"explain":"cannot help -ing: ~하지 않을 수 없다."},{"q":"She avoided ___ eye contact with him.","choices":["to make","making","make"],"answer":1,"explain":"avoid는 동명사만 목적어로 취한다."}]},{"id":"hs-participle","title":"분사 (현재분사·과거분사, 명사 수식과 보어)","key":"-ing는 ‘하는 중’, p.p.는 ‘당한 것’이다.","hook":"exciting 영화는 신나게 ‘만드는’ 쪽, excited 나는 신남을 ‘느끼는’ 쪽! 원인이면 -ing, 사람 기분이면 -ed예요.","summary":"현재분사(-ing)는 능동·진행, 과거분사(p.p.)는 수동·완료의 의미로 명사를 수식하거나 보어로 쓰인다.","rules":["현재분사는 능동·진행(~하는, ~하고 있는), 과거분사는 수동·완료(~된, ~당한)를 나타낸다.","분사가 단독이면 명사 앞에서, 수식어구를 동반하면 명사 뒤에서 수식한다.","감정유발 동사: 사물·원인은 현재분사(boring, exciting), 사람·감정대상은 과거분사(bored, excited).","지각·사역동사의 목적격보어로 현재분사(능동·진행)나 과거분사(수동)가 쓰인다.","have/get + 목적어 + p.p.: ~을 …되게 하다(시키다/당하다)."],"examples":[{"en":"The movie was so boring that I fell asleep.","ko":"그 영화는 너무 지루해서 잠이 들었다. (사물 → boring)"},{"en":"I had my hair cut yesterday.","ko":"나는 어제 머리를 잘랐다. (have+O+p.p., 수동)"},{"en":"Look at the leaves falling from the trees.","ko":"나무에서 떨어지는 나뭇잎들을 봐라. (지각동사+현재분사)"}],"quiz":[{"q":"The audience was ___ by the performance.","choices":["exciting","excited","excite"],"answer":1,"explain":"사람이 감정을 느끼는 대상이므로 과거분사 excited."},{"q":"I heard my name ___ in the crowd.","choices":["call","called","to call"],"answer":1,"explain":"이름이 ‘불리는’ 수동 관계이므로 과거분사 called."}]},{"id":"hs-participial-construction","title":"분사구문 (시간·이유·조건·양보·동시동작)","key":"분사구문은 접속사+주어 지우고 -ing로 줄인 것.","hook":"긴 부사절을 가위로 싹둑! 접속사랑 주어 잘라내고 동사를 -ing로 바꾸면 끝. 당하는 거면 p.p.로 시작해요.","summary":"분사구문은 부사절을 분사로 줄여 시간·이유·조건·양보·동시동작 등을 간결하게 표현한다.","rules":["부사절의 접속사와 주어(주절과 동일 시)를 생략하고 동사를 -ing 형태로 바꾼다.","의미: 시간(~할 때), 이유(~때문에), 조건(~한다면), 양보(~일지라도), 동시동작/연속동작.","수동 분사구문은 Being p.p.이며 보통 Being은 생략되어 p.p.로 시작한다.","완료 분사구문(Having p.p.)은 주절보다 앞선 시제를 나타낸다.","주절과 주어가 다르면 독립분사구문으로 분사 앞에 주어를 남긴다 (예: It being cold)."],"examples":[{"en":"Walking along the beach, I found a shell.","ko":"해변을 걷다가 나는 조개껍데기를 발견했다. (시간/동시동작)"},{"en":"Having finished his homework, he went out.","ko":"숙제를 끝낸 후 그는 밖으로 나갔다. (완료 분사구문)"},{"en":"Written in haste, the report had many errors.","ko":"급히 작성되어서 그 보고서에는 오류가 많았다. (수동, Being 생략)"}],"quiz":[{"q":"___ tired, she kept working until midnight.","choices":["Being","Been","To be"],"answer":0,"explain":"양보의 분사구문, 형용사 보어 앞 Being. (Though she was tired)"},{"q":"___ the letter, he immediately replied.","choices":["Receiving","Having received","Received"],"answer":1,"explain":"편지를 받은 것이 답장보다 앞선 일이므로 완료 분사구문."}]},{"id":"hs-with-participle","title":"with 분사구문 (with + 목적어 + 분사/형용사/전명구)","key":"with+명사+분사는 ‘~한 채로’다.","hook":"with the door open = 문 열어둔 채로! with 다음 그림 한 장 떠올려요. 능동이면 -ing, 당하면 p.p.를 붙여요.","summary":"with+명사+분사 구문은 ‘~한 채로, ~하면서’의 부대상황을 나타낸다.","rules":["형태: with + 명사(목적어) + 현재분사/과거분사/형용사/부사/전치사구.","목적어와 분사가 능동 관계면 현재분사(-ing), 수동 관계면 과거분사(p.p.).","의미: ‘~을 …한 채로, ~하면서’의 동시상황·부대상황을 나타낸다.","분사 자리에 형용사·전치사구도 올 수 있다: with the door open, with a book in his hand.","주절의 동작과 동시에 일어나는 상태를 묘사하는 데 쓰인다."],"examples":[{"en":"She listened with her eyes closed.","ko":"그녀는 눈을 감은 채 들었다. (수동 → closed)"},{"en":"He fell asleep with the TV playing.","ko":"그는 TV를 켜 놓은 채 잠들었다. (능동 → playing)"},{"en":"Don’t speak with your mouth full.","ko":"입에 음식을 가득 넣은 채 말하지 마라. (형용사 full)"}],"quiz":[{"q":"He stood there with his arms ___.","choices":["folding","folded","fold"],"answer":1,"explain":"팔이 ‘포개진’ 수동 관계이므로 과거분사 folded."},{"q":"She came in with tears ___ down her face.","choices":["running","run","ran"],"answer":0,"explain":"눈물이 ‘흘러내리는’ 능동·진행이므로 현재분사 running."}]},{"id":"hs-relative-pronoun-advanced","title":"관계대명사 심화 (what·전치사+관계대명사)","key":"what은 선행사를 품은 ‘~하는 것’이다.","hook":"what은 the thing which를 한 단어로 압축한 알약이에요. 앞에 꾸밀 명사가 없으면 바로 what을 꺼내요!","summary":"선행사를 포함하는 관계대명사 what과, 전치사+관계대명사 구조를 다룬다.","rules":["what은 선행사를 포함하며 ‘~하는 것’으로 해석한다 (= the thing(s) which).","what절은 명사절로 주어·목적어·보어 역할을 한다.","전치사+관계대명사: 전치사를 관계대명사 앞으로 옮길 수 있다 (the house in which he lives).","전치사를 앞으로 옮길 때 that은 쓸 수 없고 who/which를 쓴다.","관계대명사 that은 계속적 용법과 전치사 바로 뒤에는 쓸 수 없다."],"examples":[{"en":"What matters most is your health.","ko":"가장 중요한 것은 너의 건강이다. (what절=주어)"},{"en":"This is the tool with which he fixed the car.","ko":"이것이 그가 차를 고친 도구이다. (전치사+관계대명사)"},{"en":"I can’t believe what he told me.","ko":"나는 그가 내게 말한 것을 믿을 수 없다. (what절=목적어)"}],"quiz":[{"q":"___ he said surprised everyone.","choices":["That","What","Which"],"answer":1,"explain":"선행사를 포함하며 주어 역할을 하는 명사절을 이끄는 것은 what."},{"q":"The pen ___ I write is broken.","choices":["that with","with which","which with"],"answer":1,"explain":"전치사+관계대명사는 with which 어순. (write with the pen)"}]},{"id":"hs-relative-non-restrictive","title":"관계대명사 계속적 용법 (콤마 + which/who)","key":"콤마 뒤 관계대명사는 ‘그런데 그게~’ 덧붙임이다.","hook":"콤마는 ‘아 참, 그런데~’ 하고 한마디 더 붙이는 자리예요. 여기선 that 출입금지, which·who만 들어와요!","summary":"계속적 용법은 콤마 뒤에서 선행사에 대한 부가 정보를 덧붙이며, 앞 문장 전체를 받기도 한다.","rules":["콤마(,) 뒤의 관계대명사는 선행사를 보충 설명하며 ‘그리고/그런데 그것은’으로 해석한다.","계속적 용법에는 that을 쓸 수 없고 which/who(m)/whose를 쓴다.","which는 앞 문장(절) 전체를 선행사로 받을 수 있다.","제한적 용법(콤마 없음)은 선행사를 한정하지만, 계속적 용법은 부가 정보만 더한다.","계속적 용법의 관계대명사는 생략할 수 없다."],"examples":[{"en":"My uncle, who lives in Busan, is a doctor.","ko":"내 삼촌은, 부산에 사시는데, 의사이다. (부가 정보)"},{"en":"He passed the exam, which surprised everyone.","ko":"그는 시험에 합격했고, 그것이 모두를 놀라게 했다. (앞 문장 전체를 받는 which)"},{"en":"She has two sons, both of whom are teachers.","ko":"그녀에게는 두 아들이 있는데, 둘 다 교사이다. (전치사+관계대명사 계속적 용법)"}],"quiz":[{"q":"He was late again, ___ made his boss angry.","choices":["that","which","what"],"answer":1,"explain":"앞 문장 전체를 받는 계속적 용법은 which."},{"q":"다음 중 계속적 용법에 쓸 수 없는 것은?","choices":["who","which","that"],"answer":2,"explain":"that은 계속적(콤마) 용법에 쓸 수 없다."}]},{"id":"hs-relative-adverb","title":"관계부사 (when·where·why·how)","key":"뒤 문장이 완전하면 관계부사다.","hook":"빠진 자리(주어·목적어) 없이 문장이 멀쩡하면 when·where·why를 써요. the way랑 how는 둘 중 하나만, 같이는 안 돼요!","summary":"관계부사는 ‘전치사+관계대명사’를 대신해 시간·장소·이유·방법을 나타내는 선행사를 수식한다.","rules":["when(시간), where(장소), why(이유), how(방법)로 부사절을 이끌어 선행사를 수식한다.","관계부사는 ‘전치사+which’로 바꿔 쓸 수 있다 (the day on which = the day when).","선행사가 the way이면 the way how로 함께 쓰지 않고 the way 또는 how 중 하나만 쓴다.","관계부사 뒤에는 완전한 문장이, 관계대명사 뒤에는 불완전한 문장이 온다.","선행사(the time, the place 등)나 관계부사는 문맥상 생략되기도 한다."],"examples":[{"en":"This is the house where I was born.","ko":"이곳은 내가 태어난 집이다. (장소 where)"},{"en":"Do you know the reason why she left?","ko":"그녀가 떠난 이유를 아니? (이유 why)"},{"en":"That is how he solved the problem.","ko":"그것이 그가 그 문제를 푼 방법이다. (방법 how)"}],"quiz":[{"q":"I remember the day ___ we first met.","choices":["which","when","where"],"answer":1,"explain":"선행사가 시간(the day)이므로 관계부사 when."},{"q":"Tell me the way ___ you fixed it. (the way how 불가)","choices":["how","in which","which"],"answer":1,"explain":"the way 뒤에는 how를 함께 못 쓰며, in which는 가능하다."}]},{"id":"hs-compound-relatives","title":"복합관계사 (whoever·whatever·whenever·however)","key":"-ever는 ‘~든지/~하더라도’ 둘 중 하나다.","hook":"whoever·whatever는 ‘누구든·뭐든’ 아니면 ‘~하더라도’ 양보! however는 뒤에 형용사 끌고 와요. However hard, …","summary":"복합관계사(-ever)는 명사절 또는 양보의 부사절을 이끈다.","rules":["복합관계대명사: whoever, whomever, whichever, whatever.","명사절: ‘~하는 누구든지/무엇이든지’ (Whoever comes is welcome).","양보 부사절: ‘~하더라도’ (Whatever you say, I won’t change my mind).","복합관계부사: whenever(~할 때마다/언제 ~하더라도), wherever(어디서 ~하든), however(아무리 ~하더라도).","however+형용사/부사+주어+동사 어순에 주의한다 (However hard it is, …)."],"examples":[{"en":"Whoever wants to join is welcome.","ko":"참가하고 싶은 사람은 누구든 환영이다. (명사절=주어)"},{"en":"However hard you try, you can’t please everyone.","ko":"아무리 열심히 노력해도 모두를 만족시킬 수는 없다. (양보)"},{"en":"Take whichever you like.","ko":"어느 것이든 마음에 드는 것을 가져가라. (명사절=목적어)"}],"quiz":[{"q":"___ you go, I will follow you.","choices":["Whatever","Wherever","However"],"answer":1,"explain":"‘어디로 가든’ 장소의 양보는 wherever."},{"q":"___ smart he is, he can’t solve this alone.","choices":["However","Whatever","Whoever"],"answer":0,"explain":"‘아무리 ~하더라도’는 However+형용사 어순."}]},{"id":"hs-subjunctive-past","title":"가정법 과거·과거완료·혼합가정법","key":"가정법은 시제를 한 칸 과거로 민다.","hook":"현재 상상이면 과거로, 과거 상상이면 had p.p.로 한 칸씩 뒤로! 사실이 아니니까 일부러 시제를 비틀어요.","summary":"현재 사실의 반대는 가정법 과거로, 과거 사실의 반대는 가정법 과거완료로 표현하며, 둘이 섞이면 혼합가정법이 된다.","rules":["가정법 과거: If+주어+과거동사(be동사는 were), 주어+would/could/might+동사원형. (현재 사실의 반대)","가정법 과거완료: If+주어+had p.p., 주어+would/could/might have p.p. (과거 사실의 반대)","혼합가정법: If+주어+had p.p., 주어+would+동사원형 (과거의 조건 → 현재의 결과).","if절의 If는 생략하고 주어와 (조)동사를 도치할 수 있다 (Were I you, Had I known).","가정법은 직설법과 달리 실제 사실과 반대되는 상상·소망을 나타낸다."],"examples":[{"en":"If I were rich, I would travel the world.","ko":"내가 부자라면 세계를 여행할 텐데. (가정법 과거)"},{"en":"If she had studied, she would have passed.","ko":"그녀가 공부했더라면 합격했을 텐데. (가정법 과거완료)"},{"en":"If I had taken the job, I would be happier now.","ko":"그때 그 일을 맡았더라면 지금 더 행복할 텐데. (혼합가정법)"}],"quiz":[{"q":"If I ___ you, I would apologize.","choices":["am","were","had been"],"answer":1,"explain":"현재 사실의 반대 가정법 과거, be동사는 were."},{"q":"If he had left earlier, he ___ the train.","choices":["catches","would catch","would have caught"],"answer":2,"explain":"과거 사실의 반대이므로 would have p.p."}]},{"id":"hs-subjunctive-special","title":"특수 가정법 (I wish·as if·without/but for·it’s time)","key":"I wish는 ‘~라면 좋을 텐데’ 아쉬움이다.","hook":"I wish는 못 이룬 소망의 한숨, as if는 ‘마치 ~인 척’ 연기예요. but for는 ‘그게 없었다면’ 가정이고요.","summary":"wish, as if, without/but for 등 다양한 가정법 표현을 학습한다.","rules":["I wish+가정법 과거: 현재 이루기 힘든 소망. I wish+가정법 과거완료: 과거에 대한 후회.","as if/as though+가정법: 사실과 다르게 ‘마치 ~인 것처럼’ 표현한다.","without/but for ~: ‘~이 없(었)다면’ (= If it were not for / If it had not been for).","It is time+주어+과거동사: ‘~할 때이다(아직 안 함)’의 가정법.","without/but for는 가정법 과거와 과거완료 모두에서 쓰일 수 있다."],"examples":[{"en":"I wish I had studied harder when I was young.","ko":"젊었을 때 더 공부했더라면 좋았을 텐데. (과거 후회)"},{"en":"He talks as if he knew everything.","ko":"그는 마치 모든 것을 아는 것처럼 말한다. (현재 사실 반대)"},{"en":"But for your help, I would have failed.","ko":"네 도움이 없었다면 나는 실패했을 것이다. (= If it had not been for)"}],"quiz":[{"q":"I wish I ___ taller.","choices":["am","were","have been"],"answer":1,"explain":"현재의 소망(가정법 과거), be동사는 were."},{"q":"It is time you ___ to bed.","choices":["go","went","have gone"],"answer":1,"explain":"It is time+주어+과거동사(가정법)."}]},{"id":"hs-inversion","title":"도치 (부정어구·only·보어·장소부사구의 문두 도치)","key":"부정어가 맨 앞 오면 주어·동사가 뒤집힌다.","hook":"Never·Hardly가 무대 맨 앞에 서면 뒤가 의문문처럼 홱 뒤집혀요! Here comes the bus처럼 장소도 그래요.","summary":"강조나 부정어구 등이 문두에 오면 주어와 (조)동사의 어순이 도치된다.","rules":["부정어구(Never, Hardly, Not until, No sooner, Little 등)가 문두로 나오면 도치된다.","도치 어순: 부정어구 + 조동사/do/be + 주어 + 동사원형.","only+부사(구/절)가 문두에 오면 주절이 도치된다.","보어나 장소·방향의 부사구가 문두에 올 때도 도치가 일어난다 (Here comes the bus).","so/neither/nor + (조)동사 + 주어: ‘~도 그렇다/그렇지 않다’ 동의 표현."],"examples":[{"en":"Never have I seen such a beautiful sight.","ko":"그렇게 아름다운 광경을 본 적이 없다. (부정어 도치)"},{"en":"Only then did he realize his mistake.","ko":"그때서야 그는 자신의 실수를 깨달았다. (only+부사 도치)"},{"en":"On the hill stood an old castle.","ko":"언덕 위에 오래된 성이 서 있었다. (장소부사구 도치)"}],"quiz":[{"q":"Hardly ___ when it started to rain.","choices":["I had arrived","had I arrived","I arrived"],"answer":1,"explain":"부정어 Hardly 문두 도치, had+주어+p.p."},{"q":"‘I like coffee.’ ‘___.’","choices":["So do I","So I do","Do so I"],"answer":0,"explain":"‘나도 그렇다’는 So+조동사+주어."}]},{"id":"hs-cleft-emphasis","title":"강조구문 (It is ~ that 강조구문·do 강조)","key":"It is ~ that는 강조하고 싶은 걸 끼우는 틀이다.","hook":"강조할 말을 It is와 that 사이 액자에 딱 끼워 넣어요! 동사를 강조하고 싶으면 do love처럼 do를 앞에 붙여요.","summary":"It is/was ~ that 강조구문은 주어·목적어·부사(구)를 강조하고, do는 동사를 강조한다.","rules":["It is/was + 강조 대상 + that … 형태로 주어·목적어·부사(구)를 강조한다.","강조 대상이 사람이면 that 대신 who, 사물이면 which, 시간·장소면 when/where도 가능.","강조구문 It~that을 빼면 완전한 문장이 남는다 (가주어 it과 구별).","동사 강조는 do/does/did+동사원형을 쓴다 (I do love you).","the very, on earth, in the world 등으로 명사·의문사를 강조하기도 한다."],"examples":[{"en":"It was Tom that broke the window.","ko":"창문을 깬 사람은 바로 톰이었다. (주어 강조)"},{"en":"It was yesterday that I met her.","ko":"내가 그녀를 만난 것은 바로 어제였다. (부사 강조)"},{"en":"I did finish the work on time.","ko":"나는 정말로 그 일을 제때 끝냈다. (동사 강조 did)"}],"quiz":[{"q":"___ in the park that they first met.","choices":["It was","There was","That was"],"answer":0,"explain":"It is/was ~ that 강조구문."},{"q":"I ___ want to help you. (동사 강조)","choices":["am","do","did"],"answer":1,"explain":"현재시제 동사 강조는 do+동사원형."}]},{"id":"hs-ellipsis-substitution","title":"생략과 대용 (반복 어구 생략·so/not·대동사)","key":"반복되는 말은 과감히 지우거나 대신한다.","hook":"앞에 나온 말은 또 안 써요. 동사는 do로, 절은 so/not으로 대신! I think so처럼 짧게 끝내요.","summary":"중복되는 어구를 생략하거나 so, do 등으로 대신해 문장을 간결하게 만든다.","rules":["등위접속사로 연결된 반복 어구(주어·동사 등)는 생략할 수 있다.","부사절에서 ‘주어+be동사’는 종종 생략된다 (When (you are) young, …).","to부정사의 반복을 피하기 위해 대부정사 to만 남긴다 (You can go if you want to).","동사구 반복은 대동사 do/does/did로 대신한다.","think/hope/believe 등의 절은 so(긍정)·not(부정)으로 대신한다 (I think so / I hope not)."],"examples":[{"en":"She can speak French, and he can too.","ko":"그녀는 프랑스어를 할 수 있고, 그도 그렇다. (speak French 생략)"},{"en":"When in Rome, do as the Romans do.","ko":"로마에서는 로마법을 따르라. (When you are in Rome에서 you are 생략)"},{"en":"‘Will it rain?’ ‘I hope not.’","ko":"‘비가 올까?’ ‘안 오길 바라.’ (절을 not으로 대용)"}],"quiz":[{"q":"I didn’t want to go, but I had ___.","choices":["to","do","so"],"answer":0,"explain":"to go의 반복을 피하는 대부정사 to."},{"q":"‘Is he coming?’ ‘I think ___.’","choices":["so","it","that"],"answer":0,"explain":"긍정의 절 대용은 so."}]},{"id":"hs-parallelism","title":"병렬구조 (등위·상관접속사의 문법적 대등)","key":"and·or 양옆은 같은 모양으로 맞춘다.","hook":"접속사는 양팔저울이에요. 한쪽이 명사면 반대쪽도 명사, to부정사면 to부정사! 모양 안 맞으면 기우뚱해요.","summary":"등위·상관접속사로 연결되는 요소들은 문법적으로 동일한 형태(병렬)를 유지해야 한다.","rules":["and, but, or로 연결되는 요소는 품사·구조가 대등해야 한다 (명사-명사, to부정사-to부정사 등).","상관접속사: both A and B, not only A but also B, either A or B, neither A nor B의 A·B는 같은 형태.","not only A but also B는 B에 강조가 있으며 = B as well as A로 바꿀 수 있다.","비교 대상(than, as~as)도 문법적으로 대등해야 한다.","동사구 나열 시 시제·태·형태를 일치시킨다."],"examples":[{"en":"She likes singing, dancing, and painting.","ko":"그녀는 노래, 춤, 그림 그리기를 좋아한다. (동명사 병렬)"},{"en":"He is not only smart but also diligent.","ko":"그는 똑똑할 뿐만 아니라 부지런하다. (형용사 병렬)"},{"en":"To know is one thing; to teach is another.","ko":"아는 것과 가르치는 것은 별개이다. (to부정사 병렬)"}],"quiz":[{"q":"He enjoys reading books and ___ movies.","choices":["to watch","watching","watch"],"answer":1,"explain":"reading과 병렬이 되도록 동명사 watching."},{"q":"She is both intelligent and ___.","choices":["creativity","creatively","creative"],"answer":2,"explain":"both A and B는 형용사-형용사 병렬, creative."}]},{"id":"hs-comparison-advanced","title":"비교구문 심화 (배수·the 비교급 the 비교급·비교급 강조)","key":"the 비교급, the 비교급은 ‘~할수록 더~’다.","hook":"The more, the better = 많을수록 더 좋다! 비교급 강조엔 much·far를 쓰고 very는 안 돼요. superior는 than 말고 to랑 짝!","summary":"배수 표현, the 비교급 the 비교급 구문, 비교급 강조 부사 등 심화 비교 표현을 다룬다.","rules":["배수 비교: 배수사(twice, three times) + as+원급+as / 배수사 + 비교급+than.","the 비교급 ~, the 비교급 …: ‘~하면 할수록 더 …하다’ (The more, the better).","비교급 강조는 much, far, even, still, a lot을 쓴다 (much more important). very는 쓸 수 없다.","최상급 강조·표현: one of the+최상급+복수명사, by far the+최상급.","라틴어 비교: superior to, inferior to, prior to처럼 than 대신 to를 쓴다."],"examples":[{"en":"This box is twice as heavy as that one.","ko":"이 상자는 저것보다 두 배 무겁다. (배수+as 원급 as)"},{"en":"The harder you work, the more you earn.","ko":"더 열심히 일할수록 더 많이 번다. (the 비교급 the 비교급)"},{"en":"Health is far more important than money.","ko":"건강이 돈보다 훨씬 더 중요하다. (비교급 강조 far)"}],"quiz":[{"q":"My car is ___ expensive than yours.","choices":["very","much","so"],"answer":1,"explain":"비교급 강조에는 much를 쓰며 very는 불가."},{"q":"The more you practice, ___ you become.","choices":["the better","better","the best"],"answer":0,"explain":"the 비교급 ~ the 비교급 구문."}]},{"id":"hs-reported-speech","title":"화법 (직접화법·간접화법 전환)","key":"간접화법은 인칭·시제·시간말을 옮긴다.","hook":"남의 말을 내 입으로 전할 때 시점을 한 칸 뒤로! now는 then, today는 that day로 갈아끼워요.","summary":"직접화법을 간접화법으로 바꿀 때 인칭·시제·지시어를 적절히 일치시킨다.","rules":["평서문: say(to)→tell, 인용부호를 that절로, 시제·인칭·부사를 일치시킨다.","의문문: ask + 의문사 + 주어 + 동사 어순, 의문사 없으면 if/whether를 쓴다.","명령문: tell/ask/order + 목적어 + to부정사, 부정은 not to부정사.","시제 일치: 주절이 과거이면 종속절 시제를 한 단계 과거로 옮긴다.","지시어 변화: this→that, here→there, now→then, today→that day, ago→before."],"examples":[{"en":"He said, ‘I am tired.’ → He said that he was tired.","ko":"그는 피곤하다고 말했다. (시제·인칭 일치)"},{"en":"She asked me, ‘Where do you live?’ → She asked me where I lived.","ko":"그녀는 내가 어디 사는지 물었다. (의문사+주어+동사)"},{"en":"He told me to be quiet.","ko":"그는 내게 조용히 하라고 말했다. (명령문 → to부정사)"}],"quiz":[{"q":"She said, ‘I will call you.’ → She said she ___ call me.","choices":["will","would","would have"],"answer":1,"explain":"주절 과거에 맞춰 will→would로 시제 일치."},{"q":"He asked me ___ I was busy.","choices":["that","what","if"],"answer":2,"explain":"의문사 없는 의문문의 간접화법은 if/whether."}]},{"id":"hs-clauses-agreement","title":"명사절·부사절·접속사와 수일치·부분부정","key":"시간·조건 부사절은 미래도 현재로 쓴다.","hook":"When he comes처럼 will 자리에 그냥 현재형을 넣어요! not all은 ‘다 그런 건 아니다’ 부분부정, 전체부정과 헷갈리지 마요.","summary":"절을 이끄는 접속사의 역할과 주어-동사 수일치, 그리고 부분부정 표현을 정리한다.","rules":["명사절: that(~라는 것), whether/if(~인지), 의문사절이 주어·목적어·보어 역할을 한다.","부사절: 시간(when, while), 이유(because, since), 조건(if, unless), 양보(although, even though).","시간·조건의 부사절에서는 현재시제가 미래를 대신한다 (When he comes, …).","수일치: each/every/one of+복수명사는 단수 취급, a number of+복수는 복수, the number of는 단수.","부분부정: not always/all/every/both는 ‘모두/항상 ~인 것은 아니다’ (전체부정과 구별)."],"examples":[{"en":"Whether he comes or not doesn’t matter.","ko":"그가 오든 안 오든 중요하지 않다. (whether 명사절=주어, 단수 취급)"},{"en":"Not all rich people are happy.","ko":"모든 부자가 행복한 것은 아니다. (부분부정)"},{"en":"Each of the students has a laptop.","ko":"학생들 각자가 노트북을 가지고 있다. (each of+복수 → 단수 동사)"}],"quiz":[{"q":"If it ___ tomorrow, we will cancel the trip.","choices":["will rain","rains","rained"],"answer":1,"explain":"조건 부사절에서는 현재시제가 미래를 대신한다."},{"q":"‘Not every student passed.’의 의미는?","choices":["아무도 합격 못 했다","모든 학생이 합격했다","일부는 합격하지 못했다"],"answer":2,"explain":"not every는 부분부정으로 ‘모두가 ~한 것은 아니다’."}]},{"id":"hs-conjunctions-connectors","title":"접속사와 접속부사 (등위·종속접속사·연결어)","key":"접속부사는 두 문장을 직접 못 잇는다.","hook":"however·therefore는 접착제가 아니라 화살표 표지판! 두 문장 이으려면 세미콜론(;)이나 마침표가 꼭 필요해요. despite는 명사, although는 절!","summary":"접속사는 단어·구·절을 연결하며, 접속부사는 문장 사이의 논리 관계를 보여 주는 연결어로 문법적 역할이 다르다.","rules":["등위접속사(and, but, or, so, for)는 대등한 요소를, 종속접속사는 주절과 종속절을 연결한다.","접속부사(however, therefore, moreover, nevertheless, otherwise)는 부사이므로 두 절을 직접 연결하지 못한다.","접속부사로 두 절을 이을 때는 세미콜론(;)을 쓰거나 마침표로 문장을 나눈다.","양보의 종속접속사 although/though는 절을, 전치사 despite/in spite of는 명사(구)를 취한다.","because(접속사)+절, because of(전치사)+명사구로 품사에 맞게 구별해 쓴다."],"examples":[{"en":"It was raining; however, we went out.","ko":"비가 오고 있었다. 그러나 우리는 외출했다. (접속부사 앞 세미콜론)"},{"en":"Although he was tired, he kept working.","ko":"비록 그는 피곤했지만 계속 일했다. (종속접속사 although+절)"},{"en":"The game was canceled because of the storm.","ko":"폭풍 때문에 경기가 취소되었다. (because of+명사구)"}],"quiz":[{"q":"He studied hard; ___, he failed the test.","choices":["however","although","despite"],"answer":0,"explain":"세미콜론 뒤 두 절을 잇는 자리에는 접속부사 however."},{"q":"___ the bad weather, they finished the hike.","choices":["Although","Despite","Because"],"answer":1,"explain":"뒤에 명사구가 오므로 전치사 Despite."}]}],"sn":[{"id":"sn-subject-verb-agreement","title":"주어-동사 수일치 (긴 주어·도치)","key":"수식어는 괄호로 묶고, 맨 앞 핵심 명사에만 동사를 맞춰요.","hook":"긴 주어는 양파예요! of~, 관계절 껍질을 다 벗기면 알맹이 명사 하나가 나와요. 그 알맹이만 보고 단수·복수 결정!","summary":"동사의 단수/복수는 진짜 주어의 핵(head)에 일치시킨다. 수식어구(전치사구·관계절·분사구)는 수를 결정하지 않으므로 괄호로 묶어 제거하고 핵심 주어만 본다.","rules":["주어 뒤 「전치사 + 명사」(of the students 등)는 수일치에 관여하지 않는다: 핵심 명사를 찾아라.","관계절·분사구로 길어진 주어는 끝의 명사가 아니라 맨 앞 핵심 명사에 동사를 맞춘다.","장소·방향 부사구가 문두로 가면 도치되어 「부사구 + 동사 + 주어」 순; 이때도 동사는 뒤의 진주어에 일치.","There is/are 구문은 뒤따르는 진주어의 수에 동사를 일치시킨다.","주의 함정: a number of + 복수명사는 복수 취급, the number of + 복수명사는 단수 취급."],"examples":[{"en":"The list of items needed for the trip is on the table.","ko":"여행에 필요한 물품의 목록이 탁자 위에 있다. (핵심 주어 list → is)"},{"en":"Behind the old building stand two tall pine trees.","ko":"오래된 건물 뒤에 키 큰 소나무 두 그루가 서 있다. (도치, 진주어 trees → stand)"},{"en":"A number of researchers have questioned the result.","ko":"많은 연구자들이 그 결과에 의문을 제기했다. (a number of → 복수 have)"}],"quiz":[{"q":"The books on the top shelf ___ covered with dust.","choices":["is","are","was"],"answer":1,"explain":"핵심 주어는 The books(복수)이고 on the top shelf는 수식어구이므로 are."},{"q":"Among the trees ___ a small wooden cabin.","choices":["stand","stands","are standing"],"answer":1,"explain":"장소 부사구 도치 구문으로 진주어 a small wooden cabin(단수)에 일치하여 stands."}]},{"id":"sn-active-vs-passive","title":"능동태 vs 수동태","key":"동사 뒤에 목적어 있으면 능동, 없고 당하는 느낌이면 수동.","hook":"목적어는 능동의 짝꿍이에요. 짝꿍이 사라졌는데 주어가 ‘당하는’ 쪽이면 be+p.p. 옷을 입혀 주세요!","summary":"주어가 동작을 ‘하는’ 주체면 능동, 동작을 ‘받는’ 대상이면 수동(be + p.p.)으로 쓴다. 동사 뒤에 목적어가 있으면 능동, 없고 의미상 당하는 관계면 수동을 의심한다.","rules":["타동사인데 뒤에 목적어가 없고 주어가 동작의 대상이면 수동(be + p.p.)이 맞다.","수동태 뒤에는 목적어가 올 수 없다: 목적어가 보이면 능동을 의심하라.","감정 동사(interest, surprise, satisfy)는 사람이 ‘느끼면’ 수동(be interested), 사물이 ‘유발하면’ 능동/현재분사.","자동사(happen, occur, appear, exist, consist, rise)는 수동태로 쓸 수 없다.","함정: be made of/from, be known for/as/to 등 관용 수동 표현을 익혀 두라."],"examples":[{"en":"The bridge was built more than a hundred years ago.","ko":"그 다리는 100년도 더 전에 지어졌다. (다리는 지어지는 대상 → 수동)"},{"en":"The accident occurred late at night.","ko":"그 사고는 밤늦게 일어났다. (occur는 자동사 → 수동 불가)"},{"en":"Many students were satisfied with the new policy.","ko":"많은 학생들이 새 정책에 만족했다. (사람이 느낌 → 수동 be satisfied)"}],"quiz":[{"q":"The ancient temple ___ by thousands of tourists every year.","choices":["visits","is visited","visiting"],"answer":1,"explain":"사원은 방문을 받는 대상이고 뒤에 목적어가 없으므로 수동 is visited."},{"q":"A strange noise ___ from the basement last night.","choices":["was come","came","was coming from being"],"answer":1,"explain":"come은 자동사라 수동 불가; 능동 came이 옳다."}]},{"id":"sn-tense-agreement","title":"시제 일치","key":"ago·yesterday·last가 보이면 무조건 단순과거, 현재완료 금지!","hook":"‘콕 집은 과거 시간’ 친구들(어제, 작년)은 현재완료를 싫어해요. 이 친구들이 보이면 동사도 그냥 과거로!","summary":"주절 시제와 종속절 시제의 논리적 관계, 그리고 시간 부사와 동사 시제의 일치를 본다. 명백한 과거 표시어가 있으면 현재완료를 쓸 수 없다.","rules":["ago, yesterday, last + 시점, in + 과거연도 등 명확한 과거 부사는 단순과거와 함께 쓴다(현재완료 불가).","since/for + 기간이 ‘지금까지 계속’을 뜻하면 현재완료(has p.p.)를 쓴다.","시간·조건 부사절(when, if, until, as soon as)에서는 미래의 일도 현재시제로 쓴다.","역사적·불변의 진리는 항상 현재시제로 표현한다.","주절이 과거이면 종속절은 보통 과거/과거완료로 시제를 맞춘다(시제 일치)."],"examples":[{"en":"She moved to Seoul three years ago.","ko":"그녀는 3년 전에 서울로 이사했다. (ago → 단순과거)"},{"en":"We have known each other since 2010.","ko":"우리는 2010년부터 서로 알고 지냈다. (since → 현재완료)"},{"en":"I will call you when the meeting ends.","ko":"회의가 끝나면 너에게 전화할게. (시간 부사절 → 현재시제 ends)"}],"quiz":[{"q":"He ___ his homework two hours ago.","choices":["has finished","finished","had finished"],"answer":1,"explain":"two hours ago라는 명백한 과거 부사가 있으므로 단순과거 finished."},{"q":"As soon as it ___ raining, we will go out.","choices":["will stop","stops","stopped"],"answer":1,"explain":"시간 부사절에서는 미래를 현재시제로 쓰므로 stops."}]},{"id":"sn-relative-pronoun-vs-adverb","title":"관계대명사 vs 관계부사","key":"뒤 문장 빠진 데 있으면 관계대명사, 다 갖췄으면 관계부사.","hook":"뒤 문장을 체크하세요. 자리가 ‘텅’ 비었으면 which/who, 빈틈없이 ‘꽉’ 찼으면 where/when! 선행사 말고 완전성으로 판단해요.","summary":"뒤 문장이 불완전하면(주어/목적어 빠짐) 관계대명사, 완전하면 관계부사(where/when/why/how)를 쓴다. 선행사가 장소·시간이라도 절의 완전성으로 판단한다.","rules":["관계대명사(who/which/that) 뒤 절은 주어 또는 목적어가 빠진 불완전한 절.","관계부사(where/when/why/how) 뒤 절은 성분이 다 갖춰진 완전한 절.","함정: 선행사가 place라도 뒤 절이 불완전하면 which(관계대명사)를 쓴다.","관계부사 = 「전치사 + 관계대명사」로 바꿔 쓸 수 있다(where = in/at which).","the way와 how는 함께 쓰지 않는다: the way 또는 how 중 하나만."],"examples":[{"en":"This is the house where I grew up.","ko":"여기가 내가 자란 집이다. (뒤 절 완전 → where)"},{"en":"This is the house which my grandfather built.","ko":"이것이 할아버지가 지으신 집이다. (built의 목적어 빠짐 → which)"},{"en":"I remember the day when we first met.","ko":"우리가 처음 만난 날을 기억한다. (뒤 절 완전 → when)"}],"quiz":[{"q":"Tokyo is the city ___ I want to live someday.","choices":["which","where","that"],"answer":1,"explain":"live 뒤 성분이 다 갖춰진 완전한 절이므로 관계부사 where."},{"q":"He told me the reason ___ he was late.","choices":["which","why","what"],"answer":1,"explain":"선행사 reason이고 뒤 절이 완전하므로 관계부사 why."}]},{"id":"sn-what-that-which","title":"관계대명사 what vs that vs which","key":"앞에 선행사 없으면 what, 있으면 that/which.","hook":"what은 ‘the thing which’를 통째로 삼킨 욕심쟁이! 앞에 꾸밀 명사가 없을 때 혼자 다 해먹어요.","summary":"what은 선행사를 포함(the thing which)하여 명사절을 이끌고, that/which는 선행사가 있어야 한다. 앞에 선행사가 없으면 what, 있으면 that/which를 쓴다.","rules":["what = 선행사 포함, 명사절(주어·목적어·보어 자리)을 이끌며 앞에 선행사를 둘 수 없다.","that/which는 반드시 선행사가 앞에 있어야 하고 형용사절을 이끈다.","콤마(,) 뒤 계속적 용법에는 that을 쓸 수 없다: which를 쓴다.","전치사 바로 뒤에는 that을 쓸 수 없다: 전치사 + which.","함정: 앞에 명사가 보여도 그 명사가 절의 일부가 아니면 what일 수 있으니 구조를 확인하라."],"examples":[{"en":"What matters most is your attitude.","ko":"가장 중요한 것은 너의 태도이다. (선행사 없음 → what 명사절 주어)"},{"en":"This is the book that changed my life.","ko":"이것이 내 인생을 바꾼 책이다. (선행사 book → that)"},{"en":"He lost his phone, which made him anxious.","ko":"그는 휴대폰을 잃어버렸고, 그것이 그를 불안하게 했다. (콤마 계속적 용법 → which)"}],"quiz":[{"q":"I cannot believe ___ he said to me yesterday.","choices":["that","what","which"],"answer":1,"explain":"believe의 목적어 명사절이고 선행사가 없으며 said의 목적어가 빠졌으므로 what."},{"q":"She showed me a painting, ___ was created by her mother.","choices":["that","which","what"],"answer":1,"explain":"콤마 뒤 계속적 용법이므로 that 불가, which가 옳다."}]},{"id":"sn-conjunction-that-vs-relative","title":"접속사 that vs 관계사","key":"that 뒤 문장이 완전하면 접속사, 빠진 게 있으면 관계대명사.","hook":"the fact that처럼 ‘완전한 문장’을 달고 오면 접속사 that. 뒤에 주어·목적어가 ‘구멍’ 나 있으면 관계대명사!","summary":"that 뒤 절이 완전하면 접속사 that(명사절·동격절), 불완전하면 관계대명사 that이다. 또 the fact that처럼 동격절을 이끄는 접속사 that과 구별한다.","rules":["접속사 that: 뒤 절이 완전(성분 다 갖춤), 명사절 또는 동격절을 이끈다.","관계대명사 that: 뒤 절이 불완전(주어/목적어 빠짐), 선행사를 수식한다.","the fact/idea/news + that + 완전한 절 → 동격의 접속사 that.","전치사의 목적어로는 접속사 that 절이 올 수 없다(in that 제외).","함정: 의미가 통해도 구조로 판단; 절의 완전/불완전을 먼저 확인하라."],"examples":[{"en":"I know that he is honest.","ko":"나는 그가 정직하다는 것을 안다. (뒤 절 완전 → 접속사 that)"},{"en":"The rumor that she quit was false.","ko":"그녀가 그만뒀다는 소문은 거짓이었다. (the rumor 동격 → 접속사 that)"},{"en":"The book that you lent me was great.","ko":"네가 빌려준 책은 훌륭했다. (lent의 목적어 빠짐 → 관계대명사 that)"}],"quiz":[{"q":"There is strong evidence ___ the plan will work.","choices":["that (접속사)","which","what"],"answer":0,"explain":"evidence와 동격이고 뒤 절이 완전하므로 동격 접속사 that."},{"q":"Everything ___ glitters is not gold.","choices":["that (관계대명사)","what","if"],"answer":0,"explain":"glitters의 주어가 빠진 불완전한 절을 이끌어 선행사 Everything을 수식하는 관계대명사 that."}]},{"id":"sn-participle-active-passive","title":"분사(현재분사 vs 과거분사) 능동/수동","key":"명사가 직접 하면 -ing, 당하면 p.p.","hook":"명사한테 물어보세요. ‘네가 한 거야?’ 응이면 -ing(능동), ‘너 당한 거야?’ 응이면 p.p.(수동)!","summary":"수식하는 명사와의 관계가 능동·진행이면 현재분사(-ing), 수동·완료이면 과거분사(p.p.)를 쓴다. ‘무엇이 무엇을 하는가/당하는가’를 따진다.","rules":["현재분사(-ing): 명사가 동작을 하는 능동 관계 또는 진행.","과거분사(p.p.): 명사가 동작을 받는 수동 관계 또는 완료.","감정 분사: 감정을 유발하면 -ing(boring), 감정을 느끼면 -ed(bored).","분사구문도 주어와의 관계가 능동이면 -ing, 수동이면 (being) p.p.","함정: 자동사의 과거분사(fallen leaves)는 완료의 의미로 쓰일 수 있다."],"examples":[{"en":"The boy reading a book is my brother.","ko":"책을 읽고 있는 소년이 내 동생이다. (소년이 읽음 → 능동 reading)"},{"en":"The language spoken in Brazil is Portuguese.","ko":"브라질에서 쓰이는 언어는 포르투갈어이다. (언어가 말해짐 → 수동 spoken)"},{"en":"The movie was so boring that I fell asleep.","ko":"그 영화는 너무 지루해서 나는 잠들었다. (영화가 지루함 유발 → boring)"}],"quiz":[{"q":"Look at the ___ window; someone has thrown a stone.","choices":["breaking","broken","to break"],"answer":1,"explain":"창문은 깨짐을 당한 대상이므로 수동의 과거분사 broken."},{"q":"The children were ___ by the magician’s tricks.","choices":["exciting","excited","excite"],"answer":1,"explain":"아이들이 흥분을 느낀 것이므로 감정 수동 excited."}]},{"id":"sn-to-infinitive-vs-gerund","title":"to부정사 vs 동명사","key":"동사가 뭘 좋아하는지 외우고, 전치사 뒤엔 무조건 -ing.","hook":"want·hope는 ‘앞으로’를 보는 to부정사파, enjoy·finish는 ‘이미 진행’ 동명사파! 전치사 to 뒤도 -ing 잊지 마세요.","summary":"동사마다 목적어로 to부정사 또는 동명사를 취하며, 일부 동사는 둘 다 가능하되 의미가 달라진다. 동사의 어법과 의미를 함께 본다.","rules":["to부정사를 목적어로: want, hope, decide, plan, agree, refuse, expect.","동명사를 목적어로: enjoy, finish, avoid, mind, give up, consider, suggest, deny.","remember/forget/regret + to부정사(미래·앞으로 할 일) vs + -ing(과거에 한 일).","stop + to부정사(하기 위해 멈춤, 부사적) vs stop + -ing(~하기를 그만두다).","전치사 뒤에는 항상 동명사(-ing): look forward to + -ing."],"examples":[{"en":"She decided to study abroad next year.","ko":"그녀는 내년에 유학 가기로 결정했다. (decide → to부정사)"},{"en":"I really enjoy listening to jazz.","ko":"나는 재즈 듣기를 정말 즐긴다. (enjoy → 동명사)"},{"en":"Remember to lock the door before you leave.","ko":"나가기 전에 문 잠그는 것을 기억해라. (앞으로 할 일 → to부정사)"}],"quiz":[{"q":"He avoided ___ eye contact during the interview.","choices":["to make","making","make"],"answer":1,"explain":"avoid는 동명사를 목적어로 취하므로 making."},{"q":"I look forward to ___ you again soon.","choices":["see","seeing","to see"],"answer":1,"explain":"to가 전치사이므로 뒤에 동명사 seeing."}]},{"id":"sn-adjective-vs-adverb","title":"형용사 vs 부사","key":"명사 꾸미거나 보어 자리면 형용사, 나머지 꾸밈은 부사.","hook":"look·feel·seem 같은 ‘감각 동사’ 뒤엔 형용사가 와요. ‘기분 좋게(부사)’가 아니라 ‘기분 좋아(형용사)’!","summary":"명사를 수식하거나 보어 자리면 형용사, 동사·형용사·부사·문장을 수식하면 부사를 쓴다. 특히 2형식 보어 자리에는 형용사가 와야 한다.","rules":["감각·상태 동사(be, become, seem, look, feel, taste, sound) 뒤 보어는 형용사.","동사·형용사·다른 부사·문장 전체를 수식하면 부사.","함정: hardly(거의 ~않다)·lately(최근)는 hard·late와 뜻이 다르다.","5형식 목적격보어 자리에도 형용사를 쓴다(make it easy).","-ly가 붙어도 friendly, lovely, costly 등은 형용사임에 주의."],"examples":[{"en":"The soup tastes delicious.","ko":"그 수프는 맛있다. (taste 보어 → 형용사 delicious)"},{"en":"She solved the problem easily.","ko":"그녀는 그 문제를 쉽게 풀었다. (동사 수식 → 부사 easily)"},{"en":"He hardly ever eats breakfast.","ko":"그는 거의 아침을 먹지 않는다. (hardly = 거의 ~않다, 부사)"}],"quiz":[{"q":"The flowers in the garden smell ___.","choices":["sweetly","sweet","sweetness"],"answer":1,"explain":"감각동사 smell의 보어 자리이므로 형용사 sweet."},{"q":"She speaks English ___ enough to teach it.","choices":["good","well","goodly"],"answer":1,"explain":"동사 speaks를 수식하므로 부사 well."}]},{"id":"sn-pronoun-agreement","title":"대명사 수·격 일치 (it/them vs that/those)","key":"앞 명사 단수면 that, 복수면 those로 받아요.","hook":"비교할 때 같은 명사 또 쓰기 귀찮죠? 단수는 that of, 복수는 those of로 살짝 바꿔치기! 진짜 가리키는 명사의 수를 꼭 확인해요.","summary":"대명사는 가리키는 명사의 수·성·격에 일치시킨다. 앞 명사의 반복을 피할 때 단수는 that, 복수는 those를 쓰고, 동일 대상은 it/them을 쓴다.","rules":["비교에서 앞 명사 반복 회피: 단수 → that of, 복수 → those of.","동일한 대상을 다시 가리키면 it/them(앞에 나온 바로 그것).","재귀대명사: 주어와 목적어가 같으면 -self/-selves를 쓴다.","one(불특정 같은 종류) vs it(특정 바로 그것) 구별.","함정: 수식어구에 현혹되지 말고 진짜 선행 명사의 수를 확인하라."],"examples":[{"en":"The climate of Korea is milder than that of Russia.","ko":"한국의 기후는 러시아의 그것보다 온화하다. (climate 단수 → that)"},{"en":"The ears of a rabbit are longer than those of a cat.","ko":"토끼의 귀는 고양이의 그것보다 길다. (ears 복수 → those)"},{"en":"He hurt himself while skiing.","ko":"그는 스키를 타다 자신을 다쳤다. (주어=목적어 → 재귀대명사)"}],"quiz":[{"q":"The population of Tokyo is larger than ___ of Seoul.","choices":["it","that","those"],"answer":1,"explain":"population(단수)의 반복을 피하므로 that of Seoul."},{"q":"I lost my pen, so I have to buy a new ___.","choices":["it","one","that"],"answer":1,"explain":"특정한 그것이 아니라 같은 종류의 불특정 하나이므로 one."}]},{"id":"sn-parallel-structure","title":"병렬구조","key":"and·or 앞뒤는 같은 모양으로 깔맞춤!","hook":"접속사는 데칼코마니예요. 왼쪽이 to부정사면 오른쪽도 to부정사! 긴 문장은 마지막 항목이 삐뚤어졌나 꼭 살펴봐요.","summary":"등위접속사(and, but, or)나 상관접속사(both A and B, not only A but also B)로 연결된 요소는 문법적으로 같은 형태·품사여야 한다.","rules":["and/but/or 앞뒤는 같은 형태: 명사-명사, to부정사-to부정사, -ing-(-ing), 절-절.","상관접속사 both A and B, either A or B, not only A but (also) B에서 A와 B의 형태를 일치.","동사 나열 시 시제·태도 일치시킨다.","비교 구문(than, as ~ as)의 앞뒤 요소도 형태를 맞춘다.","함정: 긴 문장에서 마지막 항목의 형태가 어긋나는지 점검하라."],"examples":[{"en":"She likes reading, painting, and hiking.","ko":"그녀는 독서, 그림 그리기, 등산을 좋아한다. (-ing 병렬)"},{"en":"He wants not only to earn money but also to help others.","ko":"그는 돈을 벌 뿐 아니라 남을 돕고 싶어 한다. (to부정사 병렬)"},{"en":"The job is challenging but rewarding.","ko":"그 일은 힘들지만 보람 있다. (형용사 병렬)"}],"quiz":[{"q":"We spent the afternoon swimming, fishing, and ___.","choices":["to relax","relaxing","relaxed"],"answer":1,"explain":"앞의 swimming, fishing과 형태를 맞춰 -ing인 relaxing."},{"q":"She is both intelligent and ___.","choices":["works hard","hardworking","to work hard"],"answer":1,"explain":"both A and B에서 형용사 intelligent와 병렬이므로 형용사 hardworking."}]},{"id":"sn-inversion","title":"도치 (부정어·only·보어 도치)","key":"부정어·only가 맨 앞에 가면 「조동사+주어」로 뒤집어요.","hook":"Never, Only가 문장 맨 앞에 ‘쿵’ 떨어지면 주어와 동사가 깜짝 놀라 자리를 바꿔요! 일반동사는 do의 손을 빌려요.","summary":"부정어구나 only가 문두로 나가면 주어와 (조)동사가 도치된다. 보어·장소부사구가 문두로 갈 때도 도치가 일어난다. 도치 후 어순과 동사형을 확인한다.","rules":["부정어(never, hardly, seldom, little, not until)가 문두 → 「조동사 + 주어 + 동사」.","Only + 부사(구/절)이 문두 → 도치.","일반동사 문장의 도치는 do/does/did를 빌려 쓴다.","보어 도치: 형용사/분사 보어가 문두로 가면 「보어 + 동사 + 주어」.","함정: 도치된 동사의 수는 뒤의 진주어에 일치시킨다."],"examples":[{"en":"Never have I seen such a beautiful sunset.","ko":"나는 그렇게 아름다운 일몰을 본 적이 없다. (부정어 도치 → have I seen)"},{"en":"Only then did he realize his mistake.","ko":"그제서야 그는 자신의 실수를 깨달았다. (only 도치 → did he realize)"},{"en":"So happy was she that she cried.","ko":"그녀는 너무 행복해서 울었다. (보어 도치 → was she)"}],"quiz":[{"q":"Not until midnight ___ he finish his report.","choices":["did","does","do"],"answer":0,"explain":"부정어 Not until 도치이고 과거(finish 동사원형 동반)이므로 did."},{"q":"Hardly ___ the door when the phone rang.","choices":["I had opened","had I opened","I opened"],"answer":1,"explain":"부정어 Hardly 문두 도치로 「had + 주어 + p.p.」 어순인 had I opened."}]},{"id":"sn-subjunctive","title":"가정법 동사형","key":"if절과 주절의 동사 짝을 맞춰요(과거↔would 동사원형).","hook":"가정법은 짝꿍 댄스! if 과거동사면 주절은 would+동사원형, if had p.p.면 주절은 would have p.p. 한 쌍으로 움직여요.","summary":"현재 사실의 반대는 가정법 과거(if + 과거동사, would/could + 동사원형), 과거 사실의 반대는 가정법 과거완료(if + had p.p., would have p.p.)로 쓴다. if절과 주절의 동사형 짝을 확인한다.","rules":["가정법 과거: If + 주어 + 과거동사(be동사는 were), 주절 would/could/might + 동사원형.","가정법 과거완료: If + 주어 + had p.p., 주절 would/could have p.p.","혼합가정법: If + had p.p. (과거 조건), 주절 would + 동사원형 (현재 결과).","I wish + 가정법, as if/as though + 가정법으로 사실 반대 소망·비유.","if 생략 시 도치: Were I you, Had I known."],"examples":[{"en":"If I were rich, I would travel the world.","ko":"내가 부자라면 세계를 여행할 텐데. (현재 반대 → 가정법 과거)"},{"en":"If she had studied harder, she would have passed.","ko":"그녀가 더 열심히 공부했더라면 합격했을 텐데. (과거 반대 → 과거완료)"},{"en":"I wish I had taken your advice.","ko":"네 조언을 들었더라면 좋았을 텐데. (과거 후회 → wish + had p.p.)"}],"quiz":[{"q":"If I ___ you, I would apologize right now.","choices":["am","were","had been"],"answer":1,"explain":"현재 사실 반대 가정법 과거이므로 be동사는 were."},{"q":"If he had left earlier, he ___ the train.","choices":["would catch","would have caught","catches"],"answer":1,"explain":"과거 사실 반대 가정법 과거완료 주절은 would have p.p."}]},{"id":"sn-comparatives","title":"비교구문 어법","key":"as~as / -er~than 짝을 맞추고, more와 -er 겹치기 금지.","hook":"as는 as를, 비교급은 than을 꼭 데려와요. ‘more taller’처럼 더(more)랑 -er를 둘 다 붙이면 욕심쟁이 반칙!","summary":"원급(as ~ as), 비교급(-er/more ~ than), 최상급(the -est/most)의 형태와 짝이 되는 표현을 확인한다. 비교 대상의 형태와 강조 부사도 점검한다.","rules":["원급 비교: as + 원급 + as, 부정은 not as/so + 원급 + as.","비교급은 than과 짝; 비교급 강조는 much/far/even/still/a lot(very 불가).","라틴계 비교(superior, inferior, prior)는 than이 아니라 to를 쓴다.","비교 대상은 형태를 일치시킨다(병렬).","함정: more와 -er를 겹쳐 쓰지 않는다(more taller 불가)."],"examples":[{"en":"This box is much heavier than that one.","ko":"이 상자가 저것보다 훨씬 더 무겁다. (비교급 강조 much + than)"},{"en":"She is not as tall as her sister.","ko":"그녀는 언니만큼 키가 크지 않다. (원급 부정 not as ~ as)"},{"en":"This model is superior to the old one.","ko":"이 모델은 구형보다 우수하다. (superior + to)"}],"quiz":[{"q":"Today is ___ colder than yesterday.","choices":["very","much","more"],"answer":1,"explain":"비교급 colder를 강조하는 부사로 very는 불가, much가 옳다."},{"q":"His new car is superior ___ his old one.","choices":["than","to","as"],"answer":1,"explain":"superior는 than이 아니라 to와 함께 쓴다."}]},{"id":"sn-the-comparative","title":"「the+비교급」 구문","key":"「The 비교급~, the 비교급…」 양쪽 다 비교급으로!","hook":"하면 할수록 더! The more, the better처럼 두 칸 모두 the+비교급 세트로 채워야 해요. 한쪽만 비교급이면 짝이 안 맞아요.","summary":"‘~하면 할수록 더 …하다’는 「The + 비교급 ~, the + 비교급 …」으로 표현한다. 각 절의 비교급 위치와 어순, 동사 유무를 확인한다.","rules":["기본형: The + 비교급 + 주어 + 동사, the + 비교급 + 주어 + 동사.","비교급이 형용사/부사면 그 자리에 두고, the more가 명사를 수식하면 명사와 함께 앞으로 보낸다.","구어에서 동사(be)가 생략되기도 한다: The sooner, the better.","more와 -er를 혼동하지 말 것(긴 단어는 the more + 원급).","함정: 두 번째 the도 반드시 비교급과 함께 써야 한다."],"examples":[{"en":"The harder you work, the more you will earn.","ko":"더 열심히 일할수록 더 많이 벌게 될 것이다. (the 비교급 ~, the 비교급)"},{"en":"The more books you read, the wiser you become.","ko":"책을 더 많이 읽을수록 더 현명해진다. (the more + 명사 books)"},{"en":"The sooner, the better.","ko":"빠를수록 좋다. (동사 생략 관용표현)"}],"quiz":[{"q":"The more you practice, ___ you will get.","choices":["the better","better","the best"],"answer":0,"explain":"「the 비교급 ~, the 비교급」 구문이므로 the better."},{"q":"___ we have, the happier we feel.","choices":["The more friends","More friends","The most friends"],"answer":0,"explain":"the more가 명사 friends를 수식하며 함께 앞으로 나간 형태."}]},{"id":"sn-causative-perception-verbs","title":"사역·지각동사의 목적격보어","key":"make·see 뒤 목적어 보어는 동사원형, 당하면 p.p.","hook":"사역·지각동사 뒤엔 to 없는 ‘맨몸 동사원형’! 단, 목적어가 ‘당하는’ 입장이면 옷을 갈아입혀 p.p.로 써요.","summary":"사역동사(make, have, let)와 지각동사(see, hear, feel, watch)는 목적격보어로 동사원형을 취한다. 목적어와 보어의 관계가 수동이면 과거분사를 쓴다.","rules":["사역동사 make/have/let + 목적어 + 동사원형(능동).","지각동사 see/hear/watch/feel + 목적어 + 동사원형(완료) 또는 -ing(진행).","목적어가 동작을 ‘당하는’ 수동 관계면 목적격보어로 과거분사(p.p.).","get은 사역의 의미지만 목적격보어로 to부정사를 취한다(get + O + to do).","help는 목적격보어로 동사원형 또는 to부정사 둘 다 가능."],"examples":[{"en":"The teacher made the students clean the room.","ko":"선생님은 학생들에게 방을 청소하게 했다. (make + 동사원형)"},{"en":"I had my car repaired yesterday.","ko":"나는 어제 차를 수리받았다. (차가 수리됨 → 과거분사)"},{"en":"I saw him crossing the street.","ko":"나는 그가 길을 건너고 있는 것을 보았다. (지각동사 + -ing 진행)"}],"quiz":[{"q":"My mother let me ___ the movie last night.","choices":["to watch","watch","watched"],"answer":1,"explain":"사역동사 let의 목적격보어는 동사원형이므로 watch."},{"q":"She had her hair ___ at the salon.","choices":["cut","to cut","cutting"],"answer":0,"explain":"머리가 잘리는 수동 관계이므로 과거분사 cut."}]},{"id":"sn-preposition-plus-relative","title":"「전치사 + 관계대명사」","key":"전치사 뒤엔 which/whom, that은 절대 금지.","hook":"전치사 바로 뒤는 that 출입금지 구역이에요! which/whom만 들어갈 수 있고, 그 뒤엔 빈칸 없는 완전한 문장이 와요.","summary":"관계절 안에서 전치사의 목적어가 빠지면 「전치사 + 관계대명사(which/whom)」 형태가 되며, 뒤에는 완전한 절이 온다. 전치사 뒤에는 that을 쓸 수 없다.","rules":["전치사 + which(사물) / whom(사람) 뒤에는 완전한 절이 온다.","전치사 바로 뒤에 that이나 who는 쓸 수 없다.","전치사를 절 끝으로 보내면 that/생략도 가능: the house which I live in.","전치사 선택은 관계절 동사·표현이 요구하는 것과 일치시킨다.","「전치사 + 관계대명사」는 관계부사로 바꿀 수 있다(in which = where)."],"examples":[{"en":"This is the tool with which he fixed the engine.","ko":"이것이 그가 엔진을 고친 도구이다. (with + which + 완전한 절)"},{"en":"She is the colleague to whom I sent the report.","ko":"그녀는 내가 보고서를 보낸 동료이다. (to + whom)"},{"en":"The room in which we met was small.","ko":"우리가 만난 방은 작았다. (in which = where)"}],"quiz":[{"q":"The company ___ she works is very famous.","choices":["for that","for which","which for"],"answer":1,"explain":"전치사 뒤에는 that 불가이고 어순은 for which."},{"q":"He is the man ___ I was talking.","choices":["to that","to whom","whom to"],"answer":1,"explain":"사람 선행사에 전치사 to가 앞에 올 때 to whom이 옳다."}]},{"id":"sn-verb-vs-verbal","title":"동사 vs 준동사 구별","key":"본동사는 한 절에 하나, 접속사 없이 동사 두 개 금지.","hook":"한 문장에 ‘대장 동사’는 딱 한 명! 대장이 이미 있는데 또 동사가 나오면, 접속사 없이는 to·-ing·p.p.로 변신해야 해요.","summary":"한 절에는 본동사가 하나 있어야 한다. 이미 본동사가 있으면 추가 동사는 준동사(to부정사·동명사·분사) 형태가 되어야 하고, 접속사 없이 동사 두 개가 나란히 올 수 없다.","rules":["절마다 본동사는 하나; 접속사/관계사 없이 동사를 두 개 쓸 수 없다.","이미 본동사가 있으면 나머지 동사는 to부정사·-ing·p.p.(준동사)로.","주어가 길고 본동사가 안 보이면 빠진 본동사 자리를 찾아라.","분사구문은 접속사+주어+동사를 -ing/p.p.로 줄인 것.","함정: -ing/p.p.가 본동사인지(be + -ing/p.p.) 준동사인지 구별하라."],"examples":[{"en":"The man standing by the door is my uncle.","ko":"문가에 서 있는 남자가 내 삼촌이다. (본동사 is, standing은 분사)"},{"en":"Knowing the answer, she raised her hand.","ko":"답을 알았기에 그녀는 손을 들었다. (분사구문, 본동사는 raised)"},{"en":"His goal is to become a doctor.","ko":"그의 목표는 의사가 되는 것이다. (본동사 is, to become은 준동사 보어)"}],"quiz":[{"q":"The students ___ in the library are preparing for exams.","choices":["study","studying","studied hard they"],"answer":1,"explain":"본동사 are preparing이 있으므로 앞의 동사는 준동사(분사) studying."},{"q":"The book written by the author ___ a bestseller.","choices":["becoming","became","to become"],"answer":1,"explain":"written은 분사 수식어이고 절에 본동사가 필요하므로 became."}]},{"id":"sn-partial-double-negation","title":"부분부정·이중부정","key":"not+all/every/always는 ‘다 ~인 건 아니다’ 부분부정.","hook":"not이 all·always를 만나면 ‘전부는 아니야’라는 살짝 부정! 부정어 두 개가 만나면 오히려 강한 긍정이 돼요.","summary":"all/every/both/always 등 전체 표현이 부정어와 결합하면 ‘모두 ~인 것은 아니다’의 부분부정이 된다. 이중부정은 부정어가 둘이라 결국 긍정의 의미가 된다.","rules":["부분부정: not + all/every/both/always/necessarily = ‘모두/항상 ~인 것은 아니다’.","전체부정: no/none/neither/never = ‘아무도/결코 ~아니다’.","이중부정: 부정어 두 개가 만나면 강한 긍정의 의미.","표준 영어에서 한 절에 부정어를 두 번 써서 부정을 강조하지 않는다(비표준).","함정: not ~ until, cannot ~ too 같은 관용 표현의 의미를 정확히 해석하라."],"examples":[{"en":"Not all that glitters is gold.","ko":"반짝이는 모든 것이 금은 아니다. (not + all → 부분부정)"},{"en":"There is no rule that has no exception.","ko":"예외 없는 규칙은 없다. (no ~ no → 이중부정, 모든 규칙엔 예외가 있다)"},{"en":"You cannot be too careful when driving.","ko":"운전할 때는 아무리 조심해도 지나치지 않다. (cannot ~ too 관용)"}],"quiz":[{"q":"Choose the sentence meaning ‘부유하다고 해서 모두 행복한 것은 아니다’: ___","choices":["Not everyone who is rich is happy.","No one who is rich is happy.","Everyone who is rich is not unhappy."],"answer":0,"explain":"not + everyone은 부분부정으로 ‘모두가 행복한 것은 아니다’를 뜻한다."},{"q":"‘예외 없는 규칙은 없다’: There is ___ rule but has its exceptions.","choices":["any","no","some"],"answer":1,"explain":"no ~ but(=that ~ not) 이중부정 구문으로 no가 옳다."}]},{"id":"sn-finding-main-verb","title":"수식어구 속 본동사 찾기","key":"주어 뒤 수식어 괄호로 묶으면 진짜 본동사가 보여요.","hook":"주어 뒤에 줄줄 붙은 관계절·전치사구는 ‘장식 리본’이에요. 리본을 괄호로 싹 묶으면 숨어 있던 진짜 대장 동사가 짠!","summary":"주어와 본동사 사이에 끼어든 관계절·분사구·전치사구를 괄호로 묶어내면 진짜 본동사 자리가 보인다. 수식어 안의 동사를 본동사로 착각하지 않도록 한다.","rules":["주어 뒤 관계절·분사구·전치사구는 수식어이므로 본동사가 아니다.","주어를 찾은 뒤 그 주어에 호응하는 본동사가 하나 있는지 확인하라.","수식어 속 동사는 관계절 동사이거나 준동사일 뿐 절의 본동사가 아니다.","본동사가 빠진 듯 보이면 -ing/p.p.를 본동사(be + -ing/p.p.)로 만들거나 동사를 넣어야 한다.","함정: 긴 수식어 끝의 동사가 진짜 본동사인지, 수식어의 일부인지 구별하라."],"examples":[{"en":"The scientist who discovered the vaccine received an award.","ko":"그 백신을 발견한 과학자가 상을 받았다. (수식 who discovered 제거 → 본동사 received)"},{"en":"The tall trees lining the road provide shade.","ko":"길가에 늘어선 키 큰 나무들이 그늘을 제공한다. (lining은 분사, 본동사 provide)"},{"en":"The results of the recent survey were surprising.","ko":"최근 설문 결과는 놀라웠다. (of the recent survey 제거 → 본동사 were)"}],"quiz":[{"q":"The man, along with his two sons, ___ going to the park.","choices":["are","is","be"],"answer":1,"explain":"주어는 The man(단수)이고 along with ~는 수식어이므로 본동사는 is."},{"q":"The boxes that were delivered this morning ___ on the desk.","choices":["sitting","are sitting","to sit"],"answer":1,"explain":"that ~ morning은 수식 관계절이고 절에는 본동사가 필요하므로 are sitting."}]}],"co":[{"id":"co-sentence-types-clauses","title":"문장의 종류와 절 심화 (Sentence Types & Clauses)","key":"단문·중문·복문을 자유롭게 섞어야 글이 살아납니다.","hook":"단조로운 단문만 쓰면 글이 ‘딱딱’, 복문만 쓰면 ‘헉헉’! 리듬을 섞어야 독자가 숨 쉬어요.","summary":"대학 글쓰기에서는 단문(simple), 중문(compound), 복문(complex), 혼합문(compound-complex)을 균형 있게 사용해야 합니다. 절(clause)의 역할을 파악하는 것이 핵심입니다.","rules":["단문: 주어+동사 한 쌍 (The data shows a clear trend.)","중문: 등위접속사(and, but, or, so)로 두 독립절 연결","복문: 종속접속사(although, because, when)로 주절+종속절","혼합문: 두 개 이상의 독립절 + 하나 이상의 종속절","단조로움 방지를 위해 문장 길이와 구조를 의도적으로 다양화"],"examples":[{"en":"Although the experiment failed, the researchers gained valuable insight, and they redesigned the protocol.","ko":"실험은 실패했지만 연구자들은 귀중한 통찰을 얻었고, 절차를 다시 설계했다."},{"en":"The theory is elegant; however, it lacks empirical support.","ko":"그 이론은 우아하지만 실증적 근거가 부족하다."},{"en":"Globalization has transformed economies that once relied solely on local trade.","ko":"세계화는 한때 지역 무역에만 의존했던 경제를 변화시켰다."}],"quiz":[{"q":"다음 중 복문(complex sentence)은?","choices":["She studied hard, and she passed.","Because she studied hard, she passed.","She studied hard."],"answer":1,"explain":"종속접속사 because가 이끄는 종속절+주절 구조이므로 복문입니다."},{"q":"중문(compound)을 만드는 등위접속사는?","choices":["although","but","because"],"answer":1,"explain":"but은 등위접속사(FANBOYS)로 두 독립절을 동등하게 연결합니다."}]},{"id":"co-noun-phrase-modifiers","title":"명사구 수식어 (Noun Phrase Modifiers)","key":"명사를 꾸미는 위치는 앞과 뒤, 정보 무게에 따라 달라집니다.","hook":"짧은 수식은 앞에서 ‘똑’, 긴 수식은 뒤에서 ‘주렁주렁’ 매달아 보세요.","summary":"명사 앞에는 형용사·분사·명사가, 명사 뒤에는 전치사구·관계절·to부정사·분사구가 옵니다. 학술 영어는 후위수식이 발달했습니다.","rules":["전위수식(pre-modifier): a rapidly growing economy","후위수식(post-modifier): a study published in Nature","형용사구는 짧으면 앞, 길면 뒤 (a child afraid of dogs)","분사 후위수식으로 관계절 축약 가능","수식어가 길어질수록 후위수식을 선호"],"examples":[{"en":"The recently published article on climate policy received wide attention.","ko":"최근 발표된 기후 정책에 관한 그 논문은 큰 주목을 받았다."},{"en":"Students aiming to study abroad must prepare standardized tests.","ko":"유학을 목표로 하는 학생들은 표준화 시험을 준비해야 한다."},{"en":"A theory difficult to verify often remains controversial.","ko":"검증하기 어려운 이론은 종종 논쟁적으로 남는다."}],"quiz":[{"q":"‘책상 위의 책’을 영어로 자연스럽게?","choices":["the on-the-desk book","the book on the desk","the desk on book"],"answer":1,"explain":"전치사구는 명사 뒤에서 후위수식합니다."},{"q":"다음 중 후위수식 분사구문은?","choices":["a sleeping baby","a baby sleeping in the crib","a baby’s sleep"],"answer":1,"explain":"sleeping in the crib가 baby를 뒤에서 수식합니다."}]},{"id":"co-determiners-quantifiers","title":"한정사와 수량 표현 (Determiners & Quantifiers)","key":"셀 수 있는지 없는지로 much/many가 갈립니다.","hook":"쌀(rice)은 much, 사과(apples)는 many — ‘세어지는가?’만 물어보세요!","summary":"학술 영어에서는 정확한 수량 한정사 사용이 글의 정확성을 좌우합니다. many/several은 가산, much는 불가산에 사용합니다.","rules":["many + 가산 복수 (many studies), much + 불가산 (much evidence)","several = 몇몇 (3~7개 정도), a few = 약간 있음, few = 거의 없음","most of the + 특정 명사, most + 일반 명사 (most students vs most of the students)","a large number of + 가산, a great deal of + 불가산","학술적 격식: numerous, a substantial amount of 선호"],"examples":[{"en":"Several recent studies have challenged this assumption.","ko":"최근 몇몇 연구가 이 가정에 의문을 제기해 왔다."},{"en":"Much of the evidence remains inconclusive.","ko":"증거의 상당 부분이 여전히 결정적이지 않다."},{"en":"Most of the participants reported positive outcomes.","ko":"대부분의 참가자들이 긍정적 결과를 보고했다."}],"quiz":[{"q":"빈칸: ‘___ information is available online.’","choices":["Many","Much","Several"],"answer":1,"explain":"information은 불가산명사이므로 much를 씁니다."},{"q":"‘few’와 ‘a few’의 차이는?","choices":["같은 의미","few=거의 없음, a few=약간 있음","few=많음, a few=적음"],"answer":1,"explain":"few는 부정적, a few는 긍정적 뉘앙스입니다."}]},{"id":"co-articles-deep-dive","title":"관사 심화 (Articles in Essays)","key":"처음 언급은 a/an, 다시 언급은 the가 기본 원칙입니다.","hook":"관사는 글의 ‘안내판’! 독자가 알면 the, 모르면 a, 일반론이면 무관사예요.","summary":"학술 에세이에서 관사는 정보의 ‘구체성’과 ‘일반성’을 표시합니다. 부정관사·정관사·무관사를 정확히 구분해야 합니다.","rules":["a/an: 처음 언급, 가산 단수, 비특정 (a researcher)","the: 재언급, 유일/특정, 한정된 명사 (the researcher we cited)","zero article: 일반화(general truths), 추상명사, 복수 일반 (Education matters.)","고유 분야 명사: study of economics, the study of human behavior","학술 표현: in the long run, on the whole, by and large"],"examples":[{"en":"A growing body of research suggests that diet affects cognition.","ko":"증가하는 연구들이 식단이 인지에 영향을 미친다고 시사한다."},{"en":"The findings of the study contradict previous assumptions.","ko":"그 연구의 결과는 이전 가정들과 모순된다."},{"en":"Education plays a crucial role in social mobility.","ko":"교육은 사회 이동에 중요한 역할을 한다."}],"quiz":[{"q":"빈칸: ‘___ poverty remains a global issue.’","choices":["A","The","(무관사)"],"answer":2,"explain":"추상적·일반적 개념은 무관사로 사용합니다."},{"q":"두 번째 언급된 명사의 관사는?","choices":["a/an","the","무관사"],"answer":1,"explain":"이미 언급되어 한정되었으므로 the를 씁니다."}]},{"id":"co-aspect-perfect-progressive","title":"완료·진행 시제 (Aspect)","key":"완료는 ‘결과·연결’, 진행은 ‘지속·일시성’을 강조합니다.","hook":"have done은 ‘이미 끝난 영향’, be doing은 ‘지금 진행 중인 장면’ — 카메라 앵글이 다르죠!","summary":"현재완료는 과거와 현재의 연결을, 진행형은 행위의 지속과 일시성을 나타냅니다. 학술적 글쓰기에서 정확한 사용이 중요합니다.","rules":["현재완료(have+p.p): 과거에서 현재까지의 결과/경험/계속","현재완료진행: 지속 강조 (Researchers have been investigating…)","과거완료: 과거 시점보다 더 이전의 일","진행형은 일시적·역동적 상황 (The economy is recovering.)","상태동사(know, believe)는 진행형을 잘 쓰지 않음"],"examples":[{"en":"Scholars have long debated the origins of language.","ko":"학자들은 오랫동안 언어의 기원을 논쟁해 왔다."},{"en":"The field has been evolving rapidly over the past decade.","ko":"그 분야는 지난 10년간 급속히 발전해 오고 있다."},{"en":"By 2020, AI had transformed multiple industries.","ko":"2020년까지 AI는 여러 산업을 변화시켰었다."}],"quiz":[{"q":"빈칸: ‘Since 2000, the technology ___ dramatically.’","choices":["changed","has changed","is changing"],"answer":1,"explain":"since 2000은 현재까지의 연결 → 현재완료."},{"q":"현재완료진행이 강조하는 것은?","choices":["단발성 사건","지속과 계속","미래 예측"],"answer":1,"explain":"have been -ing는 지속성을 부각합니다."}]},{"id":"co-modal-probability","title":"추측의 조동사 (Modal Verbs of Probability)","key":"확신의 강도에 따라 must > may > might > could 순으로 사용합니다.","hook":"must는 ‘틀림없이!’, might는 ‘아마도?’, could는 ‘혹시?’ — 자신감 게이지가 다릅니다.","summary":"학술 글쓰기에서 단정 대신 적절한 조동사로 주장의 강도를 조절(hedging)하는 것이 중요합니다.","rules":["must = 강한 확신 (This must be the main cause.)","may/might/could = 가능성 (This may suggest a trend.)","must have p.p = 과거의 강한 추측 (must have influenced)","could have p.p = 과거 가능성 또는 실현되지 않은 일","학술적 hedging: appears to, seems to, tends to"],"examples":[{"en":"These results may indicate a broader social pattern.","ko":"이 결과들은 더 광범위한 사회적 패턴을 시사할 수도 있다."},{"en":"The decline must have been triggered by multiple factors.","ko":"그 쇠퇴는 여러 요인에 의해 촉발되었음에 틀림없다."},{"en":"Such an approach could prove effective in future studies.","ko":"그러한 접근법은 향후 연구에서 효과적임이 입증될 수도 있다."}],"quiz":[{"q":"가장 강한 확신을 나타내는 조동사는?","choices":["might","must","could"],"answer":1,"explain":"must는 거의 확실한 추측을 표현합니다."},{"q":"‘might have caused’의 의미는?","choices":["반드시 야기했다","야기했을 수도 있다","야기하고 있다"],"answer":1,"explain":"might have p.p는 과거에 대한 약한 추측입니다."}]},{"id":"co-subjunctive-mandative","title":"가정법·명령가정법 (Subjunctive & Mandative)","key":"요구·제안·필수 표현 뒤 that절 동사는 원형을 씁니다.","hook":"‘essential that he be’ — 3인칭인데 be? 그게 바로 ‘명령가정법’의 마법입니다!","summary":"recommend, suggest, insist, demand, essential, necessary 같은 표현 뒤 that절에서는 동사원형(should 생략형)을 사용합니다.","rules":["동사: recommend, suggest, insist, demand, require, propose + that + S + 동사원형","형용사: essential, necessary, important, crucial + that + S + 동사원형","부정: that + S + not + 동사원형 (that he not attend)","be동사도 원형 그대로 (that she be present)","If I were you처럼 가정법 과거는 were를 사용"],"examples":[{"en":"The committee insists that every applicant submit a writing sample.","ko":"위원회는 모든 지원자가 작문 샘플을 제출할 것을 요구한다."},{"en":"It is essential that the data be reviewed by an independent expert.","ko":"데이터가 독립적인 전문가에 의해 검토되는 것이 필수적이다."},{"en":"We recommend that the policy not be implemented prematurely.","ko":"우리는 그 정책이 성급하게 시행되지 않을 것을 권고한다."}],"quiz":[{"q":"빈칸: ‘It is necessary that he ___ on time.’","choices":["is","be","was"],"answer":1,"explain":"명령가정법에서는 동사원형 be를 사용합니다."},{"q":"다음 중 명령가정법 동사가 아닌 것은?","choices":["recommend","insist","enjoy"],"answer":2,"explain":"enjoy는 명령·제안의 의미가 없습니다."}]},{"id":"co-passive-voice-style","title":"수동태의 활용 (Passive Voice in Essays)","key":"행위자가 불분명·불필요하거나 객관성을 강조할 때 수동태를 씁니다.","hook":"‘누가’보다 ‘무엇이’가 중요할 때, 수동태가 무대의 주인공을 바꿔줍니다!","summary":"학술 글쓰기에서 수동태는 객관성, 행위자 은닉, 정보 흐름 조정 등의 기능을 합니다. 그러나 과도한 사용은 피해야 합니다.","rules":["행위자가 명확하지 않거나 중요하지 않을 때 (The study was conducted in 2020.)","결과·대상에 초점을 둘 때","구정보→신정보 흐름을 유지할 때","by + 행위자는 강조가 필요할 때만","과학·기술 분야에서 흔하지만 인문학에서는 능동을 선호하기도"],"examples":[{"en":"The survey was administered to 500 undergraduates.","ko":"그 설문조사는 500명의 학부생에게 실시되었다."},{"en":"These findings have been widely cited in subsequent research.","ko":"이 결과들은 후속 연구에서 널리 인용되어 왔다."},{"en":"The hypothesis was confirmed by independent experiments.","ko":"그 가설은 독립적인 실험들에 의해 확인되었다."}],"quiz":[{"q":"수동태를 선호하는 경우는?","choices":["행위자가 명확하고 중요할 때","행위자가 불분명하거나 객관성이 필요할 때","구어체 대화에서"],"answer":1,"explain":"학술적 객관성·행위자 은닉 시 수동태를 씁니다."},{"q":"‘The data was analyzed.’의 행위자 표시 방법은?","choices":["by + 행위자","for + 행위자","to + 행위자"],"answer":0,"explain":"수동태에서 행위자는 by로 표시합니다."}]},{"id":"co-relative-clauses","title":"관계절: 제한·비제한 (Relative Clauses)","key":"콤마가 있으면 비제한, 없으면 제한 — 정보의 필수성이 다릅니다.","hook":"콤마는 ‘덧붙이는 정보’ 표시! 빼도 문장 뜻이 안 바뀌면 콤마, 빼면 의미 깨지면 콤마 없이!","summary":"제한적 관계절은 선행사를 한정하는 필수 정보, 비제한적 관계절은 추가 설명입니다. 비제한절에서는 that을 쓸 수 없습니다.","rules":["제한적: 콤마 없음, 선행사 한정 (The book that I read…)","비제한적: 콤마 있음, 부가 설명 (My father, who is a doctor,…)","비제한절에는 that 사용 불가, which/who 사용","전치사+관계대명사: in which, for whom (격식체)","관계부사 where/when/why로 전치사구 대체 가능"],"examples":[{"en":"The theory that Darwin proposed revolutionized biology.","ko":"다윈이 제안한 그 이론은 생물학을 혁명적으로 바꾸었다."},{"en":"Einstein, who developed relativity, transformed modern physics.","ko":"상대성 이론을 발전시킨 아인슈타인은 현대 물리학을 변화시켰다."},{"en":"The study, the results of which were surprising, was published last year.","ko":"결과가 놀라웠던 그 연구는 작년에 발표되었다."}],"quiz":[{"q":"비제한적 관계절에서 쓸 수 없는 것은?","choices":["which","who","that"],"answer":2,"explain":"비제한적 관계절에서는 that을 사용하지 않습니다."},{"q":"‘My brother who lives in Seoul’은 형제가 몇 명임을 암시?","choices":["한 명","여러 명 중 한 명","알 수 없음"],"answer":1,"explain":"제한적 관계절이므로 다른 형제가 있음을 암시합니다."}]},{"id":"co-reduced-clauses","title":"축약 관계·부사절 (Reduced Clauses)","key":"관계대명사+be를 생략하거나 분사로 줄여 간결하게 만듭니다.","hook":"긴 절을 ‘다이어트’시키는 기술! who is, when I was를 떼어내면 글이 날씬해져요.","summary":"관계절·부사절을 분사구문이나 to부정사로 축약하면 문장이 간결해지고 학술적 톤이 강해집니다.","rules":["관계절 축약: who is/are/was/were 생략 가능 (The student [who is] studying…)","능동은 -ing, 수동은 -ed (data collected from…)","부사절 축약: 주절과 주어 일치 시 (While walking, she…)","Having p.p로 완료 분사구문 표현","주어 불일치 시 dangling modifier 오류 주의"],"examples":[{"en":"The researchers conducting the survey reported no anomalies.","ko":"설문조사를 수행하는 연구자들은 어떤 이상도 보고하지 않았다."},{"en":"Written in plain English, the report attracted general readers.","ko":"평이한 영어로 쓰인 그 보고서는 일반 독자들의 관심을 끌었다."},{"en":"Having reviewed the literature, the author proposed a new model.","ko":"문헌을 검토한 후, 저자는 새로운 모델을 제안했다."}],"quiz":[{"q":"‘The book which was written in 2020’의 축약은?","choices":["The book writing in 2020","The book written in 2020","The book to write in 2020"],"answer":1,"explain":"수동의 의미이므로 과거분사 written을 사용합니다."},{"q":"분사구문 축약 시 주의할 점은?","choices":["주절 동사 시제","주어 일치","콤마 위치"],"answer":1,"explain":"주어가 다르면 dangling modifier 오류가 발생합니다."}]},{"id":"co-conditionals-mixed-inverted","title":"조건문: 혼합·도치 (Mixed & Inverted Conditionals)","key":"if를 생략하면 had/were/should가 문두로 도치됩니다.","hook":"‘Had I known…’ — if를 떼면 동사가 앞으로 점프! 격식체의 멋이죠.","summary":"혼합조건은 과거 조건과 현재 결과를 연결하고, 도치조건은 if 없이 격식 있는 표현을 만듭니다.","rules":["혼합조건: If + 과거완료, would + 동사원형 (현재 결과)","If I had studied harder, I would be a doctor now.","도치: Had + S + p.p (= If S had p.p)","Were + S + to (= If S were to)","Should + S + 동사원형 (= If S should)"],"examples":[{"en":"Had the policy been implemented earlier, the crisis might have been averted.","ko":"그 정책이 더 일찍 시행되었다면, 위기는 피할 수 있었을지도 모른다."},{"en":"Were the government to invest in education, long-term growth would follow.","ko":"정부가 교육에 투자한다면, 장기적 성장이 뒤따를 것이다."},{"en":"Should any errors be discovered, please notify the editor immediately.","ko":"어떤 오류라도 발견되면, 즉시 편집자에게 알려 주십시오."}],"quiz":[{"q":"‘If he had left earlier, he would be home now’는 어떤 조건문?","choices":["1형식","혼합조건","단순 가정"],"answer":1,"explain":"과거 조건+현재 결과의 혼합조건입니다."},{"q":"‘Had I known’과 같은 의미는?","choices":["If I knew","If I had known","If I would know"],"answer":1,"explain":"도치된 가정법 과거완료입니다."}]},{"id":"co-reported-speech","title":"보고/인용 (Reported Speech in Essays)","key":"에세이에서는 시제 일치와 인용 동사 선택이 핵심입니다.","hook":"argue, claim, suggest, note — 인용 동사 하나로 저자의 태도를 슬쩍 드러내요.","summary":"학술 에세이에서 출처를 인용할 때 보고문법(reported speech)을 사용합니다. 인용 동사 선택이 글의 톤을 결정합니다.","rules":["직접인용: ‘…,’ Smith said. → 간접: Smith said that…","시제 일치: 현재→과거, 과거→과거완료","인용 동사: argue, claim, suggest, note, observe, contend, maintain","현재시제 인용도 가능 (Smith argues that…) — 일반적 진실 강조","according to + 출처도 자주 사용"],"examples":[{"en":"Smith (2018) argues that economic inequality undermines democracy.","ko":"Smith(2018)는 경제적 불평등이 민주주의를 약화시킨다고 주장한다."},{"en":"The report noted that participation rates had declined significantly.","ko":"그 보고서는 참여율이 크게 감소했다고 언급했다."},{"en":"According to recent research, sleep quality affects academic performance.","ko":"최근 연구에 따르면, 수면의 질은 학업 성취에 영향을 미친다."}],"quiz":[{"q":"‘He said, ‘I am tired.’’의 간접화법은?","choices":["He said that he is tired.","He said that he was tired.","He said that he had been tired."],"answer":1,"explain":"주절이 과거이므로 종속절도 과거로 일치시킵니다."},{"q":"강한 주장을 나타내는 인용 동사는?","choices":["note","contend","mention"],"answer":1,"explain":"contend는 강하게 주장한다는 의미입니다."}]},{"id":"co-linking-adverbials","title":"연결 부사 (Linking Adverbials)","key":"however, therefore, in addition으로 문장 간 논리를 명확히 합니다.","hook":"however는 ‘반전 카드’, therefore는 ‘결론 카드’! 카드 종류를 알면 글의 흐름이 보여요.","summary":"학술 글에서 문장과 단락을 잇는 연결 부사는 논리 관계를 명시합니다. 위치(문두/문중)와 구두점 사용이 중요합니다.","rules":["대조: however, nevertheless, in contrast, on the other hand","추가: in addition, furthermore, moreover, besides","결과: therefore, thus, consequently, as a result","예시: for example, for instance, namely","문두에 올 때 보통 콤마, 두 절 연결은 세미콜론 사용"],"examples":[{"en":"The theory is widely accepted; however, recent evidence challenges it.","ko":"그 이론은 널리 받아들여지지만, 최근 증거가 그것에 의문을 제기한다."},{"en":"Funding has decreased. Therefore, several projects have been suspended.","ko":"예산이 줄었다. 따라서 여러 프로젝트가 중단되었다."},{"en":"In addition, the study highlights cultural variations.","ko":"또한, 그 연구는 문화적 변이를 강조한다."}],"quiz":[{"q":"대조를 나타내는 연결어는?","choices":["therefore","however","moreover"],"answer":1,"explain":"however는 대조·반전을 표현합니다."},{"q":"‘furthermore’의 기능은?","choices":["대조","추가","결과"],"answer":1,"explain":"furthermore는 정보를 더하는 표현입니다."}]},{"id":"co-coordination-subordination","title":"등위와 종속의 균형 (Coordination vs Subordination)","key":"동등 정보는 등위로, 주·부 관계는 종속으로 표현합니다.","hook":"and로 줄줄이 잇기만 하면 단조롭죠? 종속절로 ‘주연·조연’을 나눠 보세요.","summary":"등위(coordination)는 정보의 동등성을, 종속(subordination)은 정보의 위계를 나타냅니다. 균형 있게 사용해야 문장이 정교해집니다.","rules":["등위접속사(FANBOYS): for, and, nor, but, or, yet, so","종속접속사: because, although, while, if, when, since","정보 비중이 같으면 등위, 다르면 종속","and 남발 대신 분사구문·관계절로 위계 표현","주절에 핵심 정보, 종속절에 부가 정보"],"examples":[{"en":"Although the data are limited, the conclusions remain valuable.","ko":"데이터가 제한적이지만, 결론은 여전히 가치가 있다."},{"en":"The study was small but well-designed.","ko":"그 연구는 규모가 작았지만 잘 설계되었다."},{"en":"Because resources were scarce, researchers prioritized key experiments.","ko":"자원이 부족했기 때문에, 연구자들은 핵심 실험을 우선시했다."}],"quiz":[{"q":"다음 중 종속접속사는?","choices":["and","but","although"],"answer":2,"explain":"although는 종속절을 이끄는 종속접속사입니다."},{"q":"두 정보의 비중이 다를 때 적합한 구조는?","choices":["등위","종속","병렬"],"answer":1,"explain":"위계가 있는 정보는 종속 구조로 표현합니다."}]},{"id":"co-parallel-structure","title":"병렬 구조 (Parallel Structure)","key":"나열·비교 시 문법 형태를 동일하게 맞춰야 합니다.","hook":"‘reading, writing, and to speak’는 어색해요! 같은 옷(형태)을 입혀줘야 멋스러워요.","summary":"and, or, but으로 연결된 항목들, 비교 구문, 상관접속사에서 동일한 문법 형태를 유지하는 것이 병렬 구조입니다.","rules":["동명사는 동명사끼리, to부정사는 to부정사끼리","상관접속사: both A and B, not only A but also B, either A or B (A와 B는 같은 품사)","비교: X is more efficient than Y is (동일 구조 유지)","목록 나열에서 마지막 항목 앞 and 사용","전치사·관사 반복으로 명확성 강화"],"examples":[{"en":"The course emphasizes reading critically, writing clearly, and thinking analytically.","ko":"그 강좌는 비판적 읽기, 명료한 쓰기, 분석적 사고를 강조한다."},{"en":"Students must be not only knowledgeable but also resourceful.","ko":"학생들은 지식이 풍부할 뿐 아니라 수완도 좋아야 한다."},{"en":"She is interested in both the theory and the application of linguistics.","ko":"그녀는 언어학의 이론과 응용 모두에 관심이 있다."}],"quiz":[{"q":"병렬 구조가 올바른 것은?","choices":["I like swimming, hiking, and to run.","I like swimming, hiking, and running.","I like to swim, hiking, and run."],"answer":1,"explain":"동명사로 형태를 통일했습니다."},{"q":"‘not only A but also B’에서 A, B는?","choices":["다른 품사여도 됨","같은 품사·구조","반대 의미"],"answer":1,"explain":"상관접속사는 동일 형태를 요구합니다."}]},{"id":"co-comparison-structures","title":"비교 구문 (Comparison Structures)","key":"‘the 비교급, the 비교급’ 구문으로 비례 관계를 표현합니다.","hook":"The more you read, the better you write — 마법 같은 비례 공식이에요!","summary":"비교급·최상급·상관 비교를 정확히 사용하면 학술적 논증이 명료해집니다.","rules":["비교급+than (more efficient than)","the+최상급+of/in (the most influential of all)","the 비교급, the 비교급 (The more, the merrier.)","as+원급+as / not so~as","배수 표현: twice as long as, three times more than"],"examples":[{"en":"The more we invest in education, the greater the long-term returns.","ko":"교육에 더 많이 투자할수록, 장기적 수익은 더 커진다."},{"en":"This approach is far more efficient than the traditional method.","ko":"이 접근법은 전통적 방법보다 훨씬 더 효율적이다."},{"en":"Among all variables, age proved to be the most significant.","ko":"모든 변수들 중에서 나이가 가장 유의미한 것으로 입증되었다."}],"quiz":[{"q":"‘읽을수록 더 좋아진다’의 영어 표현은?","choices":["More you read, more you become better.","The more you read, the better you become.","You read more, you become better."],"answer":1,"explain":"the 비교급, the 비교급 구문입니다."},{"q":"비교급 강조 부사가 아닌 것은?","choices":["much","far","very"],"answer":2,"explain":"very는 원급 강조, 비교급에는 much/far를 씁니다."}]},{"id":"co-cleft-emphasis","title":"분열·강조 구문 (Cleft & Emphasis)","key":"‘It is X that…’과 ‘What…is X’로 핵심을 강조합니다.","hook":"‘바로 그것!’을 외치고 싶을 때 분열구문! 무대 조명을 한 곳에 비추는 느낌이죠.","summary":"분열구문(cleft)은 문장의 일부를 강조하여 정보의 초점을 명확히 합니다. 학술 글에서 논점 부각에 효과적입니다.","rules":["It-cleft: It is/was + 강조 요소 + that/who…","Wh-cleft (pseudo-cleft): What + 절 + is/was + 요소","강조 요소는 명사, 부사구, 시간 표현 등 가능","All-cleft: All (that) S V is…","주어·목적어·부사 어느 것이든 강조 가능"],"examples":[{"en":"It is the methodology, not the data, that determines credibility.","ko":"신뢰성을 결정하는 것은 데이터가 아니라 방법론이다."},{"en":"What the study reveals is a deep cultural shift.","ko":"그 연구가 드러내는 것은 깊은 문화적 변화이다."},{"en":"It was in 1990 that the first paper on the topic was published.","ko":"이 주제에 관한 첫 논문이 출판된 것은 1990년이었다."}],"quiz":[{"q":"‘John이 그것을 발견했다’를 John 강조로?","choices":["John discovered it.","It was John that discovered it.","What John is discovered it."],"answer":1,"explain":"It is X that 구문으로 X를 강조합니다."},{"q":"What-cleft의 구조는?","choices":["What+절+is+요소","It is+요소+that+절","Only+요소+do+V"],"answer":0,"explain":"What+절+be+강조요소가 기본 구조입니다."}]},{"id":"co-inversion","title":"도치 (Inversion)","key":"부정어·only·so 등이 문두에 오면 주어-동사가 도치됩니다.","hook":"Never have I seen…! 부정어가 앞에 나오면 조동사가 따라 점프해요.","summary":"강조·문어체에서 부정어구, only, so/such, 장소부사구 등이 문두에 오면 도치가 일어납니다.","rules":["부정어 도치: Never/Rarely/Seldom/Hardly + 조동사 + S + V","Only+부사구 도치: Only then did she realize…","Not until 도치: Not until 2020 did the trend become clear.","So+형용사/Such+명사 도치: So great was the impact that…","장소부사구 도치(완전동사): On the table sat a book."],"examples":[{"en":"Never has the field witnessed such rapid transformation.","ko":"그 분야가 그토록 급격한 변화를 목격한 적은 없었다."},{"en":"Only after extensive analysis did the pattern emerge.","ko":"광범위한 분석 후에야 그 패턴이 드러났다."},{"en":"Not only is the theory elegant, but it is also testable.","ko":"그 이론은 우아할 뿐 아니라 검증 가능하기도 하다."}],"quiz":[{"q":"‘Never I have seen…’의 올바른 형태는?","choices":["Never I have seen","Never have I seen","Never seen I have"],"answer":1,"explain":"부정어 문두 도치는 조동사+주어 순입니다."},{"q":"도치를 유발하지 않는 것은?","choices":["Rarely","Only then","Often"],"answer":2,"explain":"often은 도치를 유발하지 않습니다."}]},{"id":"co-punctuation-connectives","title":"구두점과 연결 (Punctuation & Connectives)","key":"세미콜론은 ‘두 독립절 연결’, 콜론은 ‘설명·예시 도입’입니다.","hook":"세미콜론은 ‘마침표 반·콤마 반’, 콜론은 ‘여기 봐!’ 신호등이에요.","summary":"학술 글에서 구두점은 논리를 시각화합니다. ; : — 의 정확한 용법을 익히면 글의 정밀도가 올라갑니다.","rules":["세미콜론(;): 의미가 긴밀한 두 독립절 연결","콜론(:): 앞 문장의 설명·열거·인용 도입","em dash(—): 부가 정보 강조, 콤마·괄호보다 시각적","콤마 스플라이스(comma splice) 오류 주의 (두 독립절을 콤마로만 연결 X)","괄호( )는 보충 정보, 대시는 강조 정보"],"examples":[{"en":"The experiment yielded clear results; further replication is still required.","ko":"그 실험은 분명한 결과를 냈다. 다만 추가 반복 검증이 여전히 필요하다."},{"en":"The study examined three factors: motivation, environment, and feedback.","ko":"그 연구는 세 요인을 검토했다. 동기, 환경, 피드백이다."},{"en":"Her argument — though controversial — opened new debates.","ko":"그녀의 주장은, 논쟁의 여지가 있지만, 새로운 논의를 열었다."}],"quiz":[{"q":"두 독립절을 연결하는 구두점은?","choices":["콤마(,)","세미콜론(;)","하이픈(-)"],"answer":1,"explain":"세미콜론이 의미가 가까운 두 독립절을 연결합니다."},{"q":"콜론(:)의 주요 기능은?","choices":["대조","설명·열거 도입","의문"],"answer":1,"explain":"콜론은 뒤에 오는 설명·예시를 도입합니다."}]},{"id":"co-discourse-markers","title":"담화 표지 (Discourse Markers)","key":"in fact, indeed, by contrast로 글의 어조와 전환을 표시합니다.","hook":"indeed는 ‘정말로!’ 도장, by contrast는 ‘반대로!’ 화살표 — 독자에게 신호를 보내요.","summary":"담화 표지는 단순 연결을 넘어 화자/필자의 태도와 정보 흐름을 조정합니다. 학술 글에 정교함을 더합니다.","rules":["in fact / indeed: 강조·확장 (실제로/사실은)","by contrast / on the contrary: 대조·반박","in other words / that is: 환언","more specifically / in particular: 구체화","after all / ultimately: 결론·요약"],"examples":[{"en":"Indeed, the data confirm the long-standing hypothesis.","ko":"실제로, 그 데이터는 오랜 가설을 확인해 준다."},{"en":"By contrast, the control group showed no significant change.","ko":"이와 대조적으로, 통제 집단은 유의미한 변화를 보이지 않았다."},{"en":"In other words, the policy benefits some but harms others.","ko":"다시 말해, 그 정책은 누군가에게는 이롭지만 다른 이들에게는 해롭다."}],"quiz":[{"q":"환언(다시 말해)을 나타내는 표현은?","choices":["after all","in other words","by contrast"],"answer":1,"explain":"in other words는 앞 내용을 바꿔 말할 때 씁니다."},{"q":"‘indeed’의 기능은?","choices":["대조","강조·확장","결론"],"answer":1,"explain":"indeed는 앞 진술을 강조·확장합니다."}]},{"id":"co-formal-informal-register","title":"격식·비격식 어조 (Formal vs Informal Register)","key":"에세이에서는 축약형·구어 표현·주관 감탄을 피합니다.","hook":"don’t, kinda, super는 카톡톡, do not, somewhat, extremely는 에세이톡!","summary":"학술/전문 글에서는 격식체를 사용하여 객관성과 신뢰성을 확보합니다. 어휘·구문·구두점 모두 영향을 받습니다.","rules":["축약형 금지: don’t → do not, it’s → it is","구어 표현 피하기: a lot of → numerous, kids → children","1인칭·2인칭 신중: ‘you’ 대신 ‘one/readers/students’","구동사보다 단일동사: find out → discover, look into → investigate","감정 표현·과장 자제: very/really 줄이고 정확한 형용사 사용"],"examples":[{"en":"The findings demonstrate a significant correlation between the variables.","ko":"그 결과는 변수들 간의 유의미한 상관관계를 보여 준다."},{"en":"Researchers should investigate alternative explanations.","ko":"연구자들은 대안적 설명을 조사해야 한다."},{"en":"One must consider multiple perspectives before forming a conclusion.","ko":"결론을 내리기 전에 다양한 관점을 고려해야 한다."}],"quiz":[{"q":"에세이에 적합한 표현은?","choices":["a lot of people","lots of folks","numerous individuals"],"answer":2,"explain":"numerous individuals가 가장 격식 있는 표현입니다."},{"q":"‘look into’의 격식체 대체어는?","choices":["investigate","check out","see"],"answer":0,"explain":"investigate가 학술적 단일동사입니다."}]},{"id":"co-common-error-patterns","title":"흔한 글쓰기 오류 (Common Error Patterns)","key":"주술 일치, 매달린 수식어, 무종결문(run-on)을 늘 점검하세요.","hook":"글을 다 쓰고 나서 ‘주어-동사 짝꿍 확인, 수식어 짝꿍 확인’ 두 번만 해 봐요!","summary":"대학 글쓰기에서 가장 자주 지적되는 오류는 주술 불일치, 매달린 수식어, run-on/comma splice입니다. 교정 단계에서 체크리스트로 확인하세요.","rules":["주술 일치: 삽입구에 속지 말 것 (The list of items is…)","Dangling modifier: 분사구문 주어와 주절 주어 일치 (Walking down the street, I saw…)","Run-on sentence: 두 독립절을 접속사 없이 이으면 안 됨","Comma splice: 두 독립절을 콤마 하나로만 연결 금지","대명사 지시 명확화: it/they/this가 무엇을 가리키는지 분명히"],"examples":[{"en":"The set of variables was carefully selected for analysis.","ko":"그 변수 묶음은 분석을 위해 신중히 선택되었다."},{"en":"Having reviewed the data, the researchers proposed a new model.","ko":"데이터를 검토한 후, 연구자들은 새로운 모델을 제안했다."},{"en":"The argument is compelling; however, it requires further evidence.","ko":"그 주장은 설득력 있지만, 추가 증거가 필요하다."}],"quiz":[{"q":"주술 일치가 올바른 것은?","choices":["The list of books are on the desk.","The list of books is on the desk.","The list of books were on the desk."],"answer":1,"explain":"주어는 list(단수)이므로 is를 씁니다."},{"q":"‘Walking down the street, a dog barked at me.’의 문제는?","choices":["시제 오류","매달린 수식어","주술 불일치"],"answer":1,"explain":"Walking의 주체가 dog가 되어 dangling modifier 오류입니다."}]}],"gr":[{"id":"gr-nominalization","title":"명사화 (Nominalization)","key":"동사·형용사를 명사로 바꿔 압축하면 학술 문장이 됩니다.","hook":"티타의 압축 마법! ‘분석하다’를 ‘분석’으로 바꾸면 문장이 딱 정장을 차려입어요. 동사를 명사로 접으면 학술적 무게가 확 올라가요.","summary":"명사화는 동사나 형용사를 명사구로 바꿔 정보를 압축하고 객관적·추상적 어조를 만드는 학술 글쓰기의 핵심 기법입니다. 행위자보다 개념 자체에 초점을 둡니다.","rules":["동사를 명사로: ‘analyze → analysis’, ‘decide → decision’처럼 행위를 개념으로 압축합니다.","형용사도 명사화: ‘different → difference’, ‘able → ability’로 추상화합니다.","주어를 명사구로 만들어 비인칭·객관적 어조를 형성합니다: ‘The implementation of the policy failed’.","정보 밀도가 높아지므로 한 문장에 명사화를 너무 많이 쓰면 가독성이 떨어집니다. 균형이 중요합니다.","명사화 뒤에는 보통 ‘of’ 전치사구가 따라옵니다: ‘the rejection of the hypothesis’."],"examples":[{"en":"The rejection of the null hypothesis suggests a significant effect.","ko":"귀무가설의 기각은 유의미한 효과를 시사한다."},{"en":"Their failure to replicate the results raised methodological concerns.","ko":"결과를 재현하지 못한 그들의 실패는 방법론적 우려를 불러일으켰다."},{"en":"The reduction in variance indicates greater consistency across trials.","ko":"분산의 감소는 시행 전반에 걸친 일관성의 증가를 나타낸다."}],"quiz":[{"q":"다음 중 ‘We analyzed the data carefully’를 명사화한 학술적 표현은?","choices":["The analysis of the data was careful.","We were analyzing data.","Data is analyzed by us."],"answer":0,"explain":"동사 analyze를 명사 analysis로 바꿔 객관적 명사구 주어를 만든 것이 명사화입니다."},{"q":"빈칸: The ___ of the policy led to widespread debate. (‘implement’의 명사형)","choices":["implementing","implementation","implemented"],"answer":1,"explain":"동사 implement의 명사형은 implementation이며, 명사화의 전형적 형태입니다."}]},{"id":"gr-hedging","title":"완곡·신중한 표현 (Hedging)","key":"단정 대신 may·appear to·tend to로 주장을 조심스럽게 낮춥니다.","hook":"티타의 살얼음 걷기! 학자는 ‘100% 맞다’고 안 해요. ‘~인 것으로 보인다’며 살짝 발을 빼죠. 헤징은 비판을 막는 안전벨트예요.","summary":"헤징은 주장의 확실성을 의도적으로 낮춰 반증 가능성에 대비하고 학문적 겸손을 보여주는 기법입니다. 양태동사, 부사, 동사 등 다양한 장치를 씁니다.","rules":["양태동사로 확실성 낮추기: ‘may’, ‘might’, ‘could’ — ‘This may indicate a trend’.","추정 동사: ‘appear to’, ‘seem to’, ‘tend to’ — ‘Results tend to support the model’.","확률 부사: ‘possibly’, ‘arguably’, ‘relatively’, ‘somewhat’.","근사 표현: ‘approximately’, ‘to some extent’로 수치·정도를 누그러뜨립니다.","‘It is possible that ~’, ‘There is some evidence that ~’ 같은 도입절도 헤징입니다."],"examples":[{"en":"These findings may suggest a link between sleep and memory consolidation.","ko":"이 결과는 수면과 기억 공고화 사이의 연관성을 시사할 수도 있다."},{"en":"The effect appears to diminish over longer time intervals.","ko":"그 효과는 더 긴 시간 간격에 걸쳐 줄어드는 것으로 보인다."},{"en":"Participants tended to overestimate their own performance.","ko":"참가자들은 자신의 수행을 과대평가하는 경향이 있었다."}],"quiz":[{"q":"가장 학술적으로 ‘신중한(hedged)’ 문장은?","choices":["This proves the theory.","This may provide some support for the theory.","This definitely confirms the theory."],"answer":1,"explain":"may와 some support가 확실성을 낮추는 전형적 헤징 장치입니다."},{"q":"빈칸: The data ___ to support the second hypothesis. (경향을 나타내는 헤징)","choices":["prove","tend","must"],"answer":1,"explain":"tend to는 ‘~하는 경향이 있다’로 단정을 피하는 헤징 표현입니다."}]},{"id":"gr-boosting","title":"강조 (Boosting)","key":"clearly·undoubtedly로 확신이 높은 주장에 힘을 싣습니다.","hook":"티타의 볼륨 업! 헤징이 소리를 줄이는 거라면, 부스팅은 확신의 볼륨을 키우는 거예요. 근거가 탄탄할 때만 ‘분명히!’를 외쳐요.","summary":"부스팅은 화자의 확신을 강조해 주장에 권위와 설득력을 더하는 기법입니다. 충분한 근거가 있을 때 신중하게 사용해야 합니다.","rules":["확신 부사: ‘clearly’, ‘undoubtedly’, ‘evidently’, ‘indeed’ — ‘The results clearly demonstrate the effect’.","강조 동사: ‘demonstrate’, ‘establish’, ‘confirm’은 strong claim을 나타냅니다.","‘It is evident that ~’, ‘There is no doubt that ~’ 같은 도입 구문.","부스팅은 근거가 강할 때만 쓰며, 남용하면 오히려 신뢰를 떨어뜨립니다.","헤징과 부스팅의 균형으로 ‘학자의 목소리(stance)’를 조절합니다."],"examples":[{"en":"The experiment clearly demonstrates a causal relationship between the variables.","ko":"이 실험은 변수들 사이의 인과관계를 명확히 입증한다."},{"en":"These data undoubtedly establish the robustness of the model.","ko":"이 데이터는 모델의 견고성을 의심의 여지 없이 확립한다."},{"en":"Indeed, the pattern holds across all four conditions.","ko":"실제로 그 패턴은 네 가지 조건 모두에서 유지된다."}],"quiz":[{"q":"다음 중 ‘부스팅(강조)’ 표현은?","choices":["The results possibly indicate ~","The results clearly demonstrate ~","The results may suggest ~"],"answer":1,"explain":"clearly demonstrate는 확신을 높이는 부스팅이고, 나머지는 헤징입니다."},{"q":"빈칸: There is ___ doubt that the intervention improved outcomes. (강한 확신)","choices":["some","no","much"],"answer":1,"explain":"There is no doubt that ~은 강한 확신을 표현하는 부스팅 구문입니다."}]},{"id":"gr-cohesion","title":"결속성 (Cohesion)","key":"this·these 뒤에 요약명사를 붙여 앞 내용을 묶어 이어갑니다.","hook":"티타의 징검다리! 문장과 문장 사이에 ‘this approach’ 같은 돌을 놓으면 독자가 풀쩍 건너와요. 지시어+요약명사가 글을 끈끈하게 붙여요.","summary":"결속성은 지시사(this/these)에 요약명사를 결합해 앞 내용을 한 덩어리로 가리키며 문장을 매끄럽게 연결하는 기법입니다. 단독 ‘this’보다 명확합니다.","rules":["지시사+요약명사: ‘this approach’, ‘these findings’, ‘this distinction’으로 앞 내용을 캡슐화합니다.","맨몸 ‘this/it’만 쓰면 지시 대상이 모호하니, 명사를 붙여 명확히 합니다.","요약명사 예: ‘issue, view, assumption, phenomenon, tendency, framework’.","어휘 반복 대신 동의어·상위어로 연결해 단조로움을 피합니다 (lexical cohesion).","‘such’도 결속에 유용: ‘such results’, ‘such an interpretation’."],"examples":[{"en":"The model ignores feedback loops. This limitation undermines its predictive power.","ko":"그 모델은 피드백 루프를 무시한다. 이 한계는 모델의 예측력을 약화시킨다."},{"en":"Participants reported higher stress and lower focus. These effects persisted for weeks.","ko":"참가자들은 더 높은 스트레스와 더 낮은 집중을 보고했다. 이러한 효과는 몇 주 동안 지속되었다."},{"en":"Several studies use small samples. Such designs limit generalizability.","ko":"여러 연구가 작은 표본을 사용한다. 그러한 설계는 일반화 가능성을 제한한다."}],"quiz":[{"q":"앞 문장을 가장 명확하게 결속하는 표현은?","choices":["This is bad.","This methodological weakness is problematic.","It is a thing."],"answer":1,"explain":"지시사 this에 요약명사 methodological weakness를 붙이면 지시 대상이 분명해집니다."},{"q":"빈칸: Costs rose while quality fell. ___ trends worry investors. (복수 지시)","choices":["This","These","It"],"answer":1,"explain":"두 가지 추세(복수)를 가리키므로 These trends가 적절합니다."}]},{"id":"gr-academic-passive","title":"비인칭 학술 수동태 (Academic Passive)","key":"It is argued that ~로 주체를 숨기고 객관적으로 진술합니다.","hook":"티타의 투명망토! ‘내가 주장한다’ 대신 ‘It is argued that~’라고 하면 ‘나’가 사라지고 주장만 둥둥 떠요. 객관성의 마법 망토예요.","summary":"비인칭 수동태는 행위자(I/we)를 감추고 명제 자체를 전면에 내세워 객관적이고 격식 있는 어조를 만드는 학술 글쓰기 장치입니다.","rules":["‘It is + 과거분사 + that절’ 구조: ‘It is argued/assumed/believed that ~’.","행위자를 생략해 비인칭·객관적 어조를 만듭니다.","‘It has been shown that ~’, ‘It should be noted that ~’ 등 자주 쓰이는 정형구.","‘주어 + is said/thought/believed + to부정사’ 형태도 가능: ‘X is thought to cause Y’.","과용하면 모호하고 둔탁해지므로 능동태와 균형을 맞춥니다."],"examples":[{"en":"It is widely assumed that early intervention yields better outcomes.","ko":"조기 개입이 더 나은 결과를 낳는다고 널리 가정된다."},{"en":"It has been shown that the correlation weakens at higher temperatures.","ko":"그 상관관계가 더 높은 온도에서 약해진다는 것이 밝혀졌다."},{"en":"The gene is believed to play a key role in cell division.","ko":"그 유전자는 세포 분열에서 핵심적 역할을 하는 것으로 여겨진다."}],"quiz":[{"q":"가장 비인칭·학술적인 문장은?","choices":["I think the theory is wrong.","It is argued that the theory is flawed.","You should know the theory is wrong."],"answer":1,"explain":"It is argued that ~은 행위자를 숨기는 전형적 비인칭 학술 수동태입니다."},{"q":"빈칸: It ___ been shown that the method scales well. (현재완료 수동)","choices":["has","is","was"],"answer":0,"explain":"It has been shown that ~은 현재완료 수동의 정형구로 가장 자연스럽습니다."}]},{"id":"gr-reporting-verbs","title":"인용 동사·인용 문법 (Reporting Verbs & Citation)","key":"argue·claim·suggest로 출처의 입장을 정확히 전달합니다.","hook":"티타의 마이크 전달! 남의 말을 옮길 땐 어떤 동사를 쓰느냐가 톤을 정해요. ‘argues’는 강하게, ‘suggests’는 살며시. 동사가 곧 평가예요.","summary":"인용 동사는 선행 연구의 주장을 전달하면서 그 강도와 화자의 태도를 드러내는 핵심 도구입니다. 동사 선택이 미묘한 평가를 담습니다.","rules":["강도별 인용 동사: 강함 ‘argue, contend, assert’ / 중간 ‘suggest, propose’ / 약함 ‘note, observe’.","‘X argues that + 주어 + 동사’ 형태로 that절을 이끕니다: ‘Smith (2020) argues that ~’.","시제: 일반적 진실은 현재(‘argues’), 특정 연구 행위는 과거(‘found, reported’)로 자주 씁니다.","중립 보고는 ‘states, describes’, 비판·거리두기는 ‘claims, alleges’를 활용합니다.","‘according to X’ 구문도 출처 표시에 유용합니다."],"examples":[{"en":"Kim (2019) argues that bilingualism enhances executive control.","ko":"Kim(2019)은 이중언어 사용이 실행 통제력을 향상시킨다고 주장한다."},{"en":"Several researchers have suggested that the effect is context-dependent.","ko":"여러 연구자들은 그 효과가 맥락에 의존적이라고 제안해 왔다."},{"en":"The author notes that the sample was relatively small.","ko":"저자는 표본이 비교적 작았다고 언급한다."}],"quiz":[{"q":"저자의 ‘강한 주장’을 전달하기에 가장 적절한 동사는?","choices":["notes","argues","mentions"],"answer":1,"explain":"argues는 강한 주장을, notes·mentions는 단순 언급을 나타냅니다."},{"q":"빈칸: Lee (2021) ___ that the results were inconclusive. (that절 인용)","choices":["argues","argues about","argues to"],"answer":0,"explain":"argue는 ‘argue that + 절’ 형태로 that절을 직접 이끕니다."}]},{"id":"gr-reduced-relative","title":"축약 관계절 (Reduced Relative Clauses)","key":"관계대명사+be를 지우고 분사·전치사구로 줄여 간결하게.","hook":"티타의 다이어트! ‘which is based on~’에서 군더더기 ‘which is’를 쏙 빼면 ‘based on~’만 남아 날씬해져요. 학술 문장은 군살을 싫어해요.","summary":"축약 관계절은 ‘관계대명사+be동사’를 생략해 분사구나 전치사구로 만든 형태로, 문장을 간결하고 정보 밀도 높게 만듭니다.","rules":["능동은 현재분사로: ‘the students who are studying → the students studying’.","수동은 과거분사로: ‘the data which were collected → the data collected’.","‘which is/that is’ 뒤 전치사구도 생략 가능: ‘the model that is in use → the model in use’.","형용사구도 축약: ‘a result which is significant → a significant result’ 또는 후치 수식.","축약 후 수식어가 명사 뒤에서 명확히 연결되는지 확인합니다(모호성 주의)."],"examples":[{"en":"The variables measured in this study were all continuous.","ko":"이 연구에서 측정된 변수들은 모두 연속형이었다."},{"en":"Studies using longitudinal designs offer stronger causal evidence.","ko":"종단 설계를 사용하는 연구들은 더 강력한 인과적 증거를 제공한다."},{"en":"The framework proposed by the authors integrates three perspectives.","ko":"저자들이 제안한 그 틀은 세 가지 관점을 통합한다."}],"quiz":[{"q":"‘the results that were obtained’을 올바르게 축약하면?","choices":["the results obtaining","the results obtained","the results to obtain"],"answer":1,"explain":"수동 관계절(were obtained)은 과거분사 obtained로 축약합니다."},{"q":"빈칸: Researchers ___ this method reported fewer errors. (능동 축약)","choices":["used","using","to use"],"answer":1,"explain":"‘who use this method’의 능동 축약은 현재분사 using입니다."}]},{"id":"gr-participial-absolute","title":"분사·독립분사 구문 (Participial & Absolute)","key":"분사구문으로 두 절을 하나로 압축하고, 주어가 다르면 남깁니다.","hook":"티타의 접착제! ‘~한 뒤, ~했다’를 분사로 이으면 ‘Having done~, ~’처럼 두 동작이 매끈히 붙어요. 주어가 다르면 분사 앞에 주어를 슬쩍 남겨요.","summary":"분사구문은 부사절을 분사로 압축하는 고급 기법이며, 주절과 주어가 다를 때 분사 앞에 주어를 두는 것을 독립분사구문(absolute construction)이라 합니다.","rules":["능동·동시동작: ‘Using this approach, we obtained ~’ (현재분사).","완료·선행동작: ‘Having analyzed the data, the team concluded ~’.","수동: ‘Given the constraints, the design was simplified’ (과거분사).","독립분사구문: 분사의 주어가 주절과 다르면 명시 — ‘All variables being equal, X increases Y’.","현수분사(dangling) 주의: 분사의 의미상 주어가 주절 주어와 일치해야 합니다."],"examples":[{"en":"Having controlled for age, the researchers found a stronger effect.","ko":"나이를 통제한 후, 연구자들은 더 강한 효과를 발견했다."},{"en":"The temperature being constant, the reaction rate remained stable.","ko":"온도가 일정하게 유지되자, 반응 속도는 안정적으로 유지되었다."},{"en":"Based on these results, the hypothesis was revised.","ko":"이러한 결과에 근거하여, 가설이 수정되었다."}],"quiz":[{"q":"주어가 서로 다른 독립분사구문은?","choices":["Walking home, she sang.","The sun having set, the team stopped work.","Smiling, he replied."],"answer":1,"explain":"분사(having set)의 주어 The sun이 주절 주어 the team과 달라 명시된 독립분사구문입니다."},{"q":"빈칸: ___ analyzed the data, the authors drew conclusions. (선행 동작)","choices":["Have","Having","To have"],"answer":1,"explain":"선행하는 완료 동작은 Having + 과거분사(Having analyzed)로 표현합니다."}]},{"id":"gr-mandative-subjunctive","title":"명령·요구의 가정법 (Mandative Subjunctive)","key":"recommend that 뒤에는 동사원형(should 생략)을 씁니다.","hook":"티타의 명령 모드! ‘추천한다, 그가 가야 한다’를 영어로 옮길 때 ‘that he go’처럼 동사원형이 떡! 3인칭인데 -s가 없어요. 놀라지 마세요, 규칙이에요.","summary":"요구·제안·주장을 나타내는 동사·형용사 뒤 that절에서는 동사원형(가정법 현재)을 써서 ‘should’가 생략된 형태가 됩니다. 격식체 학술 영어에서 표준입니다.","rules":["유발 동사: ‘recommend, suggest, propose, require, demand, insist’ + that + 주어 + 동사원형.","3인칭 단수라도 -s 없이 원형: ‘We recommend that he be present’.","부정은 ‘that + 주어 + not + 동사원형’: ‘insist that he not leave’.","유발 형용사·명사: ‘It is essential/necessary/imperative that ~’ + 동사원형.","영국식은 ‘should + 동사원형’도 허용하나, 격식 학술체는 원형(가정법)을 선호합니다."],"examples":[{"en":"The committee recommends that the policy be revised immediately.","ko":"위원회는 그 정책이 즉시 개정될 것을 권고한다."},{"en":"It is essential that each participant remain anonymous.","ko":"각 참가자가 익명으로 남는 것이 필수적이다."},{"en":"The reviewers insisted that the author provide additional data.","ko":"심사자들은 저자가 추가 데이터를 제공할 것을 강력히 요구했다."}],"quiz":[{"q":"올바른 가정법 문장은?","choices":["We require that he submits the form.","We require that he submit the form.","We require that he submitted the form."],"answer":1,"explain":"require that 뒤에는 3인칭이라도 동사원형 submit을 씁니다(가정법 현재)."},{"q":"빈칸: It is imperative that the sample ___ representative. (가정법 현재 be동사)","choices":["is","be","was"],"answer":1,"explain":"imperative that 뒤 가정법에서는 be동사가 원형 be로 옵니다."}]},{"id":"gr-inversion-fronting","title":"도치·전치 (Inversion & Fronting)","key":"부정어·강조어를 앞에 두면 주어와 동사가 뒤집힙니다.","hook":"티타의 물구나무! 문장 맨 앞에 ‘Not only~’ 같은 부정어가 오면 주어·동사가 거꾸로 서요. 강조하려고 일부러 물구나무 서는 거예요!","summary":"부정·제한 부사를 문두에 두면 주어와 (조)동사가 도치되어 강조 효과를 냅니다. 전치(fronting)는 정보 초점을 앞으로 옮겨 결속을 돕습니다.","rules":["부정어 문두 도치: ‘Not only does X increase Y, but it also ~’.","‘Never, Rarely, Seldom, Hardly, No sooner’ 문두 → 조동사+주어: ‘Rarely have we seen ~’.","‘Only + 부사구’ 문두 도치: ‘Only then did the pattern emerge’.","‘Not until ~’ 도치: ‘Not until recently was the effect understood’.","전치(fronting): 보어·부사구를 앞으로 — ‘Of particular importance is the second factor’."],"examples":[{"en":"Not only does the model fit the data, but it also predicts new cases.","ko":"그 모델은 데이터에 들어맞을 뿐 아니라 새로운 사례도 예측한다."},{"en":"Rarely has a single study reshaped the field so profoundly.","ko":"단일 연구가 그토록 깊이 분야를 재편한 경우는 드물다."},{"en":"Of particular relevance is the distinction between the two mechanisms.","ko":"특히 관련성이 있는 것은 두 메커니즘 사이의 구별이다."}],"quiz":[{"q":"올바른 도치 문장은?","choices":["Never we have seen such results.","Never have we seen such results.","Never seen we have such results."],"answer":1,"explain":"부정어 Never가 문두에 오면 조동사+주어 어순(have we)으로 도치됩니다."},{"q":"빈칸: Only after the reform ___ the outcomes improve. (도치)","choices":["did","do","was"],"answer":0,"explain":"Only + 부사구 문두 도치에서 과거시제 일반동사는 did + 주어 + 원형으로 도치됩니다."}]},{"id":"gr-mixed-inverted-conditionals","title":"혼합·도치 가정법 (Mixed & Inverted Conditionals)","key":"if를 빼고 도치하거나, 과거 조건+현재 결과를 섞습니다.","hook":"티타의 시간 믹서! ‘과거에 ~했다면, 지금 ~할 텐데’를 한 문장에 섞어요. 게다가 if를 빼고 ‘Had it been~’처럼 도치하면 고급스러워져요.","summary":"혼합 가정법은 조건절과 주절의 시제를 다르게 섞어 과거 조건의 현재 결과 등을 표현하며, 도치 가정법은 if를 생략하고 조동사를 앞세웁니다.","rules":["혼합형(과거조건→현재결과): ‘If they had invested, the firm would be profitable now’.","혼합형(현재조건→과거결과): ‘If he were careful, he would not have erred’.","도치(가정법 과거완료): ‘Had the data been cleaner, results would have differed’.","도치(가정법 과거): ‘Were the assumption valid, the model would hold’.","도치(should): ‘Should this occur, further analysis is needed’ (가능성)."],"examples":[{"en":"Had the sample been larger, the findings would be more reliable today.","ko":"표본이 더 컸더라면, 그 결과는 오늘날 더 신뢰할 만할 것이다."},{"en":"Were these assumptions relaxed, the conclusions would change substantially.","ko":"이 가정들이 완화된다면, 결론은 상당히 달라질 것이다."},{"en":"Should anomalies arise, the protocol must be re-evaluated.","ko":"이상치가 발생할 경우, 프로토콜은 재평가되어야 한다."}],"quiz":[{"q":"‘If it had been cheaper, more people would use it now’의 도치형은?","choices":["Had it been cheaper, more people would use it now.","Has it been cheaper, more people would use it now.","Were it been cheaper, more people would use it now."],"answer":0,"explain":"가정법 과거완료의 도치는 If를 빼고 Had + 주어로 시작합니다."},{"q":"빈칸: ___ the hypothesis correct, we would expect higher scores. (도치 가정법 과거)","choices":["Was","Were","Had"],"answer":1,"explain":"가정법 과거의 도치는 Were + 주어 형태(Were the hypothesis correct)입니다."}]},{"id":"gr-concessive","title":"양보 (Concessive Structures)","key":"although·whereas·albeit·notwithstanding으로 반대 정보를 인정합니다.","hook":"티타의 한 발 양보! ‘비록 ~지만’ 하고 상대 의견을 인정한 뒤 내 주장을 펴면 더 설득력 있어요. albeit·notwithstanding은 격식 만렙 표현이에요.","summary":"양보 구조는 예상과 반대되는 사실을 인정하면서 주장을 펼쳐 논증을 정교하게 만듭니다. 격식 수준에 따라 다양한 연결어를 씁니다.","rules":["절 양보: ‘Although/Though/Even though + 주어 + 동사’ — ‘Although results vary, ~’.","대조 접속사 ‘whereas, while’은 두 사실을 나란히 대비합니다.","축약 ‘albeit’ + 형용사·구: ‘a useful, albeit limited, framework’.","전치사 ‘despite, in spite of, notwithstanding’ + 명사(구): ‘Notwithstanding these limitations, ~’.","‘however, nevertheless’는 문장 간 양보 연결에 쓰입니다."],"examples":[{"en":"Although the effect was small, it remained statistically significant.","ko":"그 효과는 작았지만, 통계적으로 유의미하게 유지되었다."},{"en":"The method is efficient, albeit somewhat sensitive to outliers.","ko":"그 방법은 다소 이상치에 민감하기는 하지만 효율적이다."},{"en":"Notwithstanding these constraints, the approach yields useful insights.","ko":"이러한 제약에도 불구하고, 그 접근법은 유용한 통찰을 제공한다."}],"quiz":[{"q":"빈칸 뒤에 명사구가 오는 양보 전치사는?","choices":["Although the limitations","Despite the limitations","Even though the limitations"],"answer":1,"explain":"Despite는 전치사로 명사(구)를 취하고, although·even though는 절을 이끕니다."},{"q":"‘유용하지만 제한적인’을 한 단어 양보로: a useful, ___, model.","choices":["albeit limited","although limited it is","despite limited"],"answer":0,"explain":"albeit + 형용사(limited)는 삽입형 축약 양보 표현으로 자연스럽습니다."}]},{"id":"gr-logical-connectors","title":"학술 연결어 (Logical Connectors)","key":"moreover·consequently·nevertheless로 논리 흐름을 표시합니다.","hook":"티타의 표지판! 독자는 길을 잃기 쉬워요. ‘게다가(moreover)’, ‘따라서(consequently)’ 같은 표지판을 세우면 논리의 방향이 한눈에 보여요.","summary":"학술 연결어는 문장·단락 사이의 논리 관계(첨가·인과·대조)를 명시해 글의 응집성과 가독성을 높입니다. 관계 유형에 맞게 골라야 합니다.","rules":["첨가: ‘moreover, furthermore, in addition, additionally’.","인과·결과: ‘consequently, therefore, thus, hence, as a result’.","대조: ‘however, nevertheless, nonetheless, conversely, in contrast’.","보통 문두에서 쉼표와 함께: ‘Moreover, the data confirm ~’. 문중 삽입도 가능.","‘and/but/so’ 같은 구어 접속사보다 격식 연결어를 선호하되 남발은 피합니다."],"examples":[{"en":"The sample was small; moreover, attrition was high.","ko":"표본이 작았고, 게다가 탈락률도 높았다."},{"en":"The assumptions were violated; consequently, the results must be interpreted cautiously.","ko":"가정들이 위배되었으며, 따라서 결과는 신중하게 해석되어야 한다."},{"en":"The theory is elegant; nevertheless, it lacks empirical support.","ko":"그 이론은 정교하다. 그럼에도 불구하고 경험적 뒷받침이 부족하다."}],"quiz":[{"q":"‘원인 → 결과’를 나타내는 연결어는?","choices":["however","consequently","moreover"],"answer":1,"explain":"consequently는 결과를 나타내고, however는 대조, moreover는 첨가입니다."},{"q":"빈칸: The model is simple; ___, it ignores key variables. (대조)","choices":["furthermore","therefore","nevertheless"],"answer":2,"explain":"단순함과 한계를 대조하므로 nevertheless(그럼에도)가 적절합니다."}]},{"id":"gr-parallelism","title":"병렬구조 (Parallelism)","key":"나열되는 요소는 같은 문법 형태로 맞춥니다.","hook":"티타의 줄 맞추기! 나열할 땐 ‘동사+동사+동사’처럼 옷을 통일해야 깔끔해요. 하나만 다른 옷을 입으면 독자가 발을 헛디뎌요.","summary":"병렬구조는 등위·비교·열거되는 요소들을 동일한 문법 형태로 일치시켜 명료함과 균형을 주는 원칙입니다. 학술 글의 정확성을 높입니다.","rules":["등위 항목은 같은 품사·형태로: ‘collecting, coding, and analyzing data’ (모두 -ing).","상관접속사 짝 맞추기: ‘not only A but also B’, ‘both A and B’의 A·B 형태 일치.","비교 대상 형태 일치: ‘reading is more useful than writing’ (둘 다 동명사).","목록·열거에서 동사형/명사형을 섞지 않습니다.","병렬은 가독성과 논리적 대등성을 동시에 강화합니다."],"examples":[{"en":"The study aims to identify, measure, and compare the three variables.","ko":"이 연구는 세 변수를 식별하고, 측정하고, 비교하는 것을 목표로 한다."},{"en":"The approach is not only efficient but also reproducible.","ko":"그 접근법은 효율적일 뿐만 아니라 재현 가능하다."},{"en":"Success depends on careful design, rigorous testing, and clear reporting.","ko":"성공은 신중한 설계, 엄격한 검증, 명확한 보고에 달려 있다."}],"quiz":[{"q":"병렬구조가 올바른 문장은?","choices":["She likes reading, to write, and research.","She likes reading, writing, and researching.","She likes to read, writing, and research."],"answer":1,"explain":"세 항목을 모두 동명사(-ing)로 통일한 b가 병렬구조에 맞습니다."},{"q":"빈칸: The plan is both ambitious and ___. (병렬 형용사)","choices":["it is realistic","realistic","to be realistic"],"answer":1,"explain":"both A and B에서 A(형용사 ambitious)와 형태를 맞춰 형용사 realistic이 옵니다."}]},{"id":"gr-cleft","title":"분열문 (Cleft Sentences)","key":"It is ~ that / What ~ is 구문으로 특정 요소를 강조합니다.","hook":"티타의 스포트라이트! 한 문장을 둘로 쪼개 ‘바로 이것이!’ 하고 조명을 비춰요. ‘It is X that~’, ‘What matters is~’로 핵심에 빛을 모아요.","summary":"분열문은 한 문장을 두 부분으로 나눠 특정 성분에 초점을 주는 강조 구문입니다. it-cleft와 wh-cleft가 대표적입니다.","rules":["It-cleft: ‘It is/was + 강조어 + that/who + 나머지’ — ‘It is context that determines meaning’.","Wh-cleft(pseudo-cleft): ‘What + 절 + is + 강조어’ — ‘What matters is the mechanism’.","강조 대상은 주어·목적어·부사구 등 다양합니다.","‘The reason (why) ~ is that ~’도 분열 강조의 변형입니다.","글에서 새 정보·대조를 부각하거나 결속을 강화하는 데 유용합니다."],"examples":[{"en":"It is the interaction effect, not the main effect, that drives the result.","ko":"결과를 이끄는 것은 주효과가 아니라 상호작용 효과이다."},{"en":"What this study highlights is the role of context in learning.","ko":"이 연구가 부각하는 것은 학습에서 맥락의 역할이다."},{"en":"The reason the model fails is that it ignores temporal dynamics.","ko":"그 모델이 실패하는 이유는 시간적 역학을 무시하기 때문이다."}],"quiz":[{"q":"‘mechanism’을 강조한 wh-분열문은?","choices":["The mechanism is important.","What matters most is the mechanism.","Mechanisms are studied."],"answer":1,"explain":"What + 절 + is + 강조어 형태로 the mechanism에 초점을 준 wh-cleft입니다."},{"q":"빈칸: ___ context that shapes interpretation. (it-cleft 강조)","choices":["It is","There is","That is"],"answer":0,"explain":"It is + 강조어 + that 구조의 it-cleft로 context를 강조합니다."}]},{"id":"gr-complex-noun-phrases","title":"복합 명사구 (Complex Noun Phrases)","key":"명사 앞뒤에 수식어를 쌓아 정보를 한 덩어리로 압축합니다.","hook":"티타의 레고 블록! 명사 하나에 형용사·명사·전치사구·관계절을 앞뒤로 척척 끼우면 정보가 꽉 찬 한 덩어리가 돼요. 학술 영어의 레고예요.","summary":"복합 명사구는 핵명사 앞(전치수식)과 뒤(후치수식)에 여러 수식어를 결합해 정보를 고밀도로 담는 학술 영어의 특징적 구조입니다.","rules":["전치수식: 형용사·명사를 앞에 쌓음 — ‘a high-resolution satellite image’.","명사+명사 연쇄: ‘climate change mitigation strategies’.","후치수식: 전치사구·분사구·관계절을 뒤에 — ‘the effect of stress on memory’.","전치+후치 결합으로 밀도를 높임: ‘a recent large-scale study examining child development’.","과도하게 길어지면 모호해지므로 핵명사와 수식 관계를 명확히 유지합니다."],"examples":[{"en":"A large-scale longitudinal study of adolescent behavior was conducted.","ko":"청소년 행동에 관한 대규모 종단 연구가 수행되었다."},{"en":"The recently proposed machine-learning framework outperforms baselines.","ko":"최근 제안된 머신러닝 프레임워크는 기준 모델들을 능가한다."},{"en":"Government-funded research programs targeting renewable energy expanded.","ko":"재생에너지를 겨냥한 정부 지원 연구 프로그램이 확대되었다."}],"quiz":[{"q":"가장 잘 압축된 복합 명사구는?","choices":["a study which is about behavior of children and is large","a large-scale study of child behavior","study big children behavior"],"answer":1,"explain":"전치수식(large-scale)과 후치수식(of child behavior)을 결합해 간결·명확합니다."},{"q":"빈칸: the effect ___ temperature ___ growth (후치수식 전치사)","choices":["of / on","in / of","for / to"],"answer":0,"explain":"‘the effect of A on B’가 표준 후치수식 패턴입니다."}]},{"id":"gr-hedged-comparatives","title":"신중한 비교·상관 (Hedged Comparatives & Correlatives)","key":"the more ~ the more 구문과 완곡 비교로 관계를 표현합니다.","hook":"티타의 시소! ‘많을수록 ~할수록’은 ‘the more~, the more~’ 시소로 표현해요. 단정 대신 ‘slightly higher’처럼 살짝 기울이면 더 학술적이에요.","summary":"상관비교(the+비교급, the+비교급)는 두 변수의 비례 관계를, 헤지드 비교는 차이를 과장 없이 신중하게 진술하는 방식을 다룹니다.","rules":["상관비교: ‘The more X, the more Y’ — ‘The larger the sample, the smaller the error’.","비교 헤징: ‘slightly, marginally, somewhat + 비교급’ — ‘marginally higher accuracy’.","‘tend to be + 비교급’으로 경향성 비교: ‘older adults tend to be slower’.","‘comparable to, similar to, on a par with’로 차이를 누그러뜨립니다.","비교 대상의 형태·범위를 명확히 해 모호한 비교를 피합니다."],"examples":[{"en":"The greater the exposure, the stronger the observed response.","ko":"노출이 클수록 관찰된 반응이 더 강했다."},{"en":"The treatment group performed marginally better than the controls.","ko":"처치 집단은 통제 집단보다 근소하게 더 나은 수행을 보였다."},{"en":"Accuracy was broadly comparable across the two methods.","ko":"정확도는 두 방법 사이에서 대체로 비슷했다."}],"quiz":[{"q":"비례 관계를 나타내는 올바른 상관비교는?","choices":["More the data, more the accuracy.","The more data, the higher the accuracy.","Data more, accuracy more."],"answer":1,"explain":"‘The + 비교급 ~, the + 비교급 ~’ 형태가 표준 상관비교 구문입니다."},{"q":"빈칸: Group A scored ___ higher than Group B. (신중한 비교)","choices":["hugely","slightly","impossibly"],"answer":1,"explain":"slightly higher는 차이를 과장하지 않는 헤지드 비교 표현입니다."}]},{"id":"gr-modality-claims","title":"주장의 양태 (Modality for Claims)","key":"may·could·would로 주장의 확신 정도를 조절합니다.","hook":"티타의 다이얼! 양태동사는 확신의 다이얼이에요. ‘will(확실)→would→could→might(약함)’ 순으로 돌려가며 주장의 세기를 미세 조정해요.","summary":"양태동사는 주장의 확실성·가능성·예측 정도를 세밀하게 조절하는 도구로, 학술적 신중함과 논증 강도를 함께 표현합니다.","rules":["가능성 약→강: ‘might < may < could < can’ — ‘This may account for the gap’.","‘would’는 가정적 결과·완곡한 일반화: ‘This would suggest a broader pattern’.","예측·경향: ‘will tend to’, ‘is likely to’로 미래·확률을 표현.","당위·권고: ‘should, must’는 강한 함의를 주므로 신중히 사용.","양태부사와 결합해 강도 미세조정: ‘could possibly’, ‘may well’."],"examples":[{"en":"These results may reflect a sampling artifact rather than a true effect.","ko":"이 결과는 진정한 효과라기보다 표집상의 인공산물을 반영할 수도 있다."},{"en":"Such a mechanism could explain the observed nonlinearity.","ko":"그러한 메커니즘이 관찰된 비선형성을 설명할 수 있을 것이다."},{"en":"This finding would imply that the model generalizes across domains.","ko":"이 발견은 그 모델이 여러 영역에 걸쳐 일반화됨을 함의할 것이다."}],"quiz":[{"q":"가장 ‘약한 가능성’을 나타내는 양태동사는?","choices":["will","might","must"],"answer":1,"explain":"might는 가장 낮은 가능성을, will·must는 높은 확신을 나타냅니다."},{"q":"빈칸: This evidence ___ suggest a wider trend, though more data are needed. (완곡한 함의)","choices":["must","would","will"],"answer":1,"explain":"would suggest는 단정을 피한 완곡한 함의로 학술 주장에 적합합니다."}]},{"id":"gr-tense-aspect","title":"학술 시제 (Tense & Aspect)","key":"일반적 사실은 현재, 특정 실험은 과거, 누적 연구는 현재완료.","hook":"티타의 시간 지도! 변하지 않는 사실은 현재, ‘내가 한 실험’은 과거, ‘지금까지 쌓인 연구’는 현재완료. 시제만 봐도 글의 구조가 보여요.","summary":"학술 글쓰기는 섹션과 의미에 따라 시제·상을 체계적으로 선택합니다. 일반적 진실은 현재, 수행한 연구는 과거, 연구 동향은 현재완료가 기본입니다.","rules":["일반적 사실·이론: 현재시제 — ‘Water boils at 100°C’.","수행한 방법·결과: 과거시제 — ‘We measured reaction times’.","지금까지의 연구 동향: 현재완료 — ‘Researchers have shown that ~’.","결과 해석·함의(Discussion): 현재시제로 일반화 — ‘These results suggest ~’.","선행 사건의 배경 설명: 과거완료 — ‘Participants had completed training before ~’."],"examples":[{"en":"Previous studies have demonstrated a robust correlation.","ko":"선행 연구들은 견고한 상관관계를 입증해 왔다."},{"en":"We collected data over a six-month period.","ko":"우리는 6개월에 걸쳐 데이터를 수집했다."},{"en":"These findings indicate that attention modulates perception.","ko":"이 결과들은 주의가 지각을 조절함을 나타낸다."}],"quiz":[{"q":"‘지금까지 누적된 연구 동향’을 나타내는 시제는?","choices":["단순과거 (studied)","현재완료 (have studied)","미래 (will study)"],"answer":1,"explain":"현재완료(have studied)는 과거부터 현재까지 이어진 연구 동향에 적합합니다."},{"q":"빈칸: In this experiment, we ___ the temperature every hour. (수행한 방법)","choices":["record","recorded","have recorded"],"answer":1,"explain":"수행한 구체적 방법·절차는 단순과거(recorded)로 기술합니다."}]},{"id":"gr-articles-determiners","title":"관사·한정사 (Articles & Determiners)","key":"총칭·추상 개념은 무관사, 특정·기지 정보는 the를 씁니다.","hook":"티타의 손가락! the는 ‘바로 그거!’ 하고 콕 집는 손가락이에요. 추상 개념·총칭은 손가락 없이 무관사로 두둥실. 작지만 의미가 확 달라져요.","summary":"학술 영어에서 관사·한정사는 명사의 특정성·총칭성·추상성을 표시합니다. 추상명사·복수 총칭은 무관사, 특정·앞서 언급된 것은 the를 씁니다.","rules":["총칭 복수·불가산 추상명사: 무관사 — ‘Research suggests ~’, ‘Educators value creativity’.","특정·앞서 언급·유일한 것: the — ‘the results’, ‘the proposed method’.","처음 도입되는 단수 가산명사: a/an — ‘a novel approach’.","‘the + 단수’로 종(種) 전체 총칭: ‘the cell’, ‘the consumer’ (격식체).","한정사 ‘this, these, such, much, many, several’로 양·특정성을 조절합니다."],"examples":[{"en":"Research on bilingualism has expanded rapidly in recent decades.","ko":"이중언어 사용에 관한 연구는 최근 수십 년간 빠르게 확장되었다."},{"en":"The method described above outperforms the standard baseline.","ko":"위에서 설명한 그 방법은 표준 기준 모델을 능가한다."},{"en":"An unexpected pattern emerged in the second experiment.","ko":"두 번째 실험에서 예상치 못한 패턴이 나타났다."}],"quiz":[{"q":"총칭적·추상적 의미에서 가장 자연스러운 것은?","choices":["The research suggests caution.","Research suggests caution.","A research suggests caution."],"answer":1,"explain":"research는 불가산 추상명사로, 총칭일 때 무관사가 자연스럽습니다(‘a research’는 비문)."},{"q":"빈칸: ___ results reported in Section 3 confirm the hypothesis. (특정 결과)","choices":["A","The","무관사"],"answer":1,"explain":"앞서 특정된(Section 3에 보고된) 결과이므로 정관사 the가 적절합니다."}]}]};

const LEVELS = [
  { min: 0, title: "견습 정비사" },
  { min: 300, title: "정비사" },
  { min: 1200, title: "숙련 정비사" },
  { min: 3500, title: "수석 엔지니어" },
  { min: 8000, title: "에프스타인 재단 연구원" },
];

const GREETINGS = [
  "안녕하세요! 오늘도 영어 정비, 같이 해 봐요!",
  "에헤헤, 와 주셨네요! 오늘은 어떤 부품(단어)을 조립해 볼까요?",
  "영어도 기계처럼 매일 조금씩 정비하면 반짝반짝해져요!",
  "무리하지 말고, 딱 5분만 해도 충분해요!",
];
const CHEER = ["잘 했어요! 완벽한 조립이에요!", "정답! 정말 대단해요!", "역시 멋져요! 오브먼트가 반짝!", "굉장해요! 한 번에 성공!"];
const OOPS = ["더 잘할 수 있어요! 연상법 다시 볼까요?", "괜찮아요! 기계도 시행착오로 완성돼요.", "아깝다! 이 부품은 한 번 더 손보면 돼요!"];
// 퀴즈 응원 음성 — 티타 보이스 자동 재생 (같은 두 문장만 써서 캐시되면 요금 거의 0)
const PRAISE_VOICE = "Great job! Well done!";
const ENCOURAGE_VOICE = "It's okay, you can do better!";

const levelInfo = (xp) => {
  let cur = LEVELS[0], next = null;
  for (let i = 0; i < LEVELS.length; i++) {
    if (xp >= LEVELS[i].min) { cur = LEVELS[i]; next = LEVELS[i + 1] || null; }
  }
  const pct = next ? Math.min(100, Math.round(((xp - cur.min) / (next.min - cur.min)) * 100)) : 100;
  return { cur, next, pct };
};

/* ───────── 티타 보이스 (내 서버 /api/tts가 ElevenLabs를 대신 호출) ───────── */
// autoPlay: 자동재생 / simBoost: 유사도 부스트(기본 off=0.75) / speakerBoost: 스피커 부스트(기본 on)
const VOICE_CFG = { autoPlay: true, simBoost: false, speakerBoost: true };
const ttsCache = new Map();
let currentAudio = null;
const stopAudio = () => {
  try { if (currentAudio) { currentAudio.pause(); currentAudio = null; } } catch (e) {}
  try { if (typeof window !== "undefined" && window.speechSynthesis) window.speechSynthesis.cancel(); } catch (e) {}
};

// 티타 목소리를 불러오지 못했을 때 띄우는 가벼운 안내.
// 예전에는 기기 기본 목소리로 대신 읽어줬지만, 그러면 완전히 다른 목소리가 나와서
// "목소리가 자꾸 변한다"는 문제가 생겼다. 이제는 다른 목소리를 절대 내지 않고,
// 잠깐 안내만 보여준 뒤 다음 시도를 기다린다(= 항상 티타 목소리만).
let voiceNoticeTimer = null;
const showVoiceNotice = () => {
  try {
    if (typeof document === "undefined") return;
    let el = document.getElementById("tita-voice-notice");
    if (!el) {
      el = document.createElement("div");
      el.id = "tita-voice-notice";
      el.setAttribute("role", "status");
      el.style.cssText =
        "position:fixed;left:50%;bottom:24px;transform:translateX(-50%);z-index:9999;" +
        "max-width:90vw;padding:10px 16px;border-radius:9999px;font-size:14px;font-weight:600;" +
        "color:#fff;background:rgba(40,40,50,.92);box-shadow:0 6px 20px rgba(0,0,0,.25);" +
        "pointer-events:none;transition:opacity .3s;opacity:0;";
      document.body.appendChild(el);
    }
    el.textContent = "티타 목소리를 지금 불러올 수 없어요. 잠시 후 다시 시도해 주세요 🎙️";
    el.style.opacity = "1";
    if (voiceNoticeTimer) clearTimeout(voiceNoticeTimer);
    voiceNoticeTimer = setTimeout(() => { el.style.opacity = "0"; }, 2600);
  } catch (e) {}
};

// /api/tts 호출 → 오디오 URL. 일시적 실패(네트워크/429 등)는 한 번 더 시도해서
// 곧바로 기기 기본 목소리로 바뀌는(= 목소리가 변하는) 일을 줄인다.
const fetchTitaAudio = async (text, attempt = 0) => {
  try {
    const res = await fetch("/api/tts", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        text,
        simBoost: VOICE_CFG.simBoost === true,
        speakerBoost: VOICE_CFG.speakerBoost !== false,
      }),
    });
    if (!res.ok) {
      let detail = "";
      try { detail = ((await res.json()).error || "").slice(0, 200); } catch (e2) {}
      window.__titaErr = { status: res.status, detail };
      throw new Error("tts " + res.status);
    }
    const blob = await res.blob();
    return URL.createObjectURL(blob);
  } catch (e) {
    if (attempt < 1) {
      await new Promise((r) => setTimeout(r, 500));
      return fetchTitaAudio(text, attempt + 1);
    }
    throw e;
  }
};

// 통합 재생: 오직 진짜 티타 보이스만 재생. 재시도 후에도 실패하면
// 다른 목소리로 바꾸지 않고 가벼운 안내만 띄운다(= 목소리 일관성 보장).
const titaSpeak = async (text) => {
  if (!text) return false;
  try {
    // 토글 상태가 다르면 다른 음성이므로 캐시 키에 포함한다.
    const cacheKey =
      text + "|" + (VOICE_CFG.simBoost === true ? "1" : "0") + (VOICE_CFG.speakerBoost !== false ? "1" : "0");
    let url = ttsCache.get(cacheKey);
    if (!url) {
      url = await fetchTitaAudio(text);
      ttsCache.set(cacheKey, url);
    }
    window.__titaErr = null;
    stopAudio();
    const a = new Audio(url);
    currentAudio = a;
    await a.play();
    return true;
  } catch (e) {
    if (typeof window !== "undefined" && !window.__titaErr) {
      window.__titaErr = { status: 0, detail: String((e && e.message) || e) };
    }
    showVoiceNotice();
    return false;
  }
};

// 업로드해 둔 티타 보이스 샘플 미리듣기
const playSample = () => {
  try {
    stopAudio();
    const a = new Audio(TITA_VOICE_SAMPLE);
    currentAudio = a;
    a.play().catch(() => {});
  } catch (e) {}
};

const shuffle = (arr) => [...arr].sort(() => Math.random() - 0.5);

