/* ───────── 영어 문법 화면 (중학·고등·수능) ───────── */
const GRAMMAR_LEVELS = [
  { id: "ms", label: "중학", tint: C.teal, intro: "중학교 영어 문법을 기초부터 차근차근! 2022 개정 교육과정 범위로 꽉 채웠어요." },
  { id: "hs", label: "고등", tint: C.copper, intro: "고등 영어 문법을 더 깊게! 시제·관계사·가정법·분사구문까지 정비해요." },
  { id: "sn", label: "수능", tint: C.pinkDeep, intro: "수능 어법 빈출 포인트만 콕! 정답을 고르는 판단 기준을 익혀요." },
  { id: "co", label: "대학", tint: C.brass, intro: "대학 영어 문법! 학술 글 읽기·에세이 쓰기·전문 영어에 필요한 고급 문법을 다져요." },
  { id: "gr", label: "대학원", tint: C.ink, intro: "대학원·학술 영어 문법! 명사화·헤징·분열문·학술 시제까지 논문 영어의 핵심을 정비해요." },
];

function uniqueItems(items) {
  return [...new Set(items.filter(Boolean))];
}

function pickItems(items, count, start = 0, exclude = []) {
  const ban = new Set(exclude.filter(Boolean));
  const clean = uniqueItems(items).filter((item) => !ban.has(item));
  if (!clean.length) return [];
  const offset = ((start % clean.length) + clean.length) % clean.length;
  const rotated = [...clean.slice(offset), ...clean.slice(0, offset)];
  return rotated.slice(0, count);
}

function makeChoices(correct, wrongs, answerIndex = 0) {
  const picks = pickItems(wrongs, 2, answerIndex, [correct]);
  const choices = [];
  let wi = 0;
  for (let i = 0; i < 3; i += 1) {
    if (i === answerIndex) choices.push(correct);
    else {
      choices.push(picks[wi] || correct);
      wi += 1;
    }
  }
  return { choices, answer: answerIndex };
}

function buildGrammarQuiz(topic, topics) {
  const baseQuiz = Array.isArray(topic.quiz) ? topic.quiz : [];
  if (baseQuiz.length >= 5) return baseQuiz.slice(0, 5);

  const topicIndex = Math.max(0, topics.findIndex((item) => item.id === topic.id));
  const otherTopics = topics.filter((item) => item.id !== topic.id);
  const keyPool = otherTopics.map((item) => item.key);
  const rulePool = otherTopics.flatMap((item) => item.rules || []);
  const koPool = otherTopics.flatMap((item) => (item.examples || []).map((ex) => ex.ko));
  const enPool = otherTopics.flatMap((item) => (item.examples || []).map((ex) => ex.en));
  const examples = Array.isArray(topic.examples) ? topic.examples : [];
  const firstExample = examples[topicIndex % Math.max(1, examples.length)] || examples[0];
  const secondExample = examples[(topicIndex + 1) % Math.max(1, examples.length)] || examples[1] || examples[0];
  const extraQuiz = [];

  if (topic.key && keyPool.length >= 2) {
    const choiceSet = makeChoices(topic.key, keyPool, topicIndex % 3);
    extraQuiz.push({
      q: "이 단원의 핵심으로 가장 알맞은 것은?",
      choices: choiceSet.choices,
      answer: choiceSet.answer,
      explain: `핵심은 ‘${topic.key}’예요.`,
    });
  }

  if (firstExample?.en && firstExample?.ko && koPool.length >= 2) {
    const choiceSet = makeChoices(firstExample.ko, koPool, (topicIndex + 1) % 3);
    extraQuiz.push({
      q: `다음 영어 문장의 뜻으로 맞는 것은? ${firstExample.en}`,
      choices: choiceSet.choices,
      answer: choiceSet.answer,
      explain: `이 문장은 ‘${firstExample.ko}’라는 뜻이에요.`,
    });
  }

  if (secondExample?.en && secondExample?.ko && enPool.length >= 2) {
    const choiceSet = makeChoices(secondExample.en, enPool, (topicIndex + 2) % 3);
    extraQuiz.push({
      q: `다음 뜻에 맞는 영어 문장은? ${secondExample.ko}`,
      choices: choiceSet.choices,
      answer: choiceSet.answer,
      explain: `맞는 문장은 ‘${secondExample.en}’예요.`,
    });
  }

  if (topic.rules?.[0] && rulePool.length >= 2) {
    const choiceSet = makeChoices(topic.rules[0], rulePool, topicIndex % 3);
    extraQuiz.push({
      q: "다음 중 이 단원 규칙으로 맞는 것은?",
      choices: choiceSet.choices,
      answer: choiceSet.answer,
      explain: `이 단원에서 먼저 기억할 규칙은 ‘${topic.rules[0]}’예요.`,
    });
  }

  const merged = [...baseQuiz];
  for (const item of extraQuiz) {
    if (merged.length >= 5) break;
    if (!merged.some((quiz) => quiz.q === item.q)) merged.push(item);
  }
  return merged.slice(0, 5);
}

/* 한 번에 한 가지만 보이게 접었다 펴는 카드 (ADHD 친화: 인지 부하 ↓) */
function Collapsible({ icon, label, accent, count, defaultOpen = false, children }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="rounded-2xl overflow-hidden" style={{ background: C.card, border: "2px solid " + C.copperSoft }}>
      <button onClick={() => setOpen((o) => !o)}
        className="w-full flex items-center gap-2 p-3 press text-left">
        <span style={{ color: accent }}>{icon}</span>
        <span className="font-bold text-sm" style={{ color: C.ink }}>{label}</span>
        {count != null && (
          <span className="text-[11px] font-bold rounded-full px-2 py-0.5" style={{ background: C.paper, color: accent, border: "1px solid " + accent }}>{count}</span>
        )}
        <ChevronDown size={18} className="ml-auto shrink-0" style={{ color: C.inkSoft, transform: open ? "rotate(180deg)" : "none", transition: "transform .2s" }} />
      </button>
      {open && <div className="px-3 pb-3">{children}</div>}
    </div>
  );
}

/* 확인 문제 — 한 번에 한 문제씩만 풀어 집중력 부담을 줄여요 */
function GrammarQuiz({ quiz, tint }) {
  const [idx, setIdx] = useState(0);
  const [chosen, setChosen] = useState(null);
  const [score, setScore] = useState(0);
  const [done, setDone] = useState(false);

  if (done) {
    return (
      <div className="rounded-xl p-4 text-center" style={{ background: C.paper, border: "1px dashed " + tint }}>
        <p className="text-sm font-bold mb-1" style={{ color: C.ink }}>다 풀었어요! 🎉</p>
        <p className="text-sm mb-3" style={{ color: C.inkSoft }}>{quiz.length}문제 중 <b style={{ color: C.teal }}>{score}개</b> 정답!</p>
        <button onClick={() => { setIdx(0); setChosen(null); setScore(0); setDone(false); }}
          className="rounded-xl py-2 px-4 text-sm font-bold press" style={{ background: tint, color: "#fff" }}>
          다시 풀기
        </button>
      </div>
    );
  }

  const qz = quiz[idx];
  const answered = chosen != null;
  const isLast = idx === quiz.length - 1;
  const next = () => {
    if (chosen === qz.answer) setScore((s) => s + 1);
    if (isLast) setDone(true);
    else { setIdx((i) => i + 1); setChosen(null); }
  };

  return (
    <div>
      <div className="flex items-center gap-2 mb-2">
        <span className="text-[11px] font-bold rounded-full px-2 py-0.5" style={{ background: C.pinkSoft, color: C.pinkDeep }}>문제 {idx + 1} / {quiz.length}</span>
        <div className="flex-1 h-1.5 rounded-full overflow-hidden" style={{ background: C.copperSoft }}>
          <div className="h-full rounded-full" style={{ width: ((idx + (answered ? 1 : 0)) / quiz.length) * 100 + "%", background: tint, transition: "width .3s" }} />
        </div>
      </div>
      <p className="text-sm font-medium mb-2" style={{ color: C.ink }}>{qz.q}</p>
      <div className="flex flex-col gap-2">
        {qz.choices.map((c, ci) => {
          const correct = ci === qz.answer;
          let bg = C.card, bd = C.copperSoft, col = C.ink;
          if (answered && correct) { bg = C.tealSoft; bd = C.teal; col = C.teal; }
          else if (answered && ci === chosen && !correct) { bg = C.redSoft; bd = C.red; col = C.red; }
          return (
            <button key={ci} disabled={answered}
              onClick={() => setChosen(ci)}
              className="rounded-xl py-2 px-3 text-left text-sm font-medium press"
              style={{ background: bg, border: "2px solid " + bd, color: col }}>
              {c}
            </button>
          );
        })}
      </div>
      {answered && (
        <>
          <p className="text-xs mt-2 rounded-lg p-2 leading-relaxed" style={{ background: C.paper, border: "1px dashed " + tint, color: C.inkSoft }}>
            <b style={{ color: chosen === qz.answer ? C.teal : C.red }}>{chosen === qz.answer ? "정답! " : "아쉬워요! "}</b>{qz.explain}
          </p>
          <button onClick={next}
            className="w-full mt-2 rounded-xl py-2 text-sm font-bold press" style={{ background: tint, color: "#fff" }}>
            {isLast ? "결과 보기" : "다음 문제 →"}
          </button>
        </>
      )}
    </div>
  );
}

